INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (1, 1, N'Khi thay thế nhóm –OH trong nhóm carboxyl của một carboxylic acid bằng nhóm –OR’ (với R’ là gốc hydrocarbon), ta thu được hợp chất thuộc loại nào sau đây?', N'Alcohol.', N'Aldehyde.', N'Ester.', N'Ether.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (2, 1, N'Mùi thơm đặc trưng của chuối chín là do ester nào sau đây gây ra?', N'Ethyl butyrate.', N'Isoamyl acetate.', N'Methyl salicylate.', N'Benzyl acetate.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (3, 1, N'Phản ứng thủy phân ester trong môi trường kiềm (dung dịch NaOH hoặc KOH) đun nóng được gọi là phản ứng gì?', N'Xà phòng hóa.', N'Tráng bạc.', N'Trùng hợp.', N'Ester hóa.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (4, 1, N'Đặc điểm nào sau đây giải thích tại sao ester thường có nhiệt độ sôi thấp hơn so với alcohol có cùng số nguyên tử carbon?', N'Ester có khối lượng phân tử lớn hơn alcohol.', N'Phân tử ester phân cực mạnh hơn phân tử alcohol.', N'Ester dễ bay hơi hơn so với các alcohol tương ứng.', N'Giữa các phân tử ester không có liên kết hydrogen.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (5, 1, N'Chất béo là triester của glycerol với chất nào sau đây?', N'Alcohol no, đơn chức.', N'Amino acid.', N'Acid béo.', N'Aldehyde no.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (6, 1, N'Ở điều kiện thường, dầu thực vật ở trạng thái lỏng vì chứa chủ yếu?', N'Gốc hydrocarbon no trong phân tử.', N'Gốc acid béo no.', N'Gốc acid béo không no.', N'Nhiều vòng benzene trong phân tử.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (7, 1, N'Quá trình chuyển hóa chất béo lỏng (dầu) thành chất béo rắn (bơ nhân tạo) được thực hiện bằng phản ứng nào?', N'Hydrogen hóa.', N'Oxi hóa.', N'Thủy phân.', N'Trùng ngưng.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (8, 1, N'Công thức chung của ester no, đơn chức, mạch hở là gì?', N'CₙH₂ₙO₂ (n ≥ 2).', N'CₙH₂ₙ₊₂O₂ (n ≥ 1).', N'CₙH₂ₙ₋₂O₂ (n ≥ 3).', N'CₙH₂ₙO (n ≥ 1).', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (9, 1, N'Tên gọi của ester có công thức CH₃COOCH=CH₂ là gì?', N'Methyl acrylate.', N'Vinyl acetate.', N'Ethyl acetate.', N'Methyl methacrylate.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (10, 1, N'Trong các chất sau, chất nào không phải là lipid?', N'Sáp ong.', N'Dầu ăn.', N'Mỡ động vật.', N'Lòng trắng trứng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (11, 1, N'Phát biểu nào sau đây là không đúng khi nói về phản ứng thủy phân ester?', N'Thủy phân ester trong môi trường acid là phản ứng thuận nghịch.', N'Sản phẩm của phản ứng xà phòng hóa là muối và alcohol.', N'Trong công nghiệp, thủy phân chất béo dùng để sản xuất xà phòng.', N'Phản ứng xà phòng hóa là một phản ứng xảy ra nhanh ở nhiệt độ thường.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (12, 1, N'Acid nào sau đây là một acid béo no?', N'Acid oleic (C₁₇H₃₃COOH).', N'Acid linoleic (C₁₇H₃₁COOH).', N'Acid acrylic (CH₂=CH-COOH).', N'Acid stearic (C₁₇H₃₅COOH).', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (13, 1, N'Dầu mỡ để lâu trong không khí thường có mùi khó chịu. Hiện tượng này gọi là gì?', N'Sự lên men của vi khuẩn.', N'Sự oxi hóa chậm chất béo.', N'Sự bay hơi của các ester.', N'Sự thủy phân chất béo.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (14, 1, N'Để điều chế ethyl acetate, người ta tiến hành đun nóng hỗn hợp nào sau đây với H₂SO₄ đặc làm xúc tác?', N'Acetic acid và methyl alcohol.', N'Formic acid và ethyl alcohol.', N'Acetic acid và ethyl alcohol.', N'Propionic acid và ethyl alcohol.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (15, 1, N'Phát biểu nào sau đây đúng?', N'Tất cả các ester đều tan tốt trong nước và có mùi thơm.', N'Chất béo là chất lỏng, nhẹ hơn nước và không tan trong nước.', N'Phản ứng giữa acid và alcohol khi có mặt H₂SO₄ đặc là phản ứng một chiều.', N'Lipid là những hợp chất hữu cơ không tan trong nước, tan trong dung môi hữu cơ.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (16, 1, N'Thủy phân hoàn toàn 8,8 gam ethyl acetate (CH₃COOC₂H₅) trong dung dịch NaOH dư, đun nóng. Khối lượng muối sodium acetate thu được là bao nhiêu?', N'8,2 gam.', N'4,1 gam.', N'9,6 gam.', N'10,2 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (17, 1, N'Để trung hòa hoàn toàn 14 gam một chất béo cần dùng 150 ml dung dịch KOH 0,4M. Chỉ số acid của mẫu chất béo này là bao nhiêu?', N'12.', N'24.', N'6.', N'4.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (18, 1, N'Đun nóng 6,0 gam CH₃COOH với 6,0 gam C₂H₅OH (có H₂SO₄ đặc làm xúc tác). Khối lượng ester tạo thành khi hiệu suất phản ứng đạt 80% là bao nhiêu?', N'7,04 gam.', N'8,80 gam.', N'10,56 gam.', N'6,40 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (19, 1, N'Xà phòng hóa hoàn toàn 1 mol tristearin ((C₁₇H₃₅COO)₃C₃H₅) trong dung dịch NaOH, thu được bao nhiêu gam glycerol?', N'92 gam.', N'46 gam.', N'184 gam.', N'276 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (20, 1, N'Cần bao nhiêu kg chất béo chứa 89% tristearin về khối lượng để sản xuất được 1 tấn xà phòng (sodium stearate)? Giả sử hiệu suất của quá trình là 90%.', N'1102,5 kg.', N'982,2 kg.', N'1091,3 kg.', N'1224,8 kg.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (21, 1, N'Đốt cháy hoàn toàn 7,4 gam một ester no, đơn chức, mạch hở X thu được 6,72 lít khí CO₂ (đktc). Công thức phân tử của X là gì?', N'C₂H₄O₂.', N'C₃H₆O₂.', N'C₄H₈O₂.', N'C₅H₁₀O₂.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (22, 1, N'Một ester X có công thức phân tử C₄H₈O₂. Khi thủy phân X trong môi trường acid thu được alcohol Y. Đem oxi hóa Y bằng CuO thu được sản phẩm không có khả năng tham gia phản ứng tráng bạc. Tên gọi của X là gì?', N'Propyl formate.', N'Ethyl acetate.', N'Isopropyl formate.', N'Methyl propionate.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (23, 1, N'Xà phòng hóa hoàn toàn 17,24 gam chất béo cần vừa đủ 0,06 mol NaOH. Cô cạn dung dịch sau phản ứng, khối lượng xà phòng thu được là bao nhiêu?', N'17,80 gam.', N'18,24 gam.', N'16,68 gam.', N'18,38 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (24, 1, N'Hỗn hợp X gồm hai ester đơn chức là đồng phân của nhau. Đun nóng 14,8 gam hỗn hợp X với dung dịch NaOH vừa đủ, thu được 16,4 gam hỗn hợp hai muối và một alcohol Y duy nhất. Công thức của hai ester là:', N'HCOOC₃H₇ và CH₃COOC₂H₅.', N'CH₃COOC₂H₅ và C₂H₅COOCH₃.', N'HCOOC(CH₃)₂CH₃ và CH₃COOC₂H₅.', N'C₃H₇COOCH₃ và C₂H₅COOC₂H₅.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (25, 1, N'Thủy phân hoàn toàn m gam chất béo X bằng dung dịch NaOH, thu được 9,2 gam glycerol và 91,8 gam muối của một acid béo duy nhất. Công thức của X là:', N'(C₁₅H₃₁COO)₃C₃H₅.', N'(C₁₇H₃₅COO)₃C₃H₅.', N'(C₁₇H₃₃COO)₃C₃H₅.', N'(C₁₇H₃₁COO)₃C₃H₅.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (26, 1, N'Đốt cháy hoàn toàn a mol một triglyceride X thu được b mol CO₂ và c mol H₂O, với b – c = 4a. Khi thủy phân hoàn toàn a mol X trong dung dịch NaOH thì thu được glycerol và hỗn hợp hai muối sodium stearate và sodium oleate. Tỉ lệ mol của hai muối này là:', N'1 : 2.', N'2 : 1.', N'1 : 1.', N'1 : 3.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (27, 1, N'Một ester đơn chức, mạch hở X có tỉ khối hơi so với CH₄ là 6,25. Cho 20 gam X tác dụng với 300 ml dung dịch KOH 1M, đun nóng. Cô cạn dung dịch sau phản ứng thu được 28 gam chất rắn khan. Công thức cấu tạo của X là:', N'CH₃COOC₂H₅.', N'C₂H₅COOCH₃.', N'HCOOC₃H₇.', N'CH₃COOCH=CH₂.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (28, 1, N'Hỗn hợp M gồm acid acetic, acid acrylic và ester methyl acetate. Đốt cháy hoàn toàn m gam hỗn hợp M cần dùng vừa đủ 0,47 mol O₂. Mặt khác, m gam M tác dụng vừa đủ với 100 ml dung dịch NaOH 1M. Nếu cho m gam M vào dung dịch Br₂ dư thì số mol Br₂ phản ứng tối đa là:', N'0,10 mol.', N'0,04 mol.', N'0,06 mol.', N'0,05 mol.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (29, 1, N'Một triglyceride X được tạo bởi glycerol và hai loại acid béo là acid palmitic và acid oleic. Đun nóng 43,45 gam X với dung dịch NaOH dư, thu được 45,05 gam hỗn hợp muối. Số mol acid palmitic có trong 43,45 gam X là:', N'0,05 mol.', N'0,025 mol.', N'0,075 mol.', N'0,10 mol.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (30, 1, N'Hỗn hợp E gồm hai ester đơn chức, là đồng phân cấu tạo và đều chứa vòng benzene. Đun nóng 13,6 gam E với dung dịch NaOH dư, thu được dung dịch T chứa các chất hữu cơ. Cho toàn bộ T tác dụng với dung dịch AgNO₃ trong NH₃ dư, thu được 43,2 gam Ag. Khối lượng muối có trong T là:', N'18,8 gam.', N'19,8 gam.', N'8,2 gam.', N'16,4 gam.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (31, 2, N'Về mặt hóa học, xà phòng là hỗn hợp muối sodium hoặc potassium của chất nào sau đây?', N'Alcohol.', N'Acid béo.', N'Hydrocarbon.', N'Amino acid.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (32, 2, N'Thành phần chính của xà phòng là C₁₇H₃₅COONa. Phần nào trong phân tử này được gọi là “đầu ưa nước”?', N'Toàn bộ phân tử C₁₇H₃₅COONa.', N'Phần gốc hydrocarbon C₁₇H₃₅–.', N'Nhóm carboxylate –COO⁻Na⁺.', N'Nguyên tử sodium Na.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (33, 2, N'Trong phân tử xà phòng, gốc hydrocarbon dài (ví dụ C₁₇H₃₅–) có đặc tính gì?', N'Dễ tan trong nước, kị dầu mỡ.', N'Vừa tan trong nước, vừa tan trong dầu mỡ.', N'Dễ tan trong dầu mỡ, kị nước.', N'Không tan trong cả nước và dầu mỡ.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (34, 2, N'Cơ chế hoạt động giặt rửa của xà phòng và chất giặt rửa tổng hợp là gì?', N'Phản ứng hóa học với chất bẩn, tạo thành chất tan.', N'Giảm sức căng bề mặt của nước, làm chất bẩn bị phân tán.', N'Phản ứng oxi hóa khử mạnh, phá hủy cấu trúc chất bẩn.', N'Tạo lớp màng bao bọc chất bẩn và kéo ra khỏi bề mặt vải.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (35, 2, N'Tại sao xà phòng bị giảm tác dụng giặt rửa khi dùng với nước cứng?', N'Do xà phòng bị thủy phân mạnh trong nước cứng.', N'Do các ion Ca²⁺, Mg²⁺ làm kết tủa muối của acid béo.', N'Do nước cứng có pH cao, làm trung hòa tính acid của xà phòng.', N'Do xà phòng phản ứng với các anion có trong nước cứng.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (36, 2, N'Nguồn nguyên liệu chính để sản xuất xà phòng trong công nghiệp là gì?', N'Dầu mỏ và than đá.', N'Alcohol và acid vô cơ.', N'Chất béo động vật và dầu thực vật.', N'Các loại quặng kim loại kiềm.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (37, 2, N'Chất giặt rửa tổng hợp là những chất có đặc điểm nào sau đây?', N'Là muối của acid béo có nguồn gốc từ tự nhiên.', N'Không phải là muối của acid béo, có khả năng giặt rửa.', N'Chỉ có khả năng giặt rửa trong môi trường nước mềm.', N'Được sản xuất bằng cách lên men thực vật.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (38, 2, N'Ưu điểm chính của chất giặt rửa tổng hợp so với xà phòng là gì?', N'Có nguồn gốc hoàn toàn từ thiên nhiên, thân thiện môi trường.', N'Có thể dùng được với nước cứng mà không tạo kết tủa.', N'Có giá thành sản xuất rẻ hơn rất nhiều so với xà phòng.', N'Có khả năng diệt khuẩn mạnh hơn xà phòng thông thường.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (39, 2, N'Một trong những nhược điểm của chất giặt rửa tổng hợp có nguồn gốc từ dầu mỏ là gì?', N'Gây ăn mòn các vật dụng bằng kim loại.', N'Dễ bị phân hủy sinh học gây tắc nghẽn.', N'Có tính acid mạnh, làm hỏng sợi vải.', N'Khó bị phân hủy sinh học, có thể gây ô nhiễm môi trường.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (40, 2, N'Hợp chất nào sau đây là một ví dụ về chất giặt rửa tổng hợp?', N'(C₁₇H₃₅COO)₂Ca.', N'C₁₇H₃₅COONa.', N'CH₃[CH₂]₁₀CH₂OSO₃Na.', N'C₃H₅(OH)₃.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (41, 2, N'Saponin có trong quả bồ kết, bồ hòn là một loại chất giặt rửa có nguồn gốc từ đâu?', N'Thiên nhiên.', N'Tổng hợp từ dầu mỏ.', N'Bán tổng hợp từ cellulose.', N'Sản phẩm của vi sinh vật.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (42, 2, N'Khi giặt quần áo bằng xà phòng trong nước cứng, hiện tượng thường thấy là:', N'Quần áo sạch hơn và mềm hơn so với giặt bằng nước mềm.', N'Xuất hiện các cặn bẩn màu trắng bám trên quần áo.', N'Tiêu tốn ít xà phòng hơn so với khi giặt bằng nước mềm.', N'Bọt xà phòng xuất hiện nhiều và bền hơn bình thường.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (43, 2, N'Thành phần hóa học của lớp cặn tạo ra khi đun sôi nước cứng tạm thời và lớp cặn tạo ra khi dùng xà phòng trong nước cứng có điểm chung là gì?', N'Đều là muối của kim loại kiềm.', N'Đều chứa ion Ca²⁺ hoặc Mg²⁺.', N'Đều là các hợp chất tan tốt trong nước.', N'Đều có khả năng giặt rửa mạnh.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (44, 2, N'Phát biểu nào sau đây không đúng?', N'Xà phòng và chất giặt rửa tổng hợp đều có cấu trúc gồm đầu ưa nước và đuôi kị nước.', N'Chất giặt rửa tổng hợp có thể giặt rửa hiệu quả trong cả nước cứng và nước mềm.', N'Xà phòng là muối của acid béo nên có tính kiềm nhẹ khi tan trong nước.', N'Muối calcium stearate, (C₁₇H₃₅COO)₂Ca, tan tốt trong nước.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (45, 2, N'Để phân biệt xà phòng và chất giặt rửa tổng hợp, ta có thể dùng thuốc thử nào sau đây?', N'Nước cứng (chứa ion Ca²⁺, Mg²⁺).', N'Dung dịch HCl.', N'Dung dịch quỳ tím.', N'Dung dịch I₂.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (46, 2, N'Để xà phòng hóa hoàn toàn 8,9 kg tristearin ((C₁₇H₃₅COO)₃C₃H₅) cần dùng tối thiểu bao nhiêu kg dung dịch NaOH 20%?', N'8,0 kg.', N'6,0 kg.', N'1,2 kg.', N'4,0 kg.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (47, 2, N'Từ 1 tấn mỡ chứa 90% tristearin (về khối lượng), đem xà phòng hóa hoàn toàn có thể thu được khối lượng sodium stearate (C₁₇H₃₅COONa) là bao nhiêu, biết hiệu suất phản ứng là 95%?', N'928,5 kg.', N'981,5 kg.', N'839,4 kg.', N'883,6 kg.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (48, 2, N'Khi cho xà phòng (sodium stearate) dư vào một dung dịch chứa 0,02 mol CaCl₂, khối lượng kết tủa thu được là bao nhiêu gam?', N'6,06 gam.', N'13,32 gam.', N'12,12 gam.', N'18,18 gam.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (49, 2, N'Một mẫu chất giặt rửa tổng hợp có công thức CH₃[CH₂]₁₁OSO₃Na. Phần trăm khối lượng của lưu huỳnh (S) trong mẫu chất này là bao nhiêu?', N'11,11%.', N'12,50%.', N'9,76%.', N'10,53%.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (50, 2, N'Xà phòng hóa hoàn toàn 178 kg một loại chất béo trung tính cần vừa đủ 24 kg NaOH. Khối lượng xà phòng thu được là bao nhiêu kg?', N'183,6 kg.', N'202,0 kg.', N'163,6 kg.', N'196,4 kg.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (51, 2, N'Để sản xuất một bánh xà phòng 100 gam có chứa 76,5% sodium stearate, khối lượng glycerol thu được trong quá trình sản xuất là bao nhiêu gam?', N'9,20 gam.', N'7,65 gam.', N'8,28 gam.', N'7,82 gam.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (52, 2, N'Có hai ống nghiệm: ống (1) chứa 3 mL nước cất và ống (2) chứa 3 mL nước cứng (dung dịch CaCl₂ 0,01M). Thêm vào mỗi ống 5 giọt dung dịch xà phòng rồi lắc đều. Hiện tượng quan sát được là:', N'Cả hai ống đều có nhiều bọt và dung dịch trong suốt.', N'Ống (1) có nhiều bọt, ống (2) có ít bọt và xuất hiện vẩn đục.', N'Ống (1) có ít bọt và vẩn đục, ống (2) có nhiều bọt và trong suốt.', N'Cả hai ống đều có ít bọt và xuất hiện vẩn đục như nhau.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (53, 2, N'Một gia đình sống ở vùng núi đá vôi thường thấy quần áo sau khi giặt bằng xà phòng hay bị khô cứng và có cặn bám. Để khắc phục tình trạng này, giải pháp nào sau đây là hiệu quả nhất?', N'Tăng lượng xà phòng sử dụng lên gấp đôi.', N'Thay thế xà phòng bằng chất giặt rửa tổng hợp.', N'Đun sôi nước thật kỹ trước khi giặt.', N'Ngâm quần áo trong dung dịch acid loãng trước khi giặt.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (54, 2, N'Để giặt rửa vết dầu mỡ bám trên các thiết bị máy móc ở một tàu đi biển, nên sử dụng loại chất nào sau đây để đạt hiệu quả cao nhất?', N'Xà phòng thông thường.', N'Nước bồ kết đun sôi.', N'Bột giặt (chất giặt rửa tổng hợp).', N'Cồn (ethanol).', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (55, 2, N'Một loại mỡ chứa 50% tristearin, 30% triolein và 20% tạp chất trơ. Khối lượng xà phòng (hỗn hợp muối sodium) thu được khi xà phòng hóa hoàn toàn 100 kg loại mỡ trên là bao nhiêu?', N'85,2 kg.', N'82,5 kg.', N'165,1 kg.', N'78,8 kg.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (56, 2, N'Xà phòng hóa hoàn toàn m gam một chất béo X bằng dung dịch NaOH, thu được 0,92 gam glycerol và hỗn hợp hai muối C₁₇H₃₅COONa và C₁₅H₃₁COONa với tỉ lệ mol 2:1. Giá trị của m là:', N'8,62 gam.', N'8,74 gam.', N'8,90 gam.', N'8,66 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (57, 2, N'So sánh khối lượng xà phòng (sodium stearate) và chất giặt rửa tổng hợp (sodium dodecylsulfate, C₁₂H₂₅OSO₃Na) cần dùng để loại bỏ cùng một lượng ion Ca²⁺ trong nước cứng bằng phương pháp kết tủa.', N'Khối lượng xà phòng cần dùng lớn hơn.', N'Khối lượng chất giặt rửa tổng hợp lớn hơn.', N'Khối lượng cần dùng của hai chất là như nhau.', N'Chất giặt rửa tổng hợp không tạo kết tủa với ion Ca²⁺.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (58, 2, N'Một mẫu chất béo được tạo bởi glycerol và hai acid béo là acid stearic và acid oleic. Khi xà phòng hóa hoàn toàn 44,15 gam mẫu chất béo này thu được 45,75 gam hỗn hợp hai muối. Phần trăm số mol của gốc oleic trong hỗn hợp muối thu được là:', N'66,67%.', N'33,33%.', N'50,00%.', N'75,00%.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (59, 2, N'Đốt cháy hoàn toàn a gam một loại xà phòng X (là muối natri của một acid béo no, đơn chức), thu được muối Na₂CO₃, CO₂ và 9,9 gam H₂O. Mặt khác, a gam X làm mất màu vừa đủ 16 gam dung dịch Br₂ 20%. Công thức của acid béo tạo nên xà phòng X là:', N'C₁₅H₃₁COOH.', N'C₁₇H₃₅COOH.', N'C₁₇H₃₃COOH.', N'C₁₅H₂₉COOH.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (60, 2, N'Một hỗn hợp gồm bột giặt (chứa 60% C₁₂H₂₅OSO₃Na về khối lượng, còn lại là chất phụ gia trơ) và xà phòng (chứa 75% C₁₇H₃₅COONa, còn lại là chất trơ). Khi cho 10 gam hỗn hợp này vào nước cứng dư, thu được 2,97 gam kết tủa. Thành phần phần trăm khối lượng của bột giặt trong hỗn hợp ban đầu là:', N'60%.', N'40%.', N'50%.', N'30%.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (61, 3, N'Carbohydrate (glucid) là những hợp chất hữu cơ tạp chức và thường có công thức chung là', N'Cₓ(H₂O)ᵧ.', N'CₙH₂ₙO₂.', N'Cₙ(H₂O)ₘ.', N'(RCOO)₃C₃H₅.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (62, 3, N'Chất nào sau đây thuộc loại monosaccharide?', N'Saccharose.', N'Maltose.', N'Tinh bột.', N'Fructose.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (63, 3, N'Glucose và fructose là hai chất có mối quan hệ', N'đồng phân về vị trí nhóm chức.', N'đồng đẳng của nhau.', N'đồng phân cấu tạo của nhau.', N'đồng phân hình học.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (64, 3, N'Đặc điểm cấu tạo của phân tử saccharose là', N'trong phân tử không còn nhóm -OH hemiacetal tự do.', N'được cấu tạo từ hai gốc α-glucose liên kết với nhau.', N'có một gốc α-glucose liên kết với một gốc β-glucose.', N'phân tử có chứa nhiều nhóm -OH nhưng không liền kề.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (65, 3, N'Ở dạng mạch hở, phân tử glucose có cấu tạo của một', N'polyhydroxy ketone.', N'polyhydroxy aldehyde.', N'polyhydroxy ether.', N'polyhydroxy acid.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (66, 3, N'Nhận định nào sau đây là không đúng khi nói về cellulose?', N'Là thành phần chính tạo nên màng tế bào thực vật.', N'Phân tử được cấu tạo bởi các mắt xích β-glucose.', N'Cellulose có cấu trúc mạch phân nhánh phức tạp.', N'Công thức phân tử của cellulose là (C₆H₁₀O₅)ₙ.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (67, 3, N'Trong củ cải đường chứa hàm lượng lớn loại carbohydrate nào?', N'Glucose.', N'Fructose.', N'Saccharose.', N'Tinh bột.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (68, 3, N'Tinh bột được tạo thành trong cây xanh nhờ quá trình nào?', N'Hô hấp.', N'Quang hợp.', N'Trao đổi chất.', N'Thủy phân.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (69, 3, N'Phát biểu nào sau đây là đúng?', N'Maltose được cấu tạo từ 1 gốc glucose và 1 gốc fructose.', N'Tinh bột và cellulose là đồng phân vì có cùng công thức (C₆H₁₀O₅)ₙ.', N'Fructose ở dạng mạch hở có 6 nhóm hydroxyl và 1 nhóm ketone.', N'Phân tử maltose vẫn còn nhóm -OH hemiacetal nên có khả năng mở vòng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (70, 3, N'Amylopectin, một thành phần của tinh bột, có đặc điểm cấu trúc là', N'các gốc α-glucose liên kết tạo mạch không phân nhánh.', N'các gốc β-glucose liên kết với nhau tạo thành mạch thẳng.', N'có cấu trúc mạch phân nhánh nhờ liên kết α-1,4- và α-1,6-glycoside.', N'các gốc β-glucose liên kết tạo thành mạch có phân nhánh.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (71, 3, N'Trong y học, glucose được dùng làm', N'thuốc giảm đau.', N'thuốc kháng sinh.', N'thuốc tăng lực.', N'thuốc hạ sốt.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (72, 3, N'Loại carbohydrate nào sau đây là thành phần chính của sợi bông, đay?', N'Tinh bột.', N'Saccharose.', N'Glucose.', N'Cellulose.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (73, 3, N'Trong mật ong chứa nhiều fructose, làm cho mật ong có vị ngọt đậm. Fructose còn có tên gọi khác là', N'đường phèn.', N'đường nho.', N'đường quả.', N'đường mía.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (74, 3, N'Sự khác biệt cơ bản nhất về cấu tạo giữa amylose và cellulose là', N'về thành phần nguyên tố trong phân tử.', N'về liên kết giữa các mắt xích trong mạch.', N'về khối lượng phân tử trung bình.', N'về tính tan trong nước nóng.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (75, 3, N'Dữ kiện thực nghiệm nào sau đây dùng để chứng minh phân tử glucose có 5 nhóm hydroxyl?', N'Cho glucose phản ứng với dung dịch AgNO₃ trong NH₃.', N'Cho glucose phản ứng tạo este chứa 5 gốc acid trong phân tử.', N'Khử hoàn toàn glucose thu được hexane.', N'Hòa tan Cu(OH)₂ ở nhiệt độ thường tạo dung dịch xanh lam.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (76, 3, N'Khối lượng phân tử của saccharose (C₁₂H₂₂O₁₁) là bao nhiêu?', N'180.', N'342.', N'360.', N'162.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (77, 3, N'Thủy phân hoàn toàn 34,2 gam saccharose trong môi trường acid, thu được m gam glucose. Giá trị của m là', N'18,0.', N'17,1.', N'34,2.', N'36,0.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (78, 3, N'Đốt cháy hoàn toàn một carbohydrate X thu được số mol CO₂ bằng số mol H₂O. X là chất nào sau đây?', N'Saccharose.', N'Maltose.', N'Tinh bột.', N'Glucose.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (79, 3, N'Phần trăm khối lượng carbon trong phân tử fructose (C₆H₁₂O₆) là', N'40,00%.', N'53,33%.', N'6,67%.', N'42,10%.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (80, 3, N'Một phân tử maltose được cấu tạo từ bao nhiêu nguyên tử oxygen?', N'6.', N'12.', N'11.', N'22.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (81, 3, N'Khi thuỷ phân 1 mol tinh bột, ta có thể thu được sản phẩm cuối cùng là', N'1 mol glucose và 1 mol fructose.', N'n mol glucose.', N'n mol fructose.', N'2 mol glucose.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (82, 3, N'Thủy phân hoàn toàn m gam tinh bột, sau đó lên men tạo 500 mL dung dịch ethanol 46°. Biết khối lượng riêng của ethanol là 0,8 g/mL. Giá trị của m là', N'405,0.', N'324,0.', N'450,0.', N'202,5.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (83, 3, N'Khối lượng phân tử trung bình của một loại cellulose là 4.860.000 đvC. Số mắt xích C₆H₁₀O₅ trong phân tử cellulose này là', N'27.000.', N'30.000.', N'15.000.', N'25.000.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (84, 3, N'Cho m gam hỗn hợp X gồm glucose và fructose tác dụng với AgNO₃/NH₃ dư, thu được 43,2 gam Ag. Giá trị của m là', N'18,0.', N'36,0.', N'45,0.', N'27,0.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (85, 3, N'Đun nóng dung dịch chứa 27 gam glucose với AgNO₃/NH₃ dư, hiệu suất phản ứng 80%, khối lượng bạc thu được là', N'21,60 gam.', N'32,40 gam.', N'25,92 gam.', N'17,28 gam.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (86, 3, N'Để có 29,7 kg saccharose từ cây mía (13% saccharose, 80% lượng nước ép), khối lượng mía cần dùng là', N'285,58 kg.', N'228,46 kg.', N'312,50 kg.', N'250,00 kg.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (87, 3, N'Cho sơ đồ chuyển hóa: Tinh bột → X → Y → Acid acetic. Các chất X, Y lần lượt là', N'Fructose, ethanol.', N'Glucose, ethanol.', N'Maltose, anđehit axetic.', N'Glucose, anđehit axetic.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (88, 3, N'Thủy phân hỗn hợp gồm 0,02 mol saccharose và 0,01 mol maltose (hiệu suất 75%), lượng Ag thu được là', N'9,18 gam.', N'6,48 gam.', N'8,10 gam.', N'9,72 gam.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (89, 3, N'Lên men m gam glucose sinh ra khí CO₂ hấp thụ vào Ca(OH)₂ tạo 40 gam kết tủa (hiệu suất 80%). Giá trị của m là', N'36,0.', N'45,0.', N'28,8.', N'22,5.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (90, 3, N'Từ 1 tấn tinh bột chứa 20% tạp chất, sản xuất ethanol (hao hụt 10%). Khối lượng ethanol thu được là', N'409,8 kg.', N'364,4 kg.', N'455,6 kg.', N'410,0 kg.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (91, 4, N'Phản ứng nào sau đây chứng tỏ phân tử glucose có nhiều nhóm hydroxyl (-OH) kề nhau?', N'Phản ứng với Cu(OH)₂ ở nhiệt độ thường tạo dung dịch màu xanh lam.', N'Phản ứng lên men dưới tác dụng của enzyme để tạo thành ethanol.', N'Phản ứng với dung dịch AgNO₃ trong NH₃, đun nóng tạo kết tủa bạc.', N'Phản ứng khử hoàn toàn glucose bằng H₂ (xúc tác Ni, t°) tạo sobitol.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (92, 4, N'Chất nào sau đây không tham gia phản ứng thuỷ phân trong môi trường acid?', N'Tinh bột.', N'Fructose.', N'Saccharose.', N'Cellulose.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (93, 4, N'Để phân biệt hai dung dịch riêng biệt là glucose và fructose, người ta có thể dùng thuốc thử nào sau đây?', N'Dung dịch AgNO₃ trong NH₃, đun nóng.', N'Thuốc thử Cu(OH)₂ trong môi trường kiềm.', N'Dung dịch nước bromine.', N'Dung dịch HCl loãng.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (94, 4, N'Fructose có thể tham gia phản ứng tráng bạc vì lý do nào sau đây?', N'Trong môi trường kiềm, fructose chuyển hoá thành glucose.', N'Phân tử fructose có chứa nhóm chức aldehyde (-CHO).', N'Fructose có khả năng bị oxi hóa mạnh hơn so với glucose.', N'Tất cả các monosaccharide đều tham gia phản ứng tráng bạc.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (95, 4, N'Khi đun nóng dung dịch glucose với Cu(OH)₂ trong môi trường kiềm, hiện tượng quan sát được là', N'dung dịch chuyển sang màu tím đặc trưng.', N'không có hiện tượng gì xảy ra.', N'xuất hiện kết tủa bạc sáng bóng.', N'xuất hiện kết tủa màu đỏ gạch (Cu₂O).', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (96, 4, N'Thuốc thử đặc trưng dùng để nhận biết hồ tinh bột là', N'dung dịch H₂SO₄ đặc.', N'dung dịch iodine.', N'dung dịch NaOH.', N'dung dịch HCl.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (97, 4, N'Dãy các chất nào sau đây đều có thể tham gia phản ứng tráng bạc?', N'Saccharose, maltose, fructose.', N'Tinh bột, cellulose, saccharose.', N'Glucose, saccharose, maltose.', N'Glucose, fructose, maltose.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (98, 4, N'Phản ứng thủy phân saccharose trong môi trường acid tạo ra sản phẩm là', N'một phân tử glucose và một phân tử fructose.', N'hai phân tử glucose.', N'hai phân tử fructose.', N'một phân tử monosaccharide duy nhất.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (99, 4, N'Sản phẩm chính thu được khi cho cellulose tác dụng với dung dịch HNO₃ đặc trong H₂SO₄ đặc, đun nóng là', N'cellulose mononitrate.', N'cellulose dinitrate.', N'cellulose trinitrate.', N'hỗn hợp các acid.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (100, 4, N'Phát biểu nào sau đây là sai?', N'Dung dịch maltose có khả năng làm mất màu nước bromine.', N'Thủy phân hoàn toàn tinh bột hoặc cellulose đều thu được glucose.', N'Saccharose có tính chất của một polyol nhưng không có tính khử.', N'Glucose và fructose đều có phản ứng thủy phân trong môi trường acid.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (101, 4, N'Phản ứng nào chứng tỏ glucose có tính chất của một aldehyde?', N'Tác dụng với Cu(OH)₂ tạo dung dịch xanh lam.', N'Lên men tạo thành acid lactic.', N'Tác dụng với H₂ (xúc tác Ni, t°) tạo sobitol.', N'Phản ứng làm mất màu dung dịch KMnO₄.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (102, 4, N'Khi nhỏ dung dịch iodine vào một lát cắt củ khoai lang, hiện tượng xảy ra là', N'lát cắt khoai lang chuyển sang màu xanh tím.', N'lát cắt khoai lang chuyển sang màu đỏ gạch.', N'dung dịch iodine bị mất màu hoàn toàn.', N'không có hiện tượng đặc biệt nào xảy ra.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (103, 4, N'Phân biệt dung dịch glucose và dung dịch saccharose có thể dùng thuốc thử nào sau đây?', N'Quỳ tím.', N'Dung dịch HCl.', N'Cu(OH)₂/NaOH, đun nóng.', N'Dung dịch NaCl.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (104, 4, N'Trong điều kiện thích hợp, glucose lên men tạo thành ethanol và khí X. Khí X là', N'H₂.', N'CO₂.', N'SO₂.', N'O₂.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (105, 4, N'Điểm khác biệt cơ bản về tính chất hoá học giữa maltose và saccharose là', N'maltose có phản ứng với Cu(OH)₂, saccharose thì không.', N'saccharose bị thuỷ phân trong môi trường acid, maltose thì không.', N'maltose là chất kết tinh không màu, saccharose là chất lỏng.', N'maltose có tính khử (phản ứng tráng bạc), saccharose thì không.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (106, 4, N'Đun nóng dung dịch chứa 9,0 gam glucose với lượng dư dung dịch AgNO₃ trong NH₃, thu được m gam Ag. Giá trị của m là', N'10,8.', N'5,4.', N'21,6.', N'16,2.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (107, 4, N'Cho 18 gam fructose tác dụng với Cu(OH)₂/NaOH dư, đun nóng. Khối lượng kết tủa Cu₂O thu được là', N'7,2 gam.', N'28,8 gam.', N'14,4 gam.', N'21,6 gam.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (108, 4, N'Lên men 45 gam glucose để tạo thành ethanol (hiệu suất 100%). Khối lượng ethanol thu được là', N'11,5 gam.', N'23,0 gam.', N'46,0 gam.', N'34,5 gam.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (109, 4, N'Thủy phân hoàn toàn 68,4 gam saccharose, thu được khối lượng glucose là', N'18,0 gam.', N'68,4 gam.', N'27,0 gam.', N'36,0 gam.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (110, 4, N'Để sản xuất 59,4 kg cellulose trinitrate từ cellulose và acid nitric, cần dùng ít nhất m kg acid nitric. Giá trị của m là', N'18,9 kg.', N'42,0 kg.', N'37,8 kg.', N'21,0 kg.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (111, 4, N'Cho một lượng maltose tham gia phản ứng tráng bạc hoàn toàn, thu được 8,64 gam Ag. Khối lượng maltose đã tham gia phản ứng là', N'13,68 gam.', N'6,84 gam.', N'27,36 gam.', N'3,42 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (112, 4, N'Lên men m gam glucose với hiệu suất 90%, lượng khí CO₂ sinh ra hấp thụ hết vào dung dịch nước vôi trong dư, thu được 10 gam kết tủa. Giá trị của m là', N'20,0.', N'15,0.', N'10,0.', N'18,0.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (113, 4, N'Thủy phân 34,2 gam saccharose với hiệu suất 75%, sau phản ứng thu được dung dịch X. Cho toàn bộ dung dịch X tác dụng với lượng dư dung dịch AgNO₃ trong NH₃, đun nóng, khối lượng Ag thu được là', N'32,4 gam.', N'16,2 gam.', N'21,6 gam.', N'43,2 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (114, 4, N'Một dung dịch X chứa glucose và saccharose. Lấy 100 ml dung dịch X cho phản ứng với lượng dư dung dịch AgNO₃/NH₃ thu được 2,16 gam Ag. Lấy 100 ml dung dịch X khác, thủy phân hoàn toàn rồi mới cho phản ứng tráng bạc thì thu được 6,48 gam Ag. Nồng độ mol của glucose và saccharose trong dung dịch X lần lượt là', N'0,1M và 0,2M.', N'0,2M và 0,1M.', N'0,1M và 0,1M.', N'0,2M và 0,2M.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (115, 4, N'Hỗn hợp X gồm glucose và fructose. Cho m gam X tác dụng hết với H₂ (dư, Ni, t°) thu được 36,4 gam sobitol. Nếu cho m gam X tác dụng với lượng dư dung dịch AgNO₃/NH₃ thì khối lượng Ag thu được là', N'21,6 gam.', N'43,2 gam.', N'10,8 gam.', N'32,4 gam.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (116, 4, N'Khối lượng cellulose cần để sản xuất 1 tấn cellulose trinitrate, biết hiệu suất của phản ứng là 90%?', N'0,60 tấn.', N'0,54 tấn.', N'0,545 tấn.', N'0,605 tấn.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (117, 4, N'Cho m gam tinh bột lên men thành ethanol với hiệu suất 81%. Toàn bộ lượng CO₂ sinh ra được hấp thụ hoàn toàn vào dung dịch Ca(OH)₂, thu được 55 gam kết tủa và dung dịch X. Đun kỹ dung dịch X thu thêm được 10 gam kết tủa nữa. Giá trị của m là', N'75.', N'150.', N'100.', N'200.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (118, 4, N'Hỗn hợp X gồm saccharose và maltose. Thủy phân hoàn toàn 70,2 gam X trong môi trường acid, thu được dung dịch Y. Trung hòa acid trong Y rồi cho toàn bộ Y tác dụng với lượng dư dung dịch AgNO₃ trong NH₃, thu được 86,4 gam Ag. Phần trăm khối lượng của maltose trong hỗn hợp X là', N'48,72%.', N'51,28%.', N'72,93%.', N'24,36%.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (119, 4, N'Thủy phân m gam hỗn hợp X gồm tinh bột và saccharose (tỉ lệ mol 1:2) trong môi trường acid. Dung dịch sau phản ứng đã được trung hòa, đem thực hiện phản ứng tráng bạc, thu được 54 gam Ag. Biết hiệu suất thủy phân mỗi chất đều đạt 75%. Giá trị của m là', N'51,3 gam.', N'45,6 gam.', N'57,6 gam.', N'48,6 gam.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (120, 4, N'Đốt cháy hoàn toàn m gam hỗn hợp gồm glucose, fructose và saccharose cần dùng vừa đủ 0,45 mol O₂. Toàn bộ sản phẩm cháy được dẫn qua dung dịch Ca(OH)₂ dư, sau phản ứng thu được kết tủa có khối lượng là', N'40 gam.', N'50 gam.', N'45 gam.', N'35 gam.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (121, 5, N'Theo định nghĩa trong sách giáo khoa, amin là hợp chất hữu cơ được xem như dẫn xuất của phân tử nào?', N'Methane (CH₄)', N'Nitric acid (HNO₃)', N'Nitrobenzene (C₆H₅NO₂)', N'Ammonia (NH₃)', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (122, 5, N'Chất nào sau đây thuộc loại amin bậc hai?', N'CH₃-NH₂', N'C₆H₅-NH₂', N'CH₃-NH-C₂H₅', N'(CH₃)₃N', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (123, 5, N'Aniline (C₆H₅NH₂) được phân loại là amin gì?', N'Amin no, bậc một', N'Amin thơm, bậc một', N'Amin không no, bậc một', N'Amin thơm, bậc hai', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (124, 5, N'Tên gọi theo danh pháp gốc–chức của hợp chất (CH₃)₂NH là', N'dimethylamine.', N'N-methylmethanamine.', N'ethylamine.', N'methylethylamine.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (125, 5, N'Hợp chất CH₃CH₂CH₂NH₂ có tên thay thế là gì?', N'Propylamine', N'N-propylamine', N'Propan-1-amine', N'Propan-2-amine', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (126, 5, N'Ở điều kiện thường, nhận định nào sau đây về tính chất vật lí của methylamine (CH₃NH₂) là đúng?', N'Là chất lỏng, không màu, không tan trong nước.', N'Là chất rắn, màu trắng, có mùi thơm nhẹ.', N'Là chất lỏng, không màu, tan vô hạn trong nước.', N'Là chất khí, có mùi khai, tan tốt trong nước.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (127, 5, N'Phát biểu nào sau đây về tính chất vật lí của aniline là chính xác?', N'Là chất lỏng, không màu, rất độc và ít tan trong nước.', N'Là chất khí, không màu, có mùi thơm và tan nhiều trong nước.', N'Là chất rắn, dạng tinh thể, không độc và dễ tan trong nước.', N'Là chất lỏng, màu vàng, không độc và bay hơi mạnh.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (128, 5, N'Tính base đặc trưng của các amin là do yếu tố nào gây ra?', N'Phân tử amin có chứa nguyên tử nitrogen.', N'Trên nguyên tử N còn cặp electron tự do chưa liên kết.', N'Gốc hydrocarbon trong phân tử amin có khả năng đẩy electron.', N'Amin có khả năng tạo liên kết hydrogen với phân tử nước.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (129, 5, N'Sắp xếp các chất sau theo chiều tăng dần lực base: (1) C₆H₅NH₂, (2) NH₃, (3) CH₃NH₂.', N'(3) < (2) < (1)', N'(2) < (1) < (3)', N'(1) < (2) < (3)', N'(1) < (3) < (2)', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (130, 5, N'Lực base của aniline (C₆H₅NH₂) yếu hơn so với ammonia (NH₃) là do', N'phân tử khối của aniline lớn hơn so với phân tử khối của ammonia.', N'nhóm phenyl (-C₆H₅) có hiệu ứng hút electron làm giảm mật độ electron trên nguyên tử N.', N'aniline là chất lỏng, ít tan trong nước nên khó thể hiện tính base.', N'nguyên tử nitrogen trong aniline có độ âm điện cao hơn trong ammonia.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (131, 5, N'Hiện tượng xảy ra khi cho giấy quỳ tím ẩm vào dung dịch ethylamine là', N'giấy quỳ tím chuyển sang màu xanh.', N'giấy quỳ tím chuyển sang màu đỏ.', N'giấy quỳ tím không đổi màu.', N'giấy quỳ tím bị mất màu.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (132, 5, N'Phản ứng giữa aniline với dung dịch bromine dư tạo ra sản phẩm kết tủa có tên là', N'2,4-dibromoaniline.', N'2,6-dibromoaniline.', N'2,4,5-tribromoaniline.', N'2,4,6-tribromoaniline.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (133, 5, N'Trong công nghiệp, phương pháp chính để điều chế aniline là', N'cho benzene tác dụng với dung dịch ammonia đặc.', N'alkyl hóa ammonia bằng bromobenzene có xúc tác.', N'khử nitrobenzene bằng hỗn hợp Fe và dung dịch HCl.', N'cho phenol tác dụng với dung dịch ammonia ở nhiệt độ cao.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (134, 5, N'Khi cho ethylamine (C₂H₅NH₂) tác dụng với dung dịch HCl, sản phẩm thu được là', N'C₂H₅Cl và NH₃.', N'C₂H₅NH₃Cl.', N'C₂H₆ và NH₂Cl.', N'C₂H₄ và NH₄Cl.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (135, 5, N'Phản ứng nào sau đây chứng tỏ aniline có tính base yếu hơn ammonia?', N'Aniline không làm đổi màu quỳ tím.', N'Aniline tác dụng được với dung dịch HCl.', N'Aniline tác dụng được với dung dịch Br₂.', N'Aniline dễ bị oxi hóa trong không khí.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (136, 5, N'Đốt cháy hoàn toàn amin no, đơn chức, mạch hở X thu được tỉ lệ mol nCO₂ : nH₂O = 2 : 5. Công thức phân tử của X là', N'C₃H₉N.', N'C₄H₁₁N.', N'C₂H₇N.', N'CH₅N.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (137, 5, N'Cho 9,3 gam aniline tác dụng hoàn toàn với dung dịch bromine dư. Khối lượng kết tủa trắng thu được là', N'33,0 gam.', N'16,5 gam.', N'24,0 gam.', N'36,0 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (138, 5, N'Để trung hòa 50 ml dung dịch methylamine 0,2M cần dùng V ml dung dịch HCl 0,5M. Giá trị của V là', N'10.', N'20.', N'40.', N'50.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (139, 5, N'Một amin đơn chức X chứa 15,05% khối lượng nitrogen. Công thức phân tử của X là', N'C₄H₁₁N.', N'C₅H₁₃N.', N'C₆H₇N.', N'C₆H₁₅N.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (140, 5, N'Cho 4,5 gam ethylamine tác dụng vừa đủ với dung dịch HCl. Khối lượng muối thu được là', N'7,65 gam.', N'8,15 gam.', N'8,10 gam.', N'7,25 gam.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (141, 5, N'Đốt cháy hoàn toàn 0,1 mol một amin no, đơn chức, mạch hở X, thu được 4,48 lít khí N₂ (đktc). Số nguyên tử H trong phân tử X là', N'7.', N'5.', N'9.', N'11.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (142, 5, N'Đốt cháy hoàn toàn m gam một amin đơn chức X, thu được 8,8 gam CO₂, 6,3 gam H₂O và 1,12 lít N₂ (các khí đo ở đktc). Công thức phân tử của X là', N'C₃H₉N.', N'C₂H₇N.', N'C₄H₉N.', N'C₂H₅N.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (143, 5, N'Cho 10 gam hỗn hợp gồm hai amin no, đơn chức, mạch hở, kế tiếp nhau trong dãy đồng đẳng tác dụng vừa đủ với dung dịch HCl, thu được 15,84 gam hỗn hợp muối. Công thức của hai amin là', N'CH₃NH₂ và C₂H₅NH₂.', N'C₂H₅NH₂ và C₃H₇NH₂.', N'C₃H₉N và C₄H₁₁N.', N'C₄H₁₁N và C₅H₁₃N.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (144, 5, N'Một hỗn hợp X gồm aniline và benzene. Cho 28,1 gam hỗn hợp X tác dụng với dung dịch bromine dư thì thu được 49,5 gam kết tủa. Thành phần phần trăm khối lượng của benzene trong hỗn hợp X là', N'47,8%.', N'39,1%.', N'52,2%.', N'48,04%.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (145, 5, N'Hỗn hợp X gồm methylamine và ethylamine có tỉ lệ mol tương ứng là 1 : 2. Đốt cháy hoàn toàn 6,75 gam hỗn hợp X thì thể tích khí O₂ (đktc) cần dùng là', N'15,12 lít.', N'14,28 lít.', N'13,44 lít.', N'16,80 lít.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (146, 5, N'Cho m gam amin đơn chức bậc một X tác dụng với dung dịch HCl dư thu được 12,95 gam muối. Toàn bộ lượng muối này tác dụng với dung dịch AgNO₃ dư thu được 28,7 gam kết tủa. Công thức của X có thể là', N'C₂H₅NH₂.', N'C₃H₇NH₂.', N'C₄H₉NH₂.', N'C₆H₅NH₂.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (147, 5, N'Đốt cháy hoàn toàn hỗn hợp X gồm hai amin no, đơn chức, mạch hở đồng đẳng kế tiếp, thu được N₂, H₂O và 11,2 lít CO₂ (đktc). Nếu cho toàn bộ hỗn hợp X trên tác dụng với dung dịch HCl dư thì khối lượng muối thu được là', N'28,65 gam.', N'32,25 gam.', N'35,95 gam.', N'30,45 gam.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (148, 5, N'Hỗn hợp X gồm hai amin đơn chức, là đồng đẳng kế tiếp. Đốt cháy hoàn toàn 0,1 mol hỗn hợp X cần vừa đủ 17,64 lít O₂ (đktc), sản phẩm cháy gồm CO₂, H₂O và N₂. Dẫn toàn bộ sản phẩm cháy qua bình đựng dung dịch Ca(OH)₂ dư, khối lượng dung dịch trong bình thay đổi như thế nào?', N'Giảm 25,65 gam.', N'Giảm 28,35 gam.', N'Tăng 17,55 gam.', N'Giảm 20,45 gam.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (149, 5, N'Hỗn hợp E gồm amin X (no, đơn chức, mạch hở) và hydrocarbon Y (no, mạch hở), trong đó số mol của X lớn hơn số mol của Y. Đốt cháy hoàn toàn 0,27 mol hỗn hợp E cần dùng vừa đủ 1,53 mol O₂, thu được H₂O, N₂ và 0,9 mol CO₂. Phần trăm khối lượng của Y trong hỗn hợp E là', N'24,05%.', N'19,42%.', N'31,16%.', N'28,57%.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (150, 5, N'Hỗn hợp X gồm aniline và hai hydrocarbon đồng đẳng kế tiếp. Đốt cháy hoàn toàn 22,9 gam hỗn hợp X cần vừa đủ 39,76 lít O₂ (đktc). Hấp thụ toàn bộ sản phẩm cháy vào bình đựng nước vôi trong dư, thu được 110 gam kết tủa và khối lượng dung dịch giảm 68,9 gam. Công thức phân tử của hai hydrocarbon là', N'CH₄ và C₂H₆.', N'C₂H₄ và C₃H₆.', N'C₂H₂ và C₃H₄.', N'C₃H₈ và C₄H₁₀.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (151, 6, N'Hợp chất nào sau đây được định nghĩa là amino acid?', N'Hợp chất hữu cơ chỉ chứa nhóm amino (-NH₂).', N'Hợp chất hữu cơ chỉ chứa nhóm carboxyl (-COOH).', N'Hợp chất hữu cơ tạp chức chứa đồng thời nhóm amino và nhóm carboxyl.', N'Hợp chất hữu cơ là ester của ammonia và acid carboxylic.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (152, 6, N'Ở trạng thái rắn và trong dung dịch, amino acid tồn tại chủ yếu ở dạng nào?', N'Phân tử trung hòa về điện.', N'Ion dương (cation).', N'Ion âm (anion).', N'Ion lưỡng cực (zwitterion).', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (153, 6, N'Amino acid nào sau đây có phân tử khối nhỏ nhất?', N'Alanine (Ala)', N'Glycine (Gly)', N'Valine (Val)', N'Lysine (Lys)', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (154, 6, N'Hợp chất H₂N–CH(CH₃)–COOH có tên thường là', N'Valine.', N'Glycine.', N'Alanine.', N'Lysine.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (155, 6, N'Tên gọi theo danh pháp thay thế (IUPAC) của glycine (H₂N-CH₂-COOH) là', N'acid aminocaproic.', N'acid 2-aminoethanoic.', N'acid aminopropanoic.', N'acid 2-aminobutanoic.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (156, 6, N'Phát biểu nào sau đây về tính chất vật lí của amino acid là không đúng?', N'Là chất rắn ở dạng tinh thể, không màu.', N'Dễ tan trong nước và có vị ngọt.', N'Có nhiệt độ nóng chảy tương đối cao.', N'Dễ bay hơi và có mùi đặc trưng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (157, 6, N'Tính chất hóa học đặc trưng nhất của amino acid là', N'tính oxi hóa mạnh.', N'tính khử mạnh.', N'tính lưỡng tính.', N'tính trơ về mặt hóa học.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (158, 6, N'Khi cho dung dịch amino acid tác dụng với dung dịch HCl, phản ứng xảy ra ở nhóm chức nào?', N'Nhóm carboxyl (-COOH).', N'Nhóm amino (-NH₂).', N'Gốc hydrocarbon (-R).', N'Cả hai nhóm -NH₂ và -COOH.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (159, 6, N'Phản ứng của amino acid với dung dịch NaOH chứng tỏ trong phân tử có chứa', N'nhóm amino (-NH₂).', N'nhóm carboxyl (-COOH).', N'gốc hydrocarbon no.', N'liên kết peptide.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (160, 6, N'Trong dung dịch có môi trường kiềm mạnh, amino acid tồn tại chủ yếu ở dạng', N'anion (ion âm).', N'cation (ion dương).', N'ion lưỡng cực.', N'phân tử trung hòa.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (161, 6, N'Phản ứng giữa các phân tử amino acid để tạo thành chuỗi dài hơn được gọi là', N'phản ứng ester hóa.', N'phản ứng thủy phân.', N'phản ứng trùng ngưng.', N'phản ứng cộng hợp.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (162, 6, N'Hợp chất nào trong các chất dưới đây là một α-amino acid?', N'H₂N-CH₂-CH₂-COOH', N'CH₃-CH(NH₂)-COOH', N'H₂N-CH₂-CH₂-CH₂-COOH', N'CH₃-CH₂-COONH₄', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (163, 6, N'Dung dịch của chất nào sau đây làm đổi màu quỳ tím sang màu xanh?', N'Glycine (1 nhóm -NH₂, 1 nhóm -COOH).', N'Alanine (1 nhóm -NH₂, 1 nhóm -COOH).', N'Lysine (2 nhóm -NH₂, 1 nhóm -COOH).', N'Acid glutamic (1 nhóm -NH₂, 2 nhóm -COOH).', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (164, 6, N'Khi cho alanine (CH₃-CH(NH₂)-COOH) tác dụng với ethanol (C₂H₅OH) trong môi trường HCl khan, sản phẩm hữu cơ chính thu được thuộc loại hợp chất nào?', N'Muối.', N'Amide.', N'Ketone.', N'Ester.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (165, 6, N'Điều kiện để các phân tử amino acid có thể tham gia phản ứng trùng ngưng tạo thành polyamide là', N'phân tử phải chứa từ hai nhóm amino trở lên.', N'phân tử phải chứa từ hai nhóm carboxyl trở lên.', N'phân tử có chứa liên kết đôi C=C trong gốc hydrocarbon.', N'phân tử có nhóm -NH₂ và -COOH cách xa nhau.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (166, 6, N'Phân tử khối của alanine (C₃H₇NO₂) là', N'75.', N'89.', N'103.', N'117.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (167, 6, N'Cho 7,5 gam glycine tác dụng hoàn toàn với dung dịch NaOH dư. Khối lượng muối thu được là', N'9,7 gam.', N'8,3 gam.', N'11,1 gam.', N'9,5 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (168, 6, N'Để tác dụng hết với 0,15 mol acid glutamic (H₂N-C₃H₅(COOH)₂) cần dùng V ml dung dịch NaOH 1M. Giá trị của V là', N'150.', N'75.', N'300.', N'100.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (169, 6, N'Thành phần phần trăm khối lượng của nitrogen trong phân tử glycine (C₂H₅NO₂) là', N'15,75%.', N'18,67%.', N'16,09%.', N'19,18%.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (170, 6, N'Cho 17,8 gam alanine tác dụng vừa đủ với dung dịch HCl. Khối lượng muối thu được là', N'21,45 gam.', N'25,10 gam.', N'24,20 gam.', N'22,75 gam.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (171, 6, N'Một α-amino acid X có công thức phân tử C₃H₇NO₂. Số đồng phân cấu tạo của X là', N'1.', N'2.', N'3.', N'4.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (172, 6, N'Một amino acid X (no, mạch hở, chứa 1 nhóm -NH₂ và 1 nhóm -COOH). Biết trong X, oxygen chiếm 35,955% về khối lượng. Công thức của X là', N'H₂N-CH₂-COOH.', N'CH₃-CH(NH₂)-COOH.', N'CH₃-CH₂-CH(NH₂)-COOH.', N'H₂N-[CH₂]₃-COOH.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (173, 6, N'Cho 0,1 mol amino acid X tác dụng vừa đủ với 200 ml dung dịch HCl 0,5M. Mặt khác, 14,7 gam X khi tác dụng với lượng dư dung dịch NaOH thì tạo ra 19,1 gam muối. Công thức của X là', N'H₂N-C₃H₅(COOH)₂.', N'(H₂N)₂C₅H₉COOH.', N'H₂N-C₂H₃(COOH)₂.', N'(H₂N)₂C₄H₇COOH.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (174, 6, N'Đốt cháy hoàn toàn 8,9 gam một amino acid X (chứa 1 nhóm -NH₂ và 1 nhóm -COOH) thu được 13,2 gam CO₂, 6,3 gam H₂O và 1,12 lít N₂ (đktc). Công thức cấu tạo của X là', N'H₂N-CH₂-COOH.', N'CH₃-CH(NH₂)-COOH.', N'H₂N-CH=CH-COOH.', N'H₂N-CH₂-CH₂-COOH.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (175, 6, N'Cho 15,1 gam hỗn hợp X gồm glycine và alanine tác dụng vừa đủ với 200 ml dung dịch KOH 1M. Khối lượng của alanine trong hỗn hợp ban đầu là', N'8,90 gam.', N'6,20 gam.', N'7,55 gam.', N'7,50 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (176, 6, N'Cho m gam hỗn hợp X gồm 2 amino acid đồng đẳng kế tiếp (đều chứa 1 nhóm -NH₂ và 1 nhóm -COOH) tác dụng với 200 ml dung dịch HCl 1M, thu được dung dịch Y. Để tác dụng hết với các chất trong Y cần 350 ml dung dịch NaOH 2M. Hai amino acid trong X là', N'Glycine và Alanine.', N'Alanine và Valine.', N'Valine và Leucine.', N'Alanine và acid α-aminobutanoic.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (177, 6, N'Dung dịch X chứa 0,02 mol H₂N-CH₂-COOH, 0,03 mol CH₃-CH(NH₂)-COOH và 0,04 mol H₂N-C₃H₅(COOH)₂. Cho X tác dụng với dung dịch HCl dư, sau đó cô cạn cẩn thận dung dịch sau phản ứng thu được m gam muối khan. Giá trị của m là', N'16,815 gam.', N'13,525 gam.', N'15,345 gam.', N'12,995 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (178, 6, N'Hỗn hợp X gồm hai amino acid no, có một nhóm amino và một nhóm carboxyl trong phân tử, là đồng đẳng kế tiếp. Đốt cháy hoàn toàn 22,1 gam hỗn hợp X, sản phẩm cháy thu được cho lội từ từ qua bình đựng dung dịch Ca(OH)₂ dư, thấy khối lượng dung dịch giảm 34,3 gam và có 2,24 lít khí (đktc) không bị hấp thụ. Công thức của hai amino acid là', N'Glycine và Alanine.', N'Alanine và acid α-aminobutanoic.', N'Acid α-aminobutanoic và Valine.', N'Valine và Leucine.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (179, 6, N'Hỗn hợp M gồm một amino acid X và một acid cacboxylic Y (đều no, đơn chức, mạch hở). Cho 0,4 mol hỗn hợp M tác dụng vừa đủ với dung dịch chứa 0,3 mol NaOH, thu được dung dịch Z. Cô cạn Z thu được m gam muối khan. Đốt cháy hoàn toàn lượng muối khan trên bằng O₂ dư, thu được 0,35 mol CO₂, H₂O, N₂ và 0,15 mol Na₂CO₃. Giá trị của m là', N'29,4 gam.', N'32,8 gam.', N'30,7 gam.', N'34,1 gam.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (180, 6, N'Cho m gam hỗn hợp X gồm Alanine và acid Glutamic tác dụng với dung dịch NaOH dư, thu được (m + 8,8) gam muối. Mặt khác, nếu cho m gam hỗn hợp X tác dụng với dung dịch HCl dư, thu được (m + 10,95) gam muối. Giá trị của m là', N'42,4.', N'36,5.', N'38,9.', N'40,2.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (181, 7, N'Liên kết của nhóm -CO- với nhóm -NH- giữa hai đơn vị α-amino acid được gọi là', N'liên kết amide.', N'liên kết hydro.', N'liên kết peptide.', N'liên kết ion.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (182, 7, N'Phân tử peptide được cấu thành từ các đơn vị nào?', N'β-amino acid.', N'α-amino acid.', N'Amin và acid carboxylic.', N'Alcohol và acid carboxylic.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (183, 7, N'Theo quy ước, khi viết công thức của một peptide, đầu N (amino tự do) được viết ở bên nào?', N'Ở giữa phân tử.', N'Ở bên phải.', N'Tùy thuộc vào loại peptide.', N'Ở bên trái.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (184, 7, N'Phản ứng màu biuret dùng để nhận biết peptide có từ bao nhiêu liên kết peptide trở lên?', N'1 liên kết.', N'2 liên kết.', N'3 liên kết.', N'4 liên kết.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (185, 7, N'Protein là những polypeptide cao phân tử có khối lượng phân tử', N'từ vài trăm đến vài nghìn.', N'từ vài chục đến vài trăm.', N'từ vài nghìn đến vài chục nghìn.', N'từ vài chục nghìn đến vài triệu.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (186, 7, N'Khi thủy phân hoàn toàn protein đơn giản trong môi trường acid hoặc kiềm, sản phẩm cuối cùng thu được là', N'hỗn hợp các α-amino acid.', N'hỗn hợp các chuỗi polypeptide ngắn hơn.', N'hỗn hợp các amin và acid carboxylic.', N'một loại amino acid duy nhất.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (187, 7, N'Hiện tượng protein đông tụ lại khi đun nóng hoặc tác dụng với acid được gọi là', N'sự biến tính.', N'sự thủy phân.', N'sự trùng ngưng.', N'sự thăng hoa.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (188, 7, N'Thuốc thử nào sau đây được dùng để phân biệt dung dịch Gly-Ala và dung dịch Gly-Ala-Gly?', N'Dung dịch NaOH.', N'Dung dịch HCl.', N'Cu(OH)₂ trong môi trường kiềm.', N'Dung dịch Br₂.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (189, 7, N'Hiện tượng nào xảy ra khi cho dung dịch lòng trắng trứng vào Cu(OH)₂?', N'Xuất hiện kết tủa màu đỏ gạch.', N'Xuất hiện dung dịch màu xanh lam.', N'Xuất hiện dung dịch màu tím.', N'Không có hiện tượng gì xảy ra.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (190, 7, N'Hầu hết các enzyme có bản chất là', N'lipid.', N'protein.', N'carbohydrate.', N'acid nucleic.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (191, 7, N'Trong các chất sau, chất nào có phản ứng màu biuret?', N'Alanine.', N'Dipeptide Gly-Ala.', N'Tripeptide Ala-Gly-Val.', N'Ethylamine.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (192, 7, N'Lòng trắng trứng khi đun sôi bị đông tụ lại là một ví dụ về', N'phản ứng thủy phân protein.', N'sự đông tụ và biến tính protein.', N'phản ứng trùng hợp protein.', N'sự hòa tan của protein trong nước.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (193, 7, N'Một trong những vai trò quan trọng của enzyme trong cơ thể sống là', N'cung cấp năng lượng chính cho tế bào.', N'xây dựng nên cấu trúc của màng tế bào.', N'làm chất xúc tác cho các quá trình sinh hóa.', N'vận chuyển oxygen trong máu.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (194, 7, N'Khi thủy phân không hoàn toàn một peptide, sản phẩm thu được có thể là', N'chỉ các α-amino acid tự do.', N'các chuỗi peptide ngắn hơn ban đầu.', N'chỉ các amin và acid tương ứng.', N'chỉ nước và khí carbon dioxide.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (195, 7, N'Sợi tơ tằm, tóc, móng tay có thành phần chính là protein dạng sợi. Đặc điểm nào sau đây là của protein dạng sợi?', N'Tan tốt trong nước tạo dung dịch keo.', N'Chủ yếu tồn tại ở dạng hình cầu.', N'Không tan trong nước, có cấu trúc bền.', N'Dễ bị biến tính bởi nhiệt độ thấp.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (196, 7, N'Số liên kết peptide có trong phân tử tetrapeptide mạch hở là', N'4.', N'3.', N'2.', N'5.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (197, 7, N'Thủy phân hoàn toàn 1 mol pentapeptide Gly-Ala-Val-Ala-Gly thì thu được', N'2 mol Gly, 2 mol Ala, 1 mol Val.', N'1 mol Gly, 2 mol Ala, 2 mol Val.', N'3 mol Gly, 1 mol Ala, 1 mol Val.', N'2 mol Gly, 1 mol Ala, 2 mol Val.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (198, 7, N'Khi tạo thành tripeptide từ 3 phân tử amino acid, có bao nhiêu phân tử nước được giải phóng?', N'1.', N'3.', N'2.', N'4.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (199, 7, N'Từ hai amino acid là Alanine và Valine có thể tạo ra tối đa bao nhiêu dipeptide khác nhau?', N'1.', N'2.', N'3.', N'4.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (200, 7, N'Phân tử khối của dipeptide Gly-Ala (Gly = 75, Ala = 89) là', N'164.', N'146.', N'162.', N'128.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (201, 7, N'Đun nóng 0,1 mol tripeptide Gly-Gly-Gly trong dung dịch NaOH dư. Số mol NaOH đã tham gia phản ứng là', N'0,2 mol.', N'0,4 mol.', N'0,3 mol.', N'0,1 mol.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (202, 7, N'Thủy phân hoàn toàn 1 mol pentapeptide X, thu được 3 mol Gly, 1 mol Ala và 1 mol Val. Khi thủy phân không hoàn toàn X thì thu được dipeptide Ala-Gly và tripeptide Gly-Val-Gly. Trình tự các amino acid trong X là', N'Ala-Gly-Gly-Val-Gly.', N'Gly-Val-Gly-Ala-Gly.', N'Gly-Ala-Gly-Val-Gly.', N'Ala-Gly-Val-Gly-Gly.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (203, 7, N'Thủy phân hoàn toàn 29,2 gam một dipeptide X tạo bởi alanin trong môi trường acid, thu được m gam alanin. Giá trị của m là', N'35,6 gam.', N'17,8 gam.', N'44,5 gam.', N'32,4 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (204, 7, N'Hỗn hợp X gồm Gly-Ala và Ala-Gly. Để thủy phân hoàn toàn 0,1 mol hỗn hợp X cần dùng 200 ml dung dịch NaOH 1M. Khối lượng của hỗn hợp X là', N'14,6 gam.', N'16,4 gam.', N'12,8 gam.', N'18,2 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (205, 7, N'Thủy phân 60 gam hỗn hợp gồm hai dipeptide Gly-Ala và Ala-Ala bằng dung dịch NaOH vừa đủ, cô cạn dung dịch sau phản ứng thu được 79,8 gam hỗn hợp muối. Tỉ lệ số mol của Gly-Ala và Ala-Ala trong hỗn hợp ban đầu là', N'1 : 2.', N'2 : 1.', N'1 : 1.', N'2 : 3.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (206, 7, N'Đun nóng 21,9 gam một tripeptide mạch hở X với dung dịch KOH dư. Sau phản ứng thu được 39,3 gam muối. Biết X được tạo từ một amino acid no, mạch hở, chứa 1 nhóm -NH₂ và 1 nhóm -COOH. Tên của amino acid đó là', N'Glycine.', N'Alanine.', N'Valine.', N'Leucine.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (207, 7, N'Một tetrapeptide X khi thủy phân hoàn toàn chỉ thu được alanin. Biết rằng 0,1 mol X phản ứng vừa đủ với dung dịch chứa 0,4 mol HCl. Phân tử khối của X là', N'302.', N'373.', N'284.', N'316.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (208, 7, N'Hỗn hợp X gồm tripeptide A và tetrapeptide B đều được tạo bởi cùng một amino acid no, mạch hở, có 1 nhóm -NH₂ và 1 nhóm -COOH. Đốt cháy hoàn toàn 0,1 mol hỗn hợp X, sau đó cho toàn bộ sản phẩm cháy (CO₂, H₂O, N₂) vào bình đựng dung dịch Ba(OH)₂ dư, thu được 177,3 gam kết tủa và khối lượng dung dịch giảm 123,3 gam. Phần trăm khối lượng của A trong hỗn hợp X là', N'36,45%.', N'44,38%.', N'55,62%.', N'63,55%.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (209, 7, N'Peptide X và peptide Y có tổng số liên kết peptide bằng 8. Thủy phân hoàn toàn X cũng như Y đều thu được Gly và Val. Đốt cháy hoàn toàn hỗn hợp E chứa X và Y có tỉ lệ mol tương ứng 1 : 2 cần dùng 26,04 lít O₂ (đktc). Sản phẩm cháy gồm CO₂, H₂O và N₂. Dẫn toàn bộ sản phẩm cháy qua dung dịch KOH đặc, dư thấy khối lượng bình tăng 58,29 gam. Phần trăm khối lượng của X trong hỗn hợp E là', N'28,15%.', N'19,84%.', N'24,36%.', N'18,91%.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (210, 7, N'X là một hexapeptide Ala-Gly-Ala-Val-Gly-Val. Y là một tetrapeptide Gly-Ala-Gly-Glu. Thủy phân hoàn toàn m gam hỗn hợp gồm X và Y trong môi trường acid thu được 4 loại amino acid, trong đó có 30 gam glyxin và 28,48 gam alanin. Giá trị của m là', N'77,6 gam.', N'83,2 gam.', N'73,4 gam.', N'87,4 gam.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (211, 8, N'Phát biểu nào sau đây định nghĩa chính xác nhất về polymer?', N'Polymer là hợp chất có phân tử khối lớn do nhiều phân tử monomer tạo nên.', N'Polymer là hợp chất do nhiều đơn vị mắt xích giống nhau liên kết với nhau.', N'Polymer là hợp chất có phân tử khối rất lớn do nhiều mắt xích liên kết với nhau.', N'Polymer là những phân tử rất lớn được tạo thành từ phản ứng trùng hợp.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (212, 8, N'Monomer là gì?', N'Là những phân tử nhỏ, tham gia phản ứng tạo nên các chuỗi polymer.', N'Là một đoạn mạch được lặp đi lặp lại nhiều lần trong phân tử polymer.', N'Là hợp chất có hai nhóm chức hoặc liên kết bội tham gia phản ứng.', N'Là phân tử được giải phóng ra trong quá trình thực hiện phản ứng trùng ngưng.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (213, 8, N'Điều kiện cần để một monomer có thể tham gia phản ứng trùng hợp là', N'phân tử phải có chứa nhóm chức có khả năng phản ứng.', N'phân tử phải có liên kết bội (C=C, C≡C) hoặc là vòng kém bền.', N'phân tử phải có khối lượng phân tử nhỏ và dễ bay hơi.', N'phân tử phải có hai nhóm chức khác nhau ở hai đầu mạch.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (214, 8, N'Monomer tham gia phản ứng trùng ngưng phải thỏa mãn điều kiện nào sau đây?', N'Phân tử có chứa liên kết đôi C=C trong gốc hydrocarbon.', N'Phân tử là một vòng kém bền có khả năng mở vòng.', N'Phân tử có khối lượng phân tử lớn và cấu trúc phức tạp.', N'Phân tử có ít nhất hai nhóm chức có khả năng phản ứng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (215, 8, N'Polymer nào sau đây thuộc loại polymer thiên nhiên?', N'Tơ nilon-6,6.', N'Polystyrene.', N'Polyethylene.', N'Tinh bột.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (216, 8, N'Dựa vào nguồn gốc, tơ capron được phân loại là', N'tơ thiên nhiên.', N'tơ tổng hợp.', N'tơ bán tổng hợp.', N'tơ nhân tạo.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (217, 8, N'Chất nhiệt dẻo là loại polymer', N'bị phân hủy ngay khi đun nóng ở nhiệt độ cao.', N'không nóng chảy mà hóa rắn vĩnh viễn khi đun nóng.', N'sẽ mềm ra khi đun nóng và rắn lại khi làm nguội.', N'chỉ mềm ra một lần duy nhất khi gia nhiệt lần đầu.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (218, 8, N'Vật liệu nào sau đây là chất nhiệt rắn?', N'Polyethylene (PE).', N'Poly(vinyl chloride) (PVC).', N'Poly(phenol formaldehyde) (PPF).', N'Polypropylene (PP).', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (219, 8, N'Phản ứng thủy phân cellulose trong môi trường acid tạo ra glucose thuộc loại phản ứng nào của polymer?', N'Phản ứng giữ nguyên mạch polymer.', N'Phản ứng tăng mạch polymer.', N'Phản ứng khâu mạch polymer.', N'Phản ứng cắt mạch polymer.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (220, 8, N'Khi cho poly(vinyl acetate) tác dụng với dung dịch NaOH (đun nóng), thu được poly(vinyl alcohol) và sodium acetate. Đây là phản ứng', N'giữ nguyên mạch polymer.', N'cắt mạch polymer.', N'depolymer hóa.', N'trùng ngưng.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (221, 8, N'Phản ứng lưu hóa cao su bằng cách cho tác dụng với sulfur là một ví dụ điển hình của', N'phản ứng cắt mạch, làm giảm độ bền của cao su.', N'phản ứng giữ nguyên mạch, không thay đổi tính chất.', N'phản ứng tăng mạch, tạo ra các cầu nối disulfide.', N'phản ứng depolymer hóa, thu lại monomer isoprene.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (222, 8, N'Loại polymer nào sau đây có cấu trúc mạng không gian?', N'Amylopectin.', N'Cao su đã lưu hóa.', N'Polyethylene.', N'Amylose.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (223, 8, N'Trong phân tử poly(vinyl chloride), mắt xích cơ bản là', N'-CH=CHCl-', N'-CH₂-CHCl-', N'CH₂=CHCl', N'-CH₂-CH₂-', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (224, 8, N'Trong phản ứng trùng ngưng, ngoài sản phẩm chính là polymer còn có', N'sản phẩm phụ là các polymer có mạch ngắn hơn.', N'các monomer dư không tham gia phản ứng.', N'các phân tử nhỏ được giải phóng (như H₂O, HCl…).', N'sản phẩm phụ là các chất có liên kết bội.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (225, 8, N'Phát biểu nào sau đây về tính chất vật lí chung của polymer là đúng?', N'Hầu hết polymer đều dễ bay hơi và có mùi đặc trưng.', N'Polymer có nhiệt độ nóng chảy xác định và rất cao.', N'Đa số polymer là chất rắn, không bay hơi, không có nhiệt độ nóng chảy xác định.', N'Hầu hết các polymer đều dễ tan trong nước tạo dung dịch keo.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (226, 8, N'Monomer nào sau đây được dùng để điều chế poly(vinyl chloride)?', N'CH₂=CH-Cl.', N'CH₂=CH₂.', N'CH₂=CH-CH₃.', N'CH₃-COO-CH=CH₂.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (227, 8, N'Khi tiến hành trùng hợp styrene, sản phẩm thu được có công thức cấu tạo là', N'(-CH₂-CH₂-)ₙ.', N'(-CF₂-CF₂-)ₙ.', N'(-CH(C₆H₅)-CH₂-)ₙ.', N'(-CH(CH₃)-CH₂-)ₙ.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (228, 8, N'Chất nào sau đây không có khả năng tham gia phản ứng trùng hợp?', N'Ethylene.', N'Toluene.', N'Propylene.', N'Isoprene.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (229, 8, N'Tên gọi của polymer có công thức (-CH₂-CH(CH₃)-)ₙ là', N'polyethylene.', N'poly(vinyl chloride).', N'polypropylene.', N'polystryrene.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (230, 8, N'Dãy các chất nào sau đây đều có thể tham gia phản ứng trùng hợp?', N'Ethylene, vinyl chloride, isoprene.', N'Methane, ethylene, vinyl chloride.', N'Styrene, benzene, isoprene.', N'Ethylene, acetic acid, vinyl acetate.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (231, 8, N'Phản ứng trùng ngưng sẽ xảy ra giữa cặp chất nào sau đây?', N'H₂N-[CH₂]₆-NH₂ và HOOC-[CH₂]₄-COOH.', N'CH₂=CH₂ và CH₂=CH-C₆H₅.', N'CH₃COOH và C₂H₅OH.', N'CH₂=CH-COOH và CH₂=CH-CN.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (232, 8, N'Polymer X được điều chế bằng phản ứng trùng hợp monomer Y. Biết X có công thức (-CH₂-C(CH₃)=CH-CH₂-)ₙ. Tên gọi của Y là', N'buta-1,3-diene.', N'isoprene.', N'styrene.', N'chloroprene.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (233, 8, N'Cho các polymer sau: tơ tằm, nilon-6,6, poly(vinyl chloride), cao su buna, cellulose. Số polymer tổng hợp là', N'2.', N'4.', N'5.', N'3.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (234, 8, N'Phát biểu nào sau đây là không đúng?', N'Tơ nilon-6,6 được điều chế bằng phản ứng trùng ngưng.', N'Phản ứng trùng hợp là quá trình cộng liên tiếp nhiều monomer.', N'Phản ứng trùng ngưng luôn tạo ra sản phẩm phụ là nước.', N'Polymer có thể được điều chế từ phản ứng trùng hợp hoặc trùng ngưng.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (235, 8, N'Đốt cháy hoàn toàn một loại polymer X, sản phẩm thu được chỉ có CO₂ và H₂O với tỉ lệ mol n(CO₂) : n(H₂O) = 1 : 1. Polymer X là', N'poly(vinyl chloride).', N'polyethylene.', N'polypropylene.', N'polystryrene.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (236, 8, N'Nylon-6,6 là một loại', N'tơ acetate được tạo ra từ phản ứng este hóa.', N'polyester được tạo ra từ phản ứng trùng ngưng.', N'tơ visco được sản xuất từ việc tái sinh cellulose.', N'polyamide được tạo ra từ phản ứng trùng ngưng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (237, 8, N'Cho sơ đồ chuyển hóa: CH≡CH → X → Y → Cao su buna. X và Y lần lượt là:', N'CH₃CHO, C₂H₅OH.', N'C₂H₄, C₂H₅OH.', N'C₄H₄ (vinylacetylene), C₄H₆ (buta-1,3-diene).', N'C₆H₆ (benzene), C₆H₅CH=CH₂ (styrene).', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (238, 8, N'Một đoạn polymer polystyrene (PS) có phân tử khối trung bình là 312000 đvC. Hệ số polymer hóa trung bình của đoạn polymer này là', N'2500.', N'4000.', N'3000.', N'5000.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (239, 8, N'So sánh quá trình trùng hợp ethylene để tạo PE và trùng ngưng hexamethylenediamine với adipic acid để tạo nilon-6,6. Nhận định nào sau đây là đúng?', N'Cả hai quá trình đều giải phóng phân tử nhỏ như nước.', N'Khối lượng polymer tạo thành luôn bằng khối lượng monomer tham gia ở cả hai quá trình.', N'Khối lượng PE tạo thành bằng khối lượng ethylene; khối lượng nilon-6,6 lớn hơn khối lượng monomer.', N'Khối lượng PE tạo thành bằng khối lượng ethylene; khối lượng nilon-6,6 nhỏ hơn tổng khối lượng monomer.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (240, 8, N'Tiến hành trùng hợp 25 kg vinyl chloride, biết hiệu suất của phản ứng là 80%. Khối lượng poly(vinyl chloride) (PVC) thu được là', N'25 kg.', N'20 kg.', N'16 kg.', N'31,25 kg.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (241, 9, N'Chất dẻo là vật liệu polymer có đặc tính cơ bản nào sau đây?', N'Có tính dẻo, tức là bị biến dạng khi chịu tác dụng của ngoại lực và giữ nguyên dạng đó.', N'Có tính đàn hồi, tức là quay về hình dạng ban đầu khi thôi tác dụng của ngoại lực.', N'Có cấu trúc dạng sợi dài, mảnh và có độ bền cao dọc theo trục sợi.', N'Có khả năng kết dính các bề mặt vật liệu khác nhau khi ở trạng thái lỏng.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (242, 9, N'Tác hại chính của việc lạm dụng chất dẻo đối với môi trường là gì?', N'Gây hiệu ứng nhà kính do giải phóng khí CO₂ khi sản xuất.', N'Làm cạn kiệt nguồn tài nguyên hóa thạch không thể tái tạo.', N'Tiêu thụ một lượng lớn năng lượng trong quá trình sản xuất.', N'Rất khó phân hủy, tồn tại lâu dài trong môi trường và tạo ra vi nhựa.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (243, 9, N'Vật liệu composite được định nghĩa là', N'vật liệu polymer được gia cố thêm chất độn để tăng khối lượng.', N'vật liệu được tổ hợp từ ít nhất hai thành phần vật liệu khác nhau.', N'vật liệu polymer có thể tái chế nhiều lần mà không làm thay đổi tính chất.', N'vật liệu polymer có nguồn gốc từ thiên nhiên như cellulose hoặc protein.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (244, 9, N'Trong vật liệu composite, thành phần “vật liệu cốt” (như sợi carbon, sợi thủy tinh) có vai trò chính là', N'tăng cường độ cứng, độ bền cơ học và khả năng chịu lực cho vật liệu.', N'tạo sự kết dính, đảm bảo các thành phần khác liên kết thành một khối.', N'làm giảm khối lượng riêng, giúp cho vật liệu trở nên nhẹ hơn.', N'tăng khả năng chống ăn mòn hóa học và chịu nhiệt độ cao.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (245, 9, N'Đặc điểm nào sau đây mô tả đúng nhất về tơ?', N'Vật liệu polymer có tính đàn hồi cao.', N'Vật liệu polymer có tính dẻo đặc trưng.', N'Vật liệu polymer có cấu trúc dạng sợi dài và mảnh.', N'Vật liệu polymer có cấu trúc mạng không gian.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (246, 9, N'Tơ tằm và len đều thuộc loại tơ nào sau đây?', N'Tơ tổng hợp.', N'Tơ bán tổng hợp.', N'Tơ nhân tạo.', N'Tơ thiên nhiên.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (247, 9, N'Tơ visco và tơ cellulose acetate được sản xuất bằng cách chế biến hóa học từ cellulose. Chúng được phân loại là', N'tơ tổng hợp.', N'tơ bán tổng hợp (tơ nhân tạo).', N'tơ thiên nhiên.', N'tơ polyamide.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (248, 9, N'Cao su là vật liệu polymer có tính chất đặc trưng nổi bật là', N'tính dẻo.', N'tính dẫn điện tốt.', N'tính đàn hồi.', N'tính dai và bền.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (249, 9, N'Monomer chính cấu tạo nên cao su thiên nhiên là', N'buta-1,3-diene.', N'styrene.', N'chloroprene.', N'isoprene.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (250, 9, N'Cao su buna-S là sản phẩm của phản ứng', N'đồng trùng hợp buta-1,3-diene và styrene.', N'trùng hợp buta-1,3-diene với xúc tác Na.', N'đồng trùng hợp buta-1,3-diene và acrylonitrile.', N'lưu hóa cao su thiên nhiên bằng hợp chất của sulfur.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (251, 9, N'Vật dụng nào sau đây chủ yếu được sản xuất từ poly(vinyl chloride) (PVC)?', N'Chai đựng nước, túi nilon.', N'Ống dẫn nước, áo mưa.', N'Hộp xốp đựng thực phẩm.', N'Kính ô tô, kính máy bay.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (252, 9, N'Vật liệu composite nền polymer cốt sợi carbon thường được ứng dụng để', N'sản xuất các loại bao bì thực phẩm dùng một lần.', N'làm vật liệu cách nhiệt trong xây dựng dân dụng.', N'chế tạo các chi tiết đòi hỏi độ bền cao và nhẹ như vỏ máy bay.', N'sản xuất các dụng cụ nhà bếp chịu được nhiệt độ cao.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (253, 9, N'Vì sao quần áo làm từ tơ nilon, len, tơ tằm không nên giặt bằng xà phòng có độ kiềm cao?', N'Vì các loại tơ này dễ bị co rút khi gặp môi trường kiềm.', N'Vì môi trường kiềm làm giảm độ bền màu của các loại tơ này.', N'Vì các loại tơ này dễ bị bám cặn xà phòng, gây cứng vải.', N'Vì các liên kết peptide hoặc amide trong tơ dễ bị thủy phân.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (254, 9, N'Keo dán epoxy là một loại keo dán hai thành phần, khi sử dụng cần phải', N'trộn đều hai thành phần với nhau ngay trước khi dùng.', N'pha loãng với nước để đạt được độ dính mong muốn.', N'đun nóng ở nhiệt độ cao để keo chuyển sang trạng thái lỏng.', N'làm lạnh để keo đông cứng lại trước khi dán.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (255, 9, N'Thành phần chính của sợi bông (dùng để dệt vải) là', N'protein.', N'polyisoprene.', N'cellulose.', N'tinh bột.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (256, 9, N'Polyme nào sau đây là chất dẻo?', N'Tơ tằm.', N'Polyethylene.', N'Cao su buna.', N'Tơ nilon-6,6.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (257, 9, N'Polyme nào sau đây thuộc loại tơ tổng hợp?', N'Bông.', N'Tơ visco.', N'Len.', N'Tơ nitron (olon).', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (258, 9, N'Để sản xuất nhựa phenol-formaldehyde (nhựa bakelite), người ta tiến hành phản ứng trùng ngưng giữa', N'phenol và etylen glicol.', N'formaldehyde và anilin.', N'phenol và formaldehyde.', N'phenol và acid acetic.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (259, 9, N'Tơ visco được sản xuất từ polymer thiên nhiên nào sau đây?', N'Cellulose.', N'Protein.', N'Polyisoprene.', N'Tinh bột.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (260, 9, N'Polyisoprene là thành phần chính của cao su thiên nhiên, được ứng dụng rộng rãi để', N'sản xuất ống dẫn nước và vỏ dây điện.', N'sản xuất lốp xe, găng tay y tế, nệm.', N'sản xuất tơ sợi để may quần áo.', N'làm vật liệu cách âm, cách nhiệt.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (261, 9, N'Vật liệu nào sau đây được điều chế bằng phản ứng đồng trùng hợp?', N'Polypropylene.', N'Tơ capron.', N'Tinh bột.', N'Cao su buna-S.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (262, 9, N'Dãy gồm các vật liệu được chế tạo từ polymer tổng hợp là:', N'Nilon-6,6, poly(vinyl chloride), tơ nitron.', N'Tơ tằm, cao su buna, polyetylen.', N'Bông, tơ visco, tơ capron.', N'Len, tơ tằm, keo dán epoxy.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (263, 9, N'Phát biểu nào sau đây là không đúng?', N'Tơ nilon-6,6 thuộc loại tơ polyamide.', N'Tơ tằm và tơ visco đều thuộc loại tơ thiên nhiên.', N'Cao su thiên nhiên là polymer của isoprene.', N'Chất dẻo là vật liệu polymer có tính dẻo.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (264, 9, N'Polyme nào sau đây được điều chế bằng phản ứng trùng ngưng?', N'Polystyrene.', N'Polyetylen.', N'Keo poly(urea-formaldehyde).', N'Poly(vinyl chloride).', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (265, 9, N'Cao su buna-N được dùng làm các chi tiết kĩ thuật như gioăng, ống dẫn nhiên liệu vì', N'có tính chống dầu mỡ và chống mài mòn tốt.', N'có tính đàn hồi vượt trội so với cao su thiên nhiên.', N'có giá thành rẻ và quy trình sản xuất đơn giản.', N'có khả năng chịu được nhiệt độ rất cao.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (266, 9, N'Vải làm từ tơ nilon-6,6 có đặc tính', N'mềm mại, thoáng mát và thấm mồ hôi tốt như cotton.', N'rất bền, dai, mềm mượt nhưng kém bền với nhiệt và acid.', N'cứng, giòn, dễ gãy và không có khả năng đàn hồi.', N'không tan trong nước nhưng tan tốt trong các dung môi hữu cơ.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (267, 9, N'So sánh cao su thiên nhiên và cao su đã lưu hóa, nhận định nào đúng?', N'Cả hai đều có cấu trúc mạch thẳng, không phân nhánh.', N'Cao su lưu hóa có tính đàn hồi và độ bền cao hơn.', N'Cao su thiên nhiên tan tốt trong nước và các alcol.', N'Quá trình lưu hóa làm giảm khối lượng phân tử polymer.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (268, 9, N'Trong công nghiệp, polystyrene (PS) được sản xuất từ benzene theo sơ đồ với hiệu suất của mỗi giai đoạn (1) và (2) lần lượt là 60% và 55%.', N'33,0 kg.', N'73,3 kg.', N'44,0 kg.', N'133,3 kg.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (269, 9, N'Để phân biệt hai mẫu tơ là tơ tằm và tơ bông (cellulose), phương pháp đơn giản và hiệu quả nhất là', N'thử độ tan của hai mẫu tơ trong dung dịch H₂SO₄ đặc.', N'cho hai mẫu tơ tác dụng với dung dịch iot.', N'so sánh độ mềm mại của hai mẫu tơ bằng tay.', N'đốt hai mẫu tơ và nhận biết qua mùi của sản phẩm cháy.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (270, 9, N'Tiến hành lưu hóa 680 gam isoprene (giả sử là cao su thiên nhiên) thu được một loại cao su lưu hóa trong đó lưu huỳnh chiếm 2% về khối lượng. Khối lượng lưu huỳnh đã tham gia phản ứng là', N'13,88 gam.', N'14,00 gam.', N'13,60 gam.', N'2,00 gam.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (271, 10, N'(NB) Trong pin điện hoá, quá trình oxi hoá một chất là quá trình chất đó', N'nhận thêm electron.', N'nhường đi electron.', N'nhận thêm proton.', N'nhường đi neutron.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (272, 10, N'(NB) Giá trị thế điện cực chuẩn của một cặp oxi hoá – khử đặc trưng cho', N'khả năng tan trong nước của cặp đó.', N'khối lượng riêng của các chất trong cặp.', N'khả năng nhường hoặc nhận electron của cặp.', N'nhiệt độ nóng chảy của kim loại trong cặp.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (273, 10, N'(NB) Cặp oxi hoá – khử của kim loại sắt (iron) được biểu diễn đúng là', N'Fe / Fe²⁺.', N'Fe³⁺ / Fe.', N'Fe²⁺ / Fe.', N'Fe / Fe³⁺.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (274, 10, N'(NB) Theo quy tắc alpha (α), phản ứng oxi hoá – khử xảy ra tự phát theo chiều', N'chất oxi hoá yếu tác dụng với chất khử yếu tạo sản phẩm mạnh hơn.', N'hai chất khử tác dụng với nhau để tạo ra hai chất oxi hoá mới.', N'chất oxi hoá mạnh tác dụng với chất khử mạnh tạo sản phẩm yếu hơn.', N'hai chất oxi hoá tác dụng với nhau để tạo ra hai chất khử mới.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (275, 10, N'(TH) Cho E⁰(Zn²⁺/Zn) = -0,76 V; E⁰(Fe²⁺/Fe) = -0,44 V. So sánh đúng:', N'Ion Fe²⁺ có tính oxi hoá mạnh hơn ion Zn²⁺.', N'Kim loại Fe có tính khử mạnh hơn kim loại Zn.', N'Ion Zn²⁺ có tính oxi hoá mạnh hơn ion Fe²⁺.', N'Tính khử của Fe và Zn là tương đương nhau.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (276, 10, N'(NB) Trong cặp oxi hoá – khử, dạng oxi hoá và dạng khử của cùng một nguyên tố kim loại', N'có số oxi hoá bằng nhau.', N'có số electron ở lớp ngoài cùng bằng nhau.', N'có số oxi hoá khác nhau.', N'luôn tồn tại ở cùng một trạng thái vật lí.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (277, 10, N'(NB) Dãy điện hóa của kim loại sắp xếp các cặp oxi hoá – khử theo chiều', N'giảm dần thế điện cực chuẩn.', N'tăng dần thế điện cực chuẩn.', N'giảm dần tính oxi hoá của ion kim loại.', N'tăng dần tính khử của kim loại.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (278, 10, N'(NB) Điều kiện chuẩn để xác định thế điện cực chuẩn là', N'nồng độ ion kim loại 1 M, nhiệt độ 25 °C.', N'nồng độ ion kim loại 0,1 M, nhiệt độ 25 °C.', N'nồng độ ion kim loại 1 M, nhiệt độ 0 °C.', N'nồng độ ion kim loại 0,1 M, nhiệt độ 100 °C.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (279, 10, N'(TH) Kim loại M có E⁰(Mⁿ⁺/M) càng âm thì', N'kim loại M có tính khử càng yếu.', N'ion Mⁿ⁺ có tính oxi hoá càng mạnh.', N'kim loại M có tính khử càng mạnh.', N'ion Mⁿ⁺ có tính oxi hoá càng yếu và M khử yếu.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (280, 10, N'(NB) Chất khử là chất', N'cho electron, bị oxi hoá.', N'nhận electron, bị khử.', N'cho electron, bị khử.', N'nhận electron, bị oxi hoá.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (281, 10, N'(TH) Trong phản ứng: Zn + Cu²⁺ → Zn²⁺ + Cu, ion Cu²⁺ là', N'chất khử.', N'chất bị oxi hoá.', N'môi trường phản ứng.', N'chất oxi hoá.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (282, 10, N'(TH) Dựa vào dãy thế điện cực chuẩn, kim loại có tính khử mạnh nhất là', N'Mg.', N'Fe.', N'Cu.', N'Ag.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (283, 10, N'(NB) Thế điện cực chuẩn của cặp 2H⁺/H₂ được quy ước là', N'-1,00 V.', N'+1,00 V.', N'0,00 V.', N'+0,50 V.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (284, 10, N'(TH) Dựa vào dãy thế điện cực chuẩn, ion có tính oxi hoá mạnh nhất là', N'Na⁺.', N'Al³⁺.', N'Fe²⁺.', N'Ag⁺.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (285, 10, N'(TH) Phản ứng không xảy ra ở điều kiện thường là', N'Cu + 2AgNO₃ → Cu(NO₃)₂ + 2Ag.', N'Fe + CuSO₄ → FeSO₄ + Cu.', N'Zn + FeSO₄ → ZnSO₄ + Fe.', N'Cu + FeSO₄ → không phản ứng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (286, 10, N'(VD) Kim loại đẩy được Fe khỏi dung dịch FeCl₂ là', N'Al.', N'Cu.', N'Ag.', N'Cả Cu và Ag.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (287, 10, N'(VD) Nhúng kẽm vào dung dịch AgNO₃ và CuSO₄, khối lượng dung dịch', N'tăng lên so với ban đầu.', N'giảm đi so với ban đầu.', N'không thay đổi so với ban đầu.', N'có thể tăng hoặc giảm tùy nhiệt độ.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (288, 10, N'(VD) Với E⁰(Fe³⁺/Fe²⁺) = +0,77 V; E⁰(Ag⁺/Ag) = +0,80 V, phản ứng xảy ra:', N'Fe²⁺ + Ag⁺ → Fe³⁺ + Ag.', N'Fe³⁺ + Ag → Fe²⁺ + Ag⁺.', N'Fe²⁺ + Ag → Fe³⁺ + Ag⁺.', N'Fe³⁺ + Ag⁺ → Fe²⁺ + Ag.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (289, 10, N'(VD) Sắp xếp theo chiều tăng dần tính khử: Fe, Cu, Al, Ag', N'Ag < Cu < Fe < Al.', N'Al < Fe < Cu < Ag.', N'Ag < Fe < Cu < Al.', N'Cu < Ag < Fe < Al.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (290, 10, N'(VD) Fe + AgNO₃ + Cu(NO₃)₂ → m = ? nếu thu được 3,44g chất rắn', N'2,80.', N'1,68.', N'2,24.', N'3,36.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (291, 10, N'(VDC) Nhúng kẽm vào dung dịch Fe(NO₃)₃, Cu(NO₃)₂, AgNO₃, thứ tự ion bị khử:', N'Ag⁺, Fe³⁺, Cu²⁺, Fe²⁺.', N'Fe³⁺, Ag⁺, Cu²⁺, Fe²⁺.', N'Ag⁺, Cu²⁺, Fe³⁺, Fe²⁺.', N'Fe³⁺, Cu²⁺, Ag⁺, Fe²⁺.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (292, 10, N'(NB) Hiện tượng khi cho Cu + AgNO₃:', N'có khí không màu thoát ra.', N'Cu tan dần, có Ag bám vào.', N'Dung dịch chuyển màu xanh lam.', N'B và C đều đúng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (293, 10, N'(TH) Cặp không phản ứng oxi hoá – khử:', N'Fe và HCl.', N'Zn và CuSO₄.', N'Ag và HCl.', N'Mg và FeCl₃.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (294, 10, N'(VD) Thứ tự tăng dần tính oxi hoá của ion:', N'Fe²⁺ < Cu²⁺ < Ag⁺ < Fe³⁺.', N'Fe²⁺ < Cu²⁺ < Fe³⁺ < Ag⁺.', N'Fe³⁺ < Ag⁺ < Cu²⁺ < Fe²⁺.', N'Fe²⁺ < Fe³⁺ < Cu²⁺ < Ag⁺.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (295, 10, N'(VD) Cu + AgNO₃, khối lượng đồng tăng 1,52g → khối lượng Ag bám vào:', N'1,08 g.', N'2,16 g.', N'4,32 g.', N'3,24 g.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (296, 10, N'(VDC) Fe và Cu phản ứng với AgNO₃ tạo chất rắn nặng hơn 22,4g → %Fe?', N'43,75%.', N'56,25%.', N'46,67%.', N'64,00%.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (297, 10, N'(TH) Bảo vệ vỏ tàu biển bằng kim loại nào?', N'Đồng (Cu).', N'Kẽm (Zn).', N'Chì (Pb).', N'Bạc (Ag).', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (298, 10, N'(NB) Kim loại phản ứng với nước ở nhiệt độ thường:', N'K.', N'Mg.', N'Fe.', N'Cu.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (299, 10, N'(VD) Mg phản ứng với FeCl₃ và CuCl₂ → khối lượng tăng 6g → m = ?', N'12,0 g.', N'6,0 g.', N'9,6 g.', N'7,2 g.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (300, 10, N'(VDC) Fe, Cu phản ứng với AgNO₃, Fe(NO₃)₃ → m chất rắn = ?', N'43,2.', N'54,0.', N'64,8.', N'48,6.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (301, 11, N'Để tìm giá trị lớn nhất hoặc nhỏ nhất của một đại lượng trong một bài toán thực tế (ví dụ: chi phí thấp nhất, lợi nhuận cao nhất), bước đầu tiên quan trọng nhất là gì?', N'Tính đạo hàm cấp hai của hàm số.', N'Xây dựng một hàm số toán học mô tả đại lượng đó.', N'Lập bảng biến thiên.', N'Giải phương trình đạo hàm bằng 0.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (302, 11, N'Một công ty có hàm chi phí sản xuất x sản phẩm là C(x) và hàm doanh thu là R(x). Hàm lợi nhuận P(x) được xác định bởi công thức nào?', N'P(x) = C(x) – R(x)', N'P(x) = R(x) – C(x)', N'P(x) = R(x) + C(x)', N'P(x) = R(x) / C(x)', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (303, 11, N'Một mảnh vườn hình chữ nhật có chu vi là 80 mét. Nếu gọi một cạnh có độ dài là x (mét) thì hàm số biểu thị diện tích S(x) của mảnh vườn là:', N'S(x) = x(80 – x)', N'S(x) = x(40 – 2x)', N'S(x) = x(40 – x)', N'S(x) = 80x', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (304, 11, N'Cho hàm chi phí sản xuất C(q) = 0.1q² – 20q + 5000. Tại mức sản lượng q₀, chi phí là thấp nhất. Điều này có nghĩa là giá trị C''(q₀) bằng bao nhiêu?', N'1', N'-1', N'0', N'5000', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (305, 11, N'Cho hàm lợi nhuận P(x) = -2x³ + 60x² + 150 (với x là số lượng sản phẩm). Để tìm số sản phẩm cho lợi nhuận tối đa, ta cần giải phương trình nào?', N'P(x) = 0', N'P''(x) = 0', N'P”(x) = 0', N'P(x) = P''(x)', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (306, 11, N'Một vật chuyển động có phương trình quãng đường là s(t) = t³ – 6t² + 9t + 2 (t tính bằng giây, s tính bằng mét). Vận tốc của vật được tính bằng công thức v(t) = s''(t). Vận tốc của vật tại thời điểm t = 1 giây là:', N'6 m/s', N'1 m/s', N'0 m/s', N'-1 m/s', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (307, 11, N'Một công ty sản xuất hộp giấy không nắp dạng hình hộp chữ nhật có đáy là hình vuông cạnh x (dm) và chiều cao là h (dm). Biết thể tích hộp là 125 dm³. Hàm số biểu thị diện tích toàn phần (diện tích giấy cần dùng) S(x) là:', N'S(x) = x² + 4xh', N'S(x) = x² + 500/x', N'S(x) = x² + 125/x', N'S(x) = 4x + 125/x²', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (308, 11, N'[ĐỀ] Đồ thị bên mô tả lợi nhuận P (triệu đồng) của một cửa hàng theo thời gian t (tháng) trong một năm. Lợi nhuận cao nhất đạt được vào khoảng tháng nào? (Gợi ý hình ảnh: Một đồ thị dạng parabol úp xuống, đỉnh của parabol có hoành độ nằm giữa 7 và 8)', N'Tháng 3', N'Tháng 10', N'Tháng 7', N'Tháng 1', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (309, 11, N'Vận tốc của một hạt được cho bởi hàm v(t) = -t² + 10t + 3. Gia tốc của hạt được tính bằng a(t) = v''(t). Gia tốc của hạt tại thời điểm t = 2 là:', N'10', N'6', N'19', N'-4', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (310, 11, N'Giá bán p (nghìn đồng) của một sản phẩm phụ thuộc vào số lượng bán được q theo công thức p = 150 – q. Hàm doanh thu R(q) được xác định như thế nào?', N'R(q) = 150 – q', N'R(q) = 150q – q²', N'R(q) = 150', N'R(q) = q / (150 – q)', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (311, 11, N'Một đoạn dây dài 20 cm được uốn thành một hình chữ nhật. Để diện tích hình chữ nhật là lớn nhất, nó phải là hình gì?', N'Một hình chữ nhật có chiều dài gấp đôi chiều rộng.', N'Một hình chữ nhật có chiều dài gấp ba chiều rộng.', N'Một hình vuông.', N'Không xác định được.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (312, 11, N'Nồng độ một loại thuốc trong máu của bệnh nhân sau khi tiêm t giờ được cho bởi hàm C(t) = 10t / (t² + 4). Tốc độ thay đổi nồng độ thuốc được cho bởi C''(t). Biểu thức của C''(t) là:', N'(10t² – 40) / (t² + 4)²', N'10 / (2t)', N'(40 + 10t²) / (t² + 4)²', N'(40 – 10t²) / (t² + 4)²', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (313, 11, N'Người ta muốn rào một khu đất hình chữ nhật có diện tích 1800 m² và sau đó chia khu đất thành hai lô nhỏ bằng một hàng rào song song với một cạnh. Để chi phí mua vật liệu rào là ít nhất thì tổng độ dài các hàng rào là bao nhiêu mét?', N'150 m', N'180 m', N'120 m', N'240 m', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (314, 11, N'Một vật được ném lên cao theo phương thẳng đứng với phương trình chuyển động s(t) = -5t² + 40t + 3, với t là thời gian (giây) và s là độ cao (mét). Độ cao tối đa mà vật đạt được là:', N'40 m', N'4 giây', N'83 m', N'80 m', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (315, 11, N'Một tấm nhôm hình vuông cạnh 18 cm. Người ta cắt ở bốn góc bốn hình vuông bằng nhau, rồi gập tấm nhôm lại để được một cái hộp không nắp. Để thể tích của hộp là lớn nhất, cạnh của các hình vuông bị cắt phải bằng:', N'2 cm', N'3 cm', N'4 cm', N'6 cm', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (316, 11, N'Một nhà sản xuất xác định rằng giá bán của mỗi sản phẩm là p = 100 – 0.2x (USD), với x là số sản phẩm được bán. Chi phí sản xuất là C(x) = 20x + 5000 (USD). Cần bán bao nhiêu sản phẩm để lợi nhuận là tối đa?', N'100 sản phẩm', N'400 sản phẩm', N'200 sản phẩm', N'500 sản phẩm', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (317, 11, N'Tìm điểm trên đồ thị hàm số y = √x (với x ≥ 0) sao cho khoảng cách từ điểm đó đến điểm A(2; 0) là ngắn nhất.', N'(1; 1)', N'(3/2; √6/2)', N'(2; √2)', N'(4; 2)', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (318, 11, N'Một trang sách cần chứa 300 cm² phần chữ in. Lề trên và lề dưới là 2 cm, lề trái và lề phải là 1.5 cm. Kích thước của trang sách (chiều rộng, chiều cao) phải là bao nhiêu để tốn ít giấy nhất?', N'(10 cm; 30 cm)', N'(20 cm; 15 cm)', N'(18 cm; 20 cm)', N'(15 cm; 24 cm)', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (319, 11, N'Nồng độ oxy hòa tan trong một hồ nước bị ô nhiễm được mô hình hóa bởi hàm số y(t) = 10 – 20t / (t² + 1) (mg/l), với t là thời gian (ngày) sau khi xảy ra sự cố. Nồng độ oxy thấp nhất trong hồ là bao nhiêu?', N'10 mg/l', N'5 mg/l', N'2 mg/l', N'0 mg/l', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (320, 11, N'[ĐỀ] Đồ thị bên mô tả chi phí C(v) (lít/100km) của một chiếc xe khi di chuyển với vận tốc v (km/h). Dựa vào đồ thị, để tiết kiệm nhiên liệu nhất, tài xế nên chạy xe với vận tốc khoảng bao nhiêu?', N'50 km/h', N'100 km/h', N'80 km/h', N'120 km/h', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (321, 11, N'Một người nông dân có 2400 mét hàng rào và muốn rào một khu đất hình chữ nhật nằm cạnh một con sông thẳng (không cần rào cạnh giáp sông). Diện tích lớn nhất mà người nông dân có thể rào được là:', N'240000 m²', N'360000 m²', N'720000 m²', N'120000 m²', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (322, 11, N'Một đoạn dây dài 40 cm được cắt thành hai phần. Một phần uốn thành hình vuông, phần còn lại uốn thành hình tròn. Phải cắt đoạn dây như thế nào để tổng diện tích của hình vuông và hình tròn là nhỏ nhất?', N'Cắt thành hai đoạn bằng nhau.', N'Đoạn dây uốn thành hình vuông có độ dài 160/(4+π) cm.', N'Đoạn dây uốn thành hình tròn có độ dài 10 cm.', N'Toàn bộ đoạn dây uốn thành hình tròn.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (323, 11, N'Hiệu suất làm việc của một công nhân H(t) sau t giờ làm việc (kể từ lúc 8h sáng) được cho bởi công thức H(t) = -t³ + 9t² + 12t, với 0 ≤ t ≤ 6. Vào thời điểm nào trong ngày, hiệu suất của người công nhân là cao nhất?', N'8h sáng (t=0)', N'11h sáng (t=3)', N'14h chiều (t=6)', N'Khoảng 14h24 phút (t ≈ 6.16) nhưng do t ≤ 6 nên là lúc 14h (t=6).', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (324, 11, N'Người ta muốn làm một thùng chứa hình trụ không nắp có thể tích là 100π cm³. Bán kính đáy r của hình trụ phải bằng bao nhiêu để diện tích vật liệu cần dùng là ít nhất?', N'10 cm', N'5 cm', N'1 cm', N'2 cm', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (325, 11, N'Một cửa sổ có dạng hình chữ nhật và phía trên là một nửa hình tròn. Chu vi của cửa sổ là 10 mét. Bán kính của nửa hình tròn phải là bao nhiêu để diện tích cửa sổ là lớn nhất (để hứng nhiều ánh sáng nhất)?', N'10 m', N'10/(4 + 2π) m', N'10/(4 + π) m', N'5/(2 + π) m', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (326, 11, N'Một máy bay bay với vận tốc so với không khí là v. Máy bay bay ngược chiều gió có vận tốc là w. Chi phí nhiên liệu mỗi giờ bay tỉ lệ với lập phương của vận tốc so với không khí, tức là C = kv³ (k là hằng số). Thời gian bay trên quãng đường S là T = S / (v – w). Chi phí tổng cộng cho chuyến bay là F = C * T = kSv³ / (v-w). Để chi phí là thấp nhất, vận tốc v của máy bay phải bằng:', N'2w', N'(3/2)w', N'3w', N'4w', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (327, 11, N'Cho hai nguồn sáng A(0; 4) và B(6; 6). Cần đặt một màn ảnh trên trục hoành tại điểm M(x; 0) sao cho tổng cường độ sáng nhận được từ hai nguồn là lớn nhất. Biết cường độ sáng tỉ lệ nghịch với bình phương khoảng cách. Tức là phải tìm x để P = 1/MA² + 1/MB² đạt giá trị lớn nhất. Hoành độ x của M gần giá trị nào nhất?', N'2.5', N'3.4', N'4.0', N'5.1', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (328, 11, N'Hai con tàu xuất phát cùng lúc từ hai cảng A và B cách nhau 100 hải lý. Tàu từ A đi về hướng Nam với vận tốc 20 hải lý/giờ. Tàu từ B đi về hướng Tây với vận tốc 30 hải lý/giờ. Sau bao lâu thì khoảng cách giữa hai tàu là nhỏ nhất?', N'1 giờ', N'3 giờ', N'30/13 giờ', N'20/13 giờ', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (329, 11, N'Một người muốn làm một bể cá không nắp bằng kính dạng hình hộp chữ nhật có thể tích 32 m³ và chiều dài gấp đôi chiều rộng. Giá kính làm mặt đáy là 200,000 đồng/m², giá kính làm mặt xung quanh là 150,000 đồng/m². Kích thước của bể (rộng, dài, cao) phải là bao nhiêu để chi phí là thấp nhất?', N'(2m, 4m, 4m)', N'(3m, 6m, 16/9m)', N'(4m, 8m, 1m)', N'(2.5m, 5m, 2.56m)', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (330, 11, N'Một công ty độc quyền sản xuất một mặt hàng với hàm cầu là p = 600 – 2q (p là giá, q là sản lượng). Hàm tổng chi phí là C(q) = 0.5q² + 20q + 500. Chính phủ đánh thuế t đồng trên mỗi sản phẩm bán ra. Công ty sẽ điều chỉnh sản lượng để tối đa hóa lợi nhuận của mình. Chính phủ muốn tìm mức thuế t để thu được nhiều tiền thuế nhất. Mức thuế t đó là bao nhiêu?', N'100 đồng', N'150 đồng', N'190 đồng', N'290 đồng', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (331, 12, N'Trong không gian, hai vectơ được gọi là bằng nhau khi và chỉ khi chúng:', N'Cùng phương và có độ dài bằng nhau.', N'Cùng hướng và có độ dài bằng nhau.', N'Có cùng điểm đầu và cùng điểm cuối.', N'Cùng nằm trên một đường thẳng.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (332, 12, N'Cho ba điểm phân biệt A, B, C. Đẳng thức nào sau đây là đúng?', N'vectơ AB + vectơ BC = vectơ CA', N'vectơ AB – vectơ AC = vectơ BC', N'vectơ CA + vectơ AB = vectơ CB', N'vectơ BA + vectơ AC = vectơ BC', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (333, 12, N'Cho hình lập phương ABCD.A’B’C’D’. Tích vô hướng của hai vectơ AB và AA’ bằng:', N'0', N'a² (với a là cạnh hình lập phương)', N'a', N'1', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (334, 12, N'Cho vectơ a khác vectơ 0 và một số thực k < 0. Khẳng định nào sau đây đúng về vectơ b = k * vectơ a?', N'Vectơ b cùng hướng với vectơ a.', N'Vectơ b có độ dài bằng k lần độ dài vectơ a.', N'Vectơ b ngược hướng với vectơ a.', N'Vectơ b vuông góc với vectơ a.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (335, 12, N'Cho hình hộp ABCD.A’B’C’D’. Đẳng thức nào sau đây thể hiện quy tắc hình hộp?', N'vectơ AB + vectơ AD = vectơ AC', N'vectơ AB + vectơ BC + vectơ CD = vectơ AD', N'vectơ AB + vectơ AD + vectơ AA’ = vectơ AC’', N'vectơ AA’ + vectơ BB’ + vectơ CC’ = vectơ 0', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (336, 12, N'Cho hình bình hành ABCD. Đẳng thức nào sau đây đúng?', N'vectơ AB + vectơ AD = vectơ DB', N'vectơ BA + vectơ BC = vectơ BD', N'vectơ DA + vectơ DC = vectơ CA', N'vectơ AB + vectơ BC = vectơ DB', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (337, 12, N'Cho hình lập phương ABCD.A’B’C’D’ cạnh a. Độ dài của vectơ AB + AD bằng:', N'2a', N'a', N'a√3', N'a√2', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (338, 12, N'Điều kiện cần và đủ để ba điểm A, B, C thẳng hàng là:', N'vectơ AB và vectơ BC cùng phương.', N'A, B, C tạo thành một tam giác.', N'Tồn tại số k khác 0 sao cho vectơ AB = k * vectơ AC.', N'vectơ AB + vectơ BC + vectơ CA = vectơ 0.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (339, 12, N'Cho hai vectơ a và b có độ dài lần lượt là 3 và 4, góc giữa chúng bằng 120°. Tích vô hướng của vectơ a và vectơ b là:', N'6', N'12', N'-6', N'-12', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (340, 12, N'Cho tứ diện đều ABCD. Gọi M và N lần lượt là trung điểm của AB và CD. Cặp vectơ nào sau đây vuông góc với nhau?', N'vectơ AB và vectơ AC', N'vectơ AB và vectơ CD', N'vectơ AC và vectơ BD', N'vectơ AD và vectơ BC', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (341, 12, N'Trong các mệnh đề sau, mệnh đề nào sai?', N'Nếu M là trung điểm của AB thì vectơ MA + vectơ MB = vectơ 0.', N'Nếu G là trọng tâm tam giác ABC thì vectơ GA + vectơ GB + vectơ GC = 3 * vectơ GG.', N'Với ba điểm A, B, C bất kỳ, ta có vectơ AB = vectơ CB – vectơ CA.', N'Vectơ đối của vectơ a – b là vectơ b – a.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (342, 12, N'Cho hai vectơ a và b vuông góc với nhau và có độ dài lần lượt là 6 và 8. Độ dài của vectơ a + b bằng:', N'14', N'2', N'10', N'48', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (343, 12, N'Cho tam giác ABC và điểm M thỏa mãn vectơ MA – vectơ MB + vectơ MC = vectơ 0. Tìm vị trí của M.', N'M là đỉnh thứ tư của hình bình hành ABCM.', N'M là đỉnh thứ tư của hình bình hành ABMC.', N'M là trọng tâm tam giác ABC.', N'M là trung điểm của AC.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (344, 12, N'Cho hình lập phương ABCD.A’B’C’D’. Góc giữa hai vectơ AB và A’C’ bằng:', N'45°', N'60°', N'90°', N'120°', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (345, 12, N'Hai lực F₁ và F₂ có cùng độ lớn là 10 N, có điểm đặt tại cùng một điểm O. Góc tạo bởi hai lực là 60°. Cường độ của hợp lực F₁ + F₂ là:', N'10 N', N'20 N', N'10√3 N', N'10√2 N', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (346, 12, N'Cho hình chóp S.ABC có đáy ABC là tam giác vuông tại B. SA vuông góc với mặt phẳng đáy. Đẳng thức nào sau đây sai?', N'vectơ SB · vectơ BC = 0', N'vectơ SA · vectơ AB = 0', N'vectơ SC · vectơ AB = 0', N'vectơ SA · vectơ BC = 0', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (347, 12, N'Cho tứ diện ABCD. Gọi G là trọng tâm của tam giác BCD. Đẳng thức nào sau đây đúng?', N'vectơ AB + vectơ AC + vectơ AD = 2 * vectơ AG', N'vectơ AB + vectơ AC + vectơ AD = 3 * vectơ AG', N'vectơ GA + vectơ GB + vectơ GC + vectơ GD = vectơ 0', N'vectơ AG = (vectơ AB + vectơ AC + vectơ AD) / 4', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (348, 12, N'Cho vectơ a có độ dài bằng 5. Tích vô hướng vectơ a · vectơ a bằng:', N'5', N'0', N'25', N'10', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (349, 12, N'Cho tam giác đều ABC cạnh a. Tích vô hướng vectơ AB · vectơ BC bằng:', N'a²/2', N'-a²/2', N'-a²/2', N'a²', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (350, 12, N'[ĐỀ] Cho hình hộp chữ nhật ABCD.A’B’C’D’. Tìm tổng của vectơ AB + vectơ AD + vectơ B’C’.', N'vectơ AC’', N'vectơ A’C', N'vectơ AB + vectơ AD + vectơ A’D’', N'vectơ AD’', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (351, 12, N'Nếu vectơ a và vectơ b thỏa mãn |vectơ a + vectơ b| = |vectơ a – vectơ b| thì:', N'Vectơ a và vectơ b bằng nhau.', N'Vectơ a và vectơ b cùng phương.', N'Vectơ a và vectơ b vuông góc với nhau.', N'Vectơ a hoặc vectơ b là vectơ 0.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (352, 12, N'Một vật có khối lượng 5 kg chịu tác động của một lực F, tạo ra gia tốc a có độ lớn 4 m/s². Độ lớn của lực F theo định luật II Newton (F = m*a) là:', N'5 N', N'4 N', N'20 N', N'1.25 N', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (353, 12, N'Cho tứ diện ABCD. Mệnh đề nào sau đây đúng?', N'vectơ AB + vectơ CD = vectơ AD + vectơ CB', N'vectơ AC + vectơ BD = vectơ AD + vectơ BC', N'vectơ AD + vectơ BC = vectơ AC + vectơ BD', N'Cả A, B, C đều sai.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (354, 12, N'Trong không gian, cho ba vectơ a, b, c đều khác vectơ 0. Nếu vectơ a + vectơ b + vectơ c = vectơ 0 và |vectơ a| = |vectơ b| = |vectơ c|, thì góc giữa hai vectơ bất kỳ trong chúng bằng:', N'60°', N'90°', N'120°', N'45°', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (355, 12, N'Cho hình chóp S.ABCD có đáy là hình thoi, SA = SC, SB = SD. Khẳng định nào sau đây đúng?', N'vectơ SO vuông góc với mặt phẳng (ABCD), với O là tâm đáy.', N'vectơ AC vuông góc với vectơ SD.', N'vectơ SA + vectơ SB = vectơ SC + vectơ SD.', N'vectơ AB và vectơ CD vuông góc.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (356, 12, N'Cho hình lập phương ABCD.A’B’C’D’ cạnh a. Tính |vectơ AB + vectơ AC’ + vectơ AD’|.', N'a√3', N'2a√3', N'3a√2', N'3a', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (357, 12, N'Cho tam giác ABC. Tập hợp các điểm M trong không gian thỏa mãn |vectơ MA + vectơ MB| = |vectơ MC| là:', N'Một đường thẳng.', N'Một mặt phẳng.', N'Một mặt cầu.', N'Một điểm.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (358, 12, N'Cho tứ diện ABCD có AB vuông góc với CD, AC vuông góc với BD. Cặp vectơ nào sau đây cũng vuông góc với nhau?', N'vectơ AD và vectơ BC', N'vectơ AB và vectơ AC', N'vectơ CD và vectơ BD', N'Không xác định được.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (359, 12, N'Cho hình lập phương ABCD.A’B’C’D’. Gọi M, N lần lượt là trung điểm của BC và A’D’. Cosin của góc giữa hai đường thẳng AM và C’N là:', N'1/3', N'1/5', N'2/5', N'2/3', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (360, 12, N'Một vật nặng 30N được treo cân bằng bởi ba sợi dây giống hệt nhau OA, OB, OC sao cho phương của mỗi sợi dây đều tạo với phương thẳng đứng một góc 30°. Lực căng trên mỗi sợi dây có độ lớn là:', N'10 N', N'30 N', N'15 N', N'20/√3 N', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (361, 12, N'Đối với một mẫu số liệu ghép nhóm, “Khoảng biến thiên” (R) được định nghĩa là:', N'Hiệu số giữa giá trị lớn nhất và giá trị nhỏ nhất trong mẫu.', N'Hiệu số giữa tứ phân vị thứ ba và tứ phân vị thứ nhất.', N'Hiệu số giữa đầu mút phải của nhóm cuối cùng và đầu mút trái của nhóm đầu tiên.', N'Giá trị có tần số lớn nhất.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (362, 12, N'Cho bảng tần số ghép nhóm về thời gian hoàn thành một bài thi (phút) của một nhóm học sinh:', N'4', N'42', N'60', N'20', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (363, 12, N'Số đặc trưng nào sau đây đo lường mức độ phân tán của 50% số liệu nằm ở giữa mẫu?', N'Số trung bình', N'Khoảng biến thiên', N'Mốt', N'Khoảng tứ phân vị', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (364, 12, N'Tứ phân vị thứ hai (Q₂) của một mẫu số liệu còn được gọi là:', N'Mốt', N'Số trung bình', N'Trung vị', N'Giá trị lớn nhất', N'C', NULL);
