INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (369, 12, N'Một giá trị x được coi là giá trị ngoại lệ (bất thường) nếu:', N'x > Q₃ + ∆_Q hoặc x < Q₁ – ∆_Q', N'x > Q₃ + 1.5 * ∆_Q hoặc x < Q₁ – 1.5 * ∆_Q', N'x lớn hơn giá trị trung bình rất nhiều.', N'x không thuộc vào nhóm có tần số cao nhất.', N'B', NULL);
