INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (382, 12, N'Giá trị nào sau đây không thể là tứ phân vị thứ nhất Q₁ của mẫu số liệu sau:', N'21', N'25', N'29', N'31', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (383, 12, N'Trong công thức tính tứ phân vị, đại lượng (uₘ₊₁ – uₘ) biểu thị cho:', N'Tần số của nhóm.', N'Tần số tích lũy.', N'Độ rộng của nhóm chứa tứ phân vị.', N'Giá trị đại diện của nhóm.', N'C', NULL);
