INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (386, 12, N'Nếu tất cả các giá trị trong một mẫu số liệu ghép nhóm đều được nhân với 2 thì khoảng biến thiên mới sẽ:', N'Bằng khoảng biến thiên cũ.', N'Gấp đôi khoảng biến thiên cũ.', N'Bằng một nửa khoảng biến thiên cũ.', N'Gấp bốn lần khoảng biến thiên cũ.', N'B', NULL);
