INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (389, 12, N'[ĐỀ] Hai công ty A và B có dữ liệu về tuổi thọ (năm) của một loại sản phẩm như sau. Công ty nào sản xuất sản phẩm có tuổi thọ ổn định, đồng đều hơn?', N'Công ty A, vì khoảng biến thiên lớn hơn.', N'Công ty B, vì khoảng tứ phân vị nhỏ hơn.', N'Công ty A, vì khoảng tứ phân vị nhỏ hơn.', N'Hai công ty có độ ổn định như nhau.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (390, 12, N'Khảo sát lượng mưa (mm) trong 30 ngày tại một địa phương thu được bảng số liệu sau:', N'Không, vì 45 nằm trong nhóm [40; 50).', N'Có, vì đây là lượng mưa cao nhất.', N'Có, vì 45 lớn hơn ngưỡng giá trị ngoại lệ trên.', N'Không, vì 45 nhỏ hơn ngưỡng giá trị ngoại lệ trên..', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (391, 12, N'[Nhận biết] Trong các khẳng định sau, khẳng định nào mô tả đúng và đầy đủ nhất về định nghĩa nguyên hàm?', N'Hàm số F(x) được gọi là một nguyên hàm của hàm số f(x) trên K nếu đạo hàm của f(x) bằng F(x) với mọi x thuộc K.', N'Hàm số F(x) được gọi là một nguyên hàm của hàm số f(x) trên K nếu F(x) = f(x) với mọi x thuộc K.', N'Hàm số F(x) được gọi là một nguyên hàm của hàm số f(x) trên K nếu đạo hàm của F(x) bằng f(x) với mọi x thuộc K.', N'Hàm số F(x) được gọi là một nguyên hàm của hàm số f(x) trên K nếu đạo hàm của F(x) bằng f(x) với một vài giá trị x thuộc K.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (392, 12, N'[Nhận biết] Họ nguyên hàm của hàm số f(x) = 0 là gì?', N'0', N'x + C', N'C (hằng số)', N'1', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (393, 12, N'[Nhận biết] Họ nguyên hàm của hàm số f(x) = 1 là gì?', N'x + C', N'1', N'C', N'0', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (394, 12, N'[Nhận biết] Tìm họ nguyên hàm của f(x) = x.', N'1 + C', N'x² + C', N'(1/2)x² + C', N'(1/2)x + C', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (395, 12, N'[Nhận biết] Tìm họ nguyên hàm của f(x) = 1/√x với x > 0.', N'2√x + C', N'(1/2)√x + C', N'-1/(2x√x) + C', N'ln(√x) + C', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (396, 12, N'[Nhận biết] Tìm họ nguyên hàm của f(x) = cos(x).', N'sin(x) + C', N'-sin(x) + C', N'cos(x) + C', N'-cos(x) + C', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (397, 12, N'[Nhận biết] Tìm họ nguyên hàm của f(x) = 1/sin²x trên các khoảng xác định của nó.', N'tan(x) + C', N'-tan(x) + C', N'cot(x) + C', N'-cot(x) + C', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (398, 12, N'[Nhận biết] Tìm họ nguyên hàm của f(x) = 2^x.', N'2^x.ln(2) + C', N'2^x + C', N'2^x / ln(2) + C', N'x.2^(x-1) + C', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (399, 12, N'[Nhận biết] Tính chất ∫[f(x) – g(x)]dx = ∫f(x)dx – ∫g(x)dx được suy ra từ tính chất nào của đạo hàm?', N'Đạo hàm của một tổng/hiệu.', N'Đạo hàm của một tích.', N'Đạo hàm của một thương.', N'Quy tắc chuỗi (đạo hàm hàm hợp).', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (400, 12, N'[Thông hiểu] Nếu F(x) là một nguyên hàm của hàm số f(x) trên một khoảng K và C là một hằng số tùy ý, thì mối quan hệ giữa G(x) = F(x) + C và f(x) là gì?', N'G(x) cũng là một nguyên hàm của f(x) trên K vì đạo hàm của G(x) bằng đạo hàm của F(x) cộng C, tức là f(x) + C.', N'G(x) không phải là một nguyên hàm của f(x) vì có sự xuất hiện của hằng số C.', N'G(x) cũng là một nguyên hàm của f(x) trên K vì đạo hàm của hằng số C bằng 0.', N'G(x) chỉ là một nguyên hàm của f(x) khi C = 0.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (401, 12, N'[Thông hiểu] Xét hàm số f(x) = 3x². Hàm số F(x) = x³ là một nguyên hàm của f(x). Đâu là cách diễn đạt đúng về tập hợp tất cả các nguyên hàm của f(x)?', N'Họ nguyên hàm của f(x) là x³.', N'Họ nguyên hàm của f(x) là ∫3x²dx = x³ + C, với C là hằng số.', N'Họ nguyên hàm của f(x) là 3x³ + C, với C là hằng số.', N'Không tồn tại khái niệm họ nguyên hàm, chỉ có một nguyên hàm duy nhất.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (402, 12, N'[Thông hiểu] Phát biểu nào sau đây là đúng?', N'Hai nguyên hàm bất kỳ của cùng một hàm số thì bằng nhau.', N'Hai nguyên hàm bất kỳ của cùng một hàm số có thể sai khác nhau một lượng tùy ý.', N'Hai nguyên hàm bất kỳ của cùng một hàm số chỉ sai khác nhau một hằng số.', N'Một hàm số chỉ có duy nhất một nguyên hàm.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (403, 12, N'[Thông hiểu] Cho F(x) và G(x) đều là các nguyên hàm của hàm số f(x) trên K. Mối quan hệ giữa đồ thị của y = F(x) và y = G(x) là gì?', N'Chúng là hai đường cong đối xứng nhau qua trục Ox.', N'Chúng là hai đường cong có thể thu được bằng cách tịnh tiến lẫn nhau theo phương của trục Oy.', N'Chúng trùng nhau hoàn toàn.', N'Chúng là hai đường cong không liên quan.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (404, 12, N'[Thông hiểu] Dựa vào định nghĩa, đẳng thức nào sau đây luôn đúng?', N'∫(đạo hàm của f(x))dx = (đạo hàm của f(x)) + C', N'∫f(x)dx = (đạo hàm của f(x)) + C', N'Đạo hàm của (∫f(x)dx) bằng f(x).', N'Đạo hàm của (∫f(x)dx) bằng f(x) + C.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (405, 12, N'[Thông hiểu] Khẳng định nào sau đây là sai về tính chất của nguyên hàm?', N'∫[f(x) + g(x)]dx = ∫f(x)dx + ∫g(x)dx', N'∫k.f(x)dx = k.∫f(x)dx (với k là hằng số khác 0)', N'∫[f(x).g(x)]dx = [∫f(x)dx].[∫g(x)dx]', N'Mọi hàm số liên tục trên K đều có nguyên hàm trên K.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (406, 12, N'[Thông hiểu] Biểu thức f(x)dx trong ∫f(x)dx được gọi là gì và nó bằng với biểu thức nào sau đây nếu F(x) là một nguyên hàm của f(x)?', N'Vi phân của f(x), bằng (đạo hàm của f(x))dx.', N'Vi phân của F(x), bằng (đạo hàm của F(x))dx.', N'Tích phân của f(x).', N'Đạo hàm của F(x).', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (407, 12, N'[Thông hiểu] Cho ∫f(x)dx = 2x² + sin(x) + C. Hàm số f(x) là hàm số nào dưới đây?', N'f(x) = 4x – cos(x)', N'f(x) = 4x + cos(x)', N'f(x) = (2/3)x³ – cos(x)', N'f(x) = 2x + sin(x)', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (408, 12, N'[Thông hiểu] Nếu ∫f(x)dx = F(x) + C thì ∫f(2x)dx bằng:', N'F(2x) + C', N'2F(2x) + C', N'(1/2)F(2x) + C', N'2F(x) + C', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (409, 12, N'[Vận dụng thấp] Tìm họ nguyên hàm F(x) của hàm số f(x) = (x+1)².', N'F(x) = (1/3)(x+1)³ + C', N'F(x) = 2(x+1) + C', N'F(x) = x³ + x² + x + C', N'F(x) = (1/3)x³ + x² + x + C', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (410, 12, N'[Vận dụng] Tìm một nguyên hàm F(x) của hàm số f(x) = e^x + 2 biết rằng F(0) = 3.', N'F(x) = e^x + 2x + 2', N'F(x) = e^x + 2x + 3', N'F(x) = e^x + 2', N'F(x) = e^x + 3', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (411, 12, N'[Vận dụng] Tìm nguyên hàm của f(x) = 1/cos²x biết đồ thị của nó đi qua điểm M(π/4, 3).', N'tan(x) + 2', N'tan(x) + 3', N'-cot(x) + 4', N'tan(x)', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (412, 12, N'[Vận dụng] Tìm nguyên hàm F(x) của f(x) = 1/x biết F(1) = 2.', N'F(x) = ln|x| + 1', N'F(x) = ln(x) + 2', N'F(x) = ln|x| + 2', N'F(x) = -1/x² + 3', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (413, 12, N'[Vận dụng] Một vật thể chuyển động với gia tốc a(t) = 12t (m/s²). Biết rằng tại thời điểm t=1 s, vận tốc của vật là v(1) = 10 m/s. Hàm số biểu thị vận tốc v(t) của vật là gì?', N'v(t) = 12t² + C', N'v(t) = 6t² + 4', N'v(t) = 6t² + 10', N'v(t) = 12', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (414, 12, N'[Vận dụng] Một chiếc ô tô đang chạy thì hãm phanh, chuyển động chậm dần với vận tốc v(t) = 20 – 4t (m/s), trong đó t là thời gian tính bằng giây kể từ lúc hãm phanh. Quãng đường ô tô đi được từ lúc hãm phanh đến khi dừng hẳn là bao nhiêu?', N'40 m', N'50 m', N'20 m', N'100 m', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (415, 12, N'[Vận dụng cao] Tìm họ nguyên hàm của hàm số f(x) = 2sin(x/2)cos(x/2).', N'-cos(x) + C', N'sin(x) + C', N'-cos(2x) + C', N'2sin²(x/2) + C', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (416, 12, N'[Vận dụng cao] Tại sao khi tìm nguyên hàm của f(x) = 1/x trên tập xác định R{0}, ta phải viết kết quả là ln|x| + C thay vì ln(x) + C?', N'Vì ln|x| có đạo hàm là 1/x trên cả hai khoảng (-∞, 0) và (0, +∞).', N'Vì ln(x) chỉ xác định với x > 0, trong khi f(x) còn xác định với x < 0.', N'Đây chỉ là quy ước để bài toán đơn giản hơn.', N'Cả A và B đều là những lý do quan trọng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (417, 12, N'[Vận dụng cao] Cho hai hàm số F(x) và G(x) sao cho đạo hàm của F(x) bằng đạo hàm của G(x) với mọi x thuộc K. Kết luận nào sau đây là chính xác nhất?', N'F(x) = G(x) trên K.', N'F(x) – G(x) = C (với C là hằng số) trên K.', N'Đồ thị y = F(x) song song với đồ thị y = G(x).', N'∫F(x)dx = ∫G(x)dx.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (418, 12, N'[Vận dụng cao] Cho F(x) là một nguyên hàm của f(x) trên R. Nếu f(x) > 0 với mọi x thuộc R thì ta có thể kết luận gì về hàm số F(x)?', N'F(x) là hàm đồng biến trên R.', N'F(x) là hàm nghịch biến trên R.', N'F(x) là hàm hằng.', N'F(x) luôn dương trên R.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (419, 12, N'[Vận dụng cao] Cho hàm số F(x) là một nguyên hàm của f(x) trên K. Nếu f(x) là hàm số lẻ thì F(x) có tính chất gì?', N'F(x) là hàm số lẻ.', N'F(x) là hàm số chẵn.', N'F(x) là hàm số không chẵn, không lẻ.', N'Không đủ thông tin để kết luận.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (420, 12, N'[Vận dụng cao] Xét hai hàm số f(x) = 1/x trên khoảng (0, +∞) và g(x) = 1/x trên khoảng (-∞, 0).', N'ln(x) là nguyên hàm của f(x) và ln(-x) là nguyên hàm của g(x).', N'ln|x| là nguyên hàm chung cho cả hai trường hợp.', N'f(x) có nguyên hàm nhưng g(x) không có nguyên hàm.', N'Cả A và B đều đúng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (421, 12, N'Trong không gian Oxyz, mặt phẳng (P) có phương trình 2x – y + 5z – 1 = 0. Vectơ nào dưới đây là một vectơ pháp tuyến của (P)?', N'n = (2; 1; 5)', N'n = (2; -1; 1)', N'n = (-1; 5; -1)', N'', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (422, 12, N'Một mặt phẳng (P) có một vectơ pháp tuyến là n = (1; -3; 2). Vectơ nào sau đây cũng là một vectơ pháp tuyến của (P)?', N'v = (1; 3; 2)', N'v = (2; -3; 1)', N'', N'v = (2; 6; -4)', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (423, 12, N'Trong không gian Oxyz, điểm nào sau đây thuộc mặt phẳng (P): x + y – 2z + 1 = 0?', N'M(1; 1; 1)', N'N(2; 1; 0)', N'P(0; 1; 2)', N'', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (424, 12, N'Phương trình nào dưới đây là phương trình tổng quát của một mặt phẳng trong không gian Oxyz?', N'x² + y² + z² = 1', N'y = 2x + 1', N'x/2 + y/1 = 1', N'', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (425, 12, N'Trong không gian Oxyz, phương trình mặt phẳng đi qua điểm M(1; 2; -3) và nhận n = (2; 1; -1) làm vectơ pháp tuyến là:', N'2x + y – z – 7 = 0', N'', N'x + 2y – 3z – 1 = 0', N'2x + y – z + 7 = 0', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (426, 12, N'Nếu một mặt phẳng (P) có cặp vectơ chỉ phương là a và b không cùng phương, thì vectơ pháp tuyến n của (P) được xác định như thế nào?', N'n = a + b', N'n = a – b', N'n = a.b (tích vô hướng)', N'', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (427, 12, N'Trong không gian Oxyz, phương trình mặt phẳng (Oxy) là:', N'x = 0', N'y = 0', N'', N'x + y = 0', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (428, 12, N'Hai mặt phẳng (P): x + 2y – z + 5 = 0 và (Q): 2x + 4y – 2z + 1 = 0 có vị trí tương đối là gì?', N'Cắt nhau', N'Trùng nhau', N'Vuông góc', N'', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (429, 12, N'Điều kiện để hai mặt phẳng (P): A₁x + B₁y + C₁z + D₁ = 0 và (Q): A₂x + B₂y + C₂z + D₂ = 0 vuông góc với nhau là gì?', N'A₁/A₂ = B₁/B₂ = C₁/C₂', N'A₁A₂ + B₁B₂ + C₁C₂ = 1', N'A₁ = A₂, B₁ = B₂, C₁ = C₂', N'', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (430, 12, N'Trong không gian Oxyz, phương trình mặt phẳng đi qua ba điểm A(2; 0; 0), B(0; 3; 0), C(0; 0; -1) là:', N'3x + 2y – 6z – 6 = 0', N'', N'2x + 3y – z – 6 = 0', N'x/2 + y/3 + z/1 = 1', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (431, 12, N'Tính khoảng cách từ điểm M(1; -2; 2) đến mặt phẳng (P): x + 2y – 2z – 1 = 0.', N'8/3', N'', N'4/3', N'2', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (432, 12, N'Trong không gian Oxyz, cho hai điểm A(1; 2; 1) và B(-1; 0; 3). Phương trình mặt phẳng trung trực của đoạn thẳng AB là:', N'x + y + z – 3 = 0', N'', N'x – y + z – 1 = 0', N'-x – y + z + 1 = 0', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (433, 12, N'Trong không gian Oxyz, phương trình mặt phẳng (P) đi qua điểm M(1; 1; -1) và song song với mặt phẳng (Q): 2x – y + 3z = 0 là:', N'2x – y + 3z + 2 = 0', N'', N'2x – y + 3z – 2 = 0', N'x + y – z – 3 = 0', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (434, 12, N'Trong không gian Oxyz, cho mặt phẳng (P) có cặp vectơ chỉ phương là a = (1; 2; 0) và b = (0; -1; 3). Vectơ nào sau đây là một vectơ pháp tuyến của (P)?', N'n = (2; -1; -1)', N'n = (6; 3; 1)', N'', N'n = (6; -3; 1)', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (435, 12, N'Vị trí tương đối của hai mặt phẳng (P): x – y + 3z – 1 = 0 và (Q): -2x + 2y – 6z + 2 = 0 là:', N'Song song', N'Cắt nhau không vuông góc', N'Vuông góc', N'', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (436, 12, N'Phương trình mặt phẳng đi qua điểm M(2; -1; 1) và vuông góc với hai mặt phẳng (P): 2x – z + 1 = 0, (Q): y = 0 là:', N'x – 2z = 0', N'x + 2y = 0', N'', N'x – 2y + z – 5 = 0', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (437, 12, N'Trong không gian Oxyz, hình chiếu của điểm M(3; 1; -2) trên mặt phẳng (Oxy) có tọa độ là:', N'(3; 1; 2)', N'(3; 0; -2)', N'(0; 1; -2)', N'', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (438, 12, N'Cho ba điểm A(0; 1; 2), B(1; 3; 1), C(2; 0; 0). Phương trình mặt phẳng (ABC) là:', N'5x + 3y + 5z – 13 = 0', N'', N'-5x + 3y – 5z + 7 = 0', N'5x – 3y + 5z + 7 = 0', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (439, 12, N'Mặt phẳng (P) cắt các trục Ox, Oy, Oz lần lượt tại các điểm có hoành độ, tung độ, cao độ là 2, -3, 4. Phương trình của (P) là:', N'6x – 4y + 3z – 12 = 0', N'', N'6x + 4y – 3z – 12 = 0', N'2x – 3y + 4z = 1', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (440, 12, N'Khoảng cách giữa hai mặt phẳng song song (P): x + y – 2z = 0 và (Q): x + y – 2z + 6 = 0 là:', N'6', N'√6', N'3', N'', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (441, 12, N'Trong không gian Oxyz, cho điểm M(1; -1; 3) và mặt phẳng (P): 2x – 2y + z + 3 = 0. Khoảng cách từ M đến (P) bằng bao nhiêu?', N'10', N'', N'4', N'10/9', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (442, 12, N'Mặt phẳng (P) đi qua M(1;0;0) và chứa trục Oy có phương trình là:', N'x + z – 1 = 0', N'x – 1 = 0', N'y + z = 0', N'', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (443, 12, N'Cho mặt phẳng (P): (m+1)x – my + 2z – 1 = 0. Tìm giá trị của m để (P) vuông góc với mặt phẳng (Q): x + 3y – 4z = 0.', N'm = 7', N'm = -7/2', N'', N'm = -7', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (444, 12, N'Cho hai điểm A(-1; 0; 1), B(1; 2; -1). Phương trình mặt phẳng (P) đi qua A và vuông góc với đường thẳng AB là:', N'x + y – z + 2 = 0', N'', N'x + y – z – 2 = 0', N'x + 2y – z = 0', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (445, 12, N'Tìm giá trị của m để hai mặt phẳng sau song song: (P): 2x + y – z + 1 = 0 và (Q): 4x + my – 2z + 5 = 0.', N'm = 1', N'm = -2', N'', N'không tồn tại m', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (446, 12, N'Phương trình mặt phẳng (P) chứa trục Oz và đi qua điểm M(1; 2; 3) là:', N'2x – y + z – 3 = 0', N'x – 2y = 0', N'', N'3x – z = 0', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (447, 12, N'Cho hai mặt phẳng (P): x – 2y + 2z – 3 = 0 và (Q): 2x + y – 2z + 1 = 0. Điểm nào sau đây nằm trên giao tuyến của hai mặt phẳng này?', N'(1; -1; 0)', N'(3; 1; 1)', N'(1; 0; 1)', N'', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (448, 12, N'Trong không gian Oxyz, viết phương trình mặt phẳng (P) đi qua hai điểm A(1; 0; 1), B(2; 1; 2) và vuông góc với mặt phẳng (Q): x + 2y + 3z + 4 = 0.', N'x + 2y – z = 0', N'x – 2y + z = 0', N'', N'x + y + z – 2 = 0', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (449, 12, N'Cho điểm A(1; 2; -1) và mặt phẳng (P): x + y + z = 0. Mặt phẳng (Q) đi qua A, song song với trục Ox và vuông góc với mặt phẳng (P). Phương trình của (Q) là:', N'y – z – 3 = 0', N'', N'y + z – 1 = 0', N'x + y – z – 4 = 0', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (450, 12, N'Trong không gian Oxyz, cho hai mặt phẳng (P): x + y + z – 2 = 0 và (Q): x + y + z – 6 = 0. Một mặt phẳng (R) song song và cách đều (P) và (Q). Phương trình của (R) là:', N'x + y + z – 8 = 0', N'', N'x + y + z + 2 = 0', N'x + y + z = 0', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (451, 12, N'Cho A và B là hai biến cố. Công thức P(B|A) biểu thị điều gì?', N'Xác suất để biến cố B xảy ra.', N'Xác suất để cả hai biến cố A và B cùng xảy ra.', N'', N'Xác suất để biến cố A xảy ra, với giả thiết biến cố B đã xảy ra.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (452, 12, N'Cho hai biến cố A và B với P(A) > 0. Công thức tính xác suất có điều kiện của B khi A đã xảy ra là:', N'P(B|A) = P(A ∩ B) * P(A)', N'P(B|A) = P(A) / P(A ∩ B)', N'P(B|A) = P(A ∩ B)', N'', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (453, 12, N'Gieo một con xúc xắc cân đối. Biết rằng mặt xuất hiện là mặt có số chấm chẵn. Tính xác suất để mặt xuất hiện là 6 chấm.', N'1/6', N'1/2', N'', N'2/3', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (454, 12, N'Cho P(A) = 0.5 và P(A ∩ B) = 0.2. Tính P(B|A).', N'0.1', N'0.25', N'', N'0.7', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (455, 12, N'Nếu A và B là hai biến cố độc lập và P(B) > 0 thì khẳng định nào sau đây là đúng?', N'P(A|B) = P(B)', N'P(A|B) = P(A) * P(B)', N'P(A|B) = 1 – P(A)', N'', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (456, 12, N'Cho P(A|B) = 0.7. Tính P(Ā|B), với Ā là biến cố đối của A.', N'0.7', N'0.5', N'', N'Không đủ dữ kiện để tính.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (457, 12, N'Trong một sơ đồ hình cây, xác suất trên các nhánh xuất phát từ một nút ở tầng thứ hai (không phải gốc) thể hiện loại xác suất nào?', N'Xác suất của biến cố hợp.', N'', N'Xác suất của biến cố giao.', N'Xác suất của biến cố độc lập.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (458, 12, N'Sử dụng công thức nhân xác suất, P(A ∩ B) bằng:', N'P(A) * P(B)', N'P(A) + P(B|A)', N'P(B) / P(A|B)', N'', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (459, 12, N'Một lớp học có 20 nam và 15 nữ. Chọn ngẫu nhiên một bạn. Biết rằng bạn được chọn là nữ, xác suất bạn đó có học lực giỏi là 1/5. Xác suất để chọn được một bạn nữ học lực giỏi là:', N'1/5', N'1/35', N'', N'15/35 + 1/5', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (460, 12, N'Một hộp chứa 3 bi xanh và 7 bi đỏ. Lấy lần lượt hai bi không hoàn lại. Biết rằng bi thứ nhất lấy ra là bi đỏ. Xác suất để bi thứ hai cũng là bi đỏ là:', N'7/10', N'6/10', N'', N'7/9', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (461, 12, N'Gieo hai con xúc xắc cân đối. Biết rằng tổng số chấm xuất hiện là 8. Xác suất để có ít nhất một con xúc xắc xuất hiện mặt 5 chấm là:', N'1/5', N'', N'1/6', N'1/3', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (462, 12, N'Một công ty có hai dây chuyền sản xuất. Dây chuyền I sản xuất 60% tổng sản phẩm và có tỷ lệ phế phẩm là 2%. Dây chuyền II sản xuất 40% tổng sản phẩm và có tỷ lệ phế phẩm là 3%. Lấy ngẫu nhiên một sản phẩm từ công ty. Xác suất để sản phẩm đó là phế phẩm được sản xuất bởi dây chuyền I là:', N'0.02', N'0.6 * 0.03', N'', N'0.012 + 0.012', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (463, 12, N'Trong một cuộc khảo sát, 70% khách hàng thích sản phẩm A. Trong số những người thích sản phẩm A, có 40% là nam. Biết rằng tỷ lệ khách hàng là nam trong cuộc khảo sát là 50%. Tính xác suất để một khách hàng nam được chọn ngãu nhiên sẽ thích sản phẩm A.', N'0.40', N'', N'0.7 * 0.4', N'0.5 * 0.4', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (464, 12, N'Một hộp có 5 sản phẩm tốt và 3 phế phẩm. Lấy ngẫu nhiên lần lượt 2 sản phẩm không hoàn lại. Xác suất để cả hai sản phẩm lấy ra đều tốt là:', N'(5/8)²', N'', N'5/8 + 4/7', N'1 – (3/8)*(2/7)', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (465, 12, N'Rút một lá bài từ bộ bài 52 lá. Biết rằng lá bài rút ra là lá màu đen (cơ hoặc chuồn), xác suất để lá bài đó là lá Át (Ace) là:', N'1/52', N'1/13', N'', N'2/13', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (466, 12, N'Một người có hai chiếc điện thoại. Xác suất để chiếc thứ nhất hết pin là 0.2, xác suất để chiếc thứ hai hết pin là 0.15. Biết rằng sự kiện hết pin của hai chiếc là độc lập. Nếu người đó thấy chiếc thứ nhất đã hết pin, xác suất chiếc thứ hai vẫn còn pin là:', N'0.15', N'0.8', N'', N'0.8 * 0.85', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (467, 12, N'Một hộp I chứa 2 bi xanh, 3 bi đỏ. Hộp II chứa 4 bi xanh, 1 bi đỏ. Lấy ngẫu nhiên một bi từ hộp I bỏ vào hộp II, rồi sau đó lấy ngẫu nhiên một bi từ hộp II. Xác suất để bi lấy ra từ hộp II là bi đỏ là:', N'1/6', N'1/5', N'(3/5)*(1/6) + (2/5)*(2/6)', N'', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (468, 12, N'Cho P(A) = 0.6, P(B) = 0.4 và P(A U B) = 0.8. Tính P(A|B).', N'0.2', N'', N'0.25', N'1/3', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (469, 12, N'Một bài thi trắc nghiệm có 2 câu. Xác suất làm đúng câu 1 là 0.8. Nếu làm đúng câu 1 thì xác suất làm đúng câu 2 là 0.9. Nếu làm sai câu 1 thì xác suất làm đúng câu 2 là 0.4. Xác suất để học sinh đó làm đúng cả 2 câu là:', N'0.9', N'', N'0.36', N'0.32', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (470, 12, N'Tỷ lệ người dân mắc bệnh tim ở một vùng là 5%. Trong số người mắc bệnh tim, tỷ lệ người hút thuốc là 80%. Trong số người không mắc bệnh tim, tỷ lệ người hút thuốc là 20%. Chọn ngẫu nhiên một người và thấy người đó hút thuốc. Xác suất người đó mắc bệnh tim là:', N'(0.05 * 0.8) / 0.2', N'', N'0.05 * 0.8', N'0.8', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (471, 12, N'Hai xạ thủ cùng bắn vào một mục tiêu. Xác suất trúng của người thứ nhất là 0.7. Xác suất trúng của người thứ hai là 0.8. Biết rằng mục tiêu bị trúng đạn, xác suất để đó là đạn của người thứ nhất là:', N'0.7', N'0.7 / 0.8', N'', N'0.7 / (0.7 + 0.8)', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (472, 12, N'Tung một đồng xu 3 lần. Biết rằng trong 3 lần tung có ít nhất một lần xuất hiện mặt ngửa, xác suất để cả 3 lần đều là mặt ngửa là:', N'1/8', N'', N'1/4', N'1/3', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (473, 12, N'Một lớp có 60% học sinh nam. Trong đó, 30% học sinh nam và 20% học sinh nữ học giỏi môn Toán. Chọn ngẫu nhiên một học sinh của lớp. Biết rằng học sinh đó học giỏi môn Toán, xác suất học sinh đó là nữ là:', N'0.2', N'(0.4 * 0.2) / 0.3', N'', N'0.4 * 0.2', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (474, 12, N'Có 2 chuồng thỏ. Chuồng 1 có 5 con trắng, 3 con nâu. Chuồng 2 có 4 con trắng, 4 con nâu. Bắt ngẫu nhiên 1 con từ chuồng 1 bỏ vào chuồng 2, rồi lại bắt ngẫu nhiên 1 con từ chuồng 2. Xác suất để con thỏ bắt ra từ chuồng 2 là thỏ trắng là:', N'5/9', N'4/9', N'', N'5/8 * 5/9', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (475, 12, N'Cho P(A|B) = 0.5, P(B) = 0.4, P(A) = 0.3. Tính P(B|A).', N'0.5', N'', N'3/4', N'0.4', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (476, 12, N'Gieo một cặp xúc xắc. Nếu tổng số chấm là 6, bạn thắng. Nếu không, bạn gieo lại. Biết rằng bạn đã thắng, xác suất để lần gieo đầu tiên có một mặt là 2 chấm là:', N'1/5', N'', N'1/6', N'2/36', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (477, 12, N'Một nhà máy có 3 máy sản xuất cùng một loại sản phẩm. Máy 1 sản xuất 25%, máy 2 sản xuất 35% và máy 3 sản xuất 40% tổng sản phẩm. Tỷ lệ sản phẩm lỗi của các máy lần lượt là 1%, 2% và 3%. Lấy ngẫu nhiên một sản phẩm và thấy nó bị lỗi. Xác suất sản phẩm đó do máy 1 sản xuất là:', N'0.01', N'0.25 * 0.01', N'(0.25 * 0.01) / (0.01 + 0.02 + 0.03)', N'', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (478, 12, N'Một gia đình có 2 người con. Một hôm bạn gặp người cha đi cùng một người con trai của ông ấy. Xác suất để người con còn lại cũng là con trai là:', N'1/4', N'', N'1/2', N'2/3', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (479, 12, N'Trong một trò chơi, bạn được chọn 1 trong 3 cánh cửa. Sau một cánh cửa là ô tô, hai cánh còn lại là con dê. Sau khi bạn chọn một cửa, người dẫn chương trình (biết cửa nào có ô tô) mở một trong hai cửa còn lại để lộ ra một con dê. Sau đó, họ hỏi bạn có muốn đổi cửa không. Biết rằng bạn đã chọn cửa 1 và người dẫn chương trình mở cửa 3 thấy con dê. Xác suất thắng nếu bạn đổi sang cửa 2 là:', N'1/3', N'1/2', N'', N'Không thay đổi so với xác suất ban đầu.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (480, 12, N'Có 3 tù nhân A, B, C bị kết án tử hình. Thống đốc ân xá cho một người trong số họ. Cai ngục biết người được ân xá là ai, nhưng không được tiết lộ. Tù nhân A hỏi cai ngục: “Hãy cho tôi biết tên một người bạn tù sẽ bị hành quyết, B hoặc C”. Cai ngục suy nghĩ và trả lời: “B sẽ bị hành quyết”. Biết rằng cai ngục nói thật, xác suất A được ân xá là:', N'1/3', N'', N'1/2', N'2/3', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (481, 17, N'Dòng điện xoay chiều là gì?', N'Là dòng điện có chiều không đổi và cường độ luôn tăng.', N'Là dòng điện có chiều và cường độ biến thiên điều hòa theo thời gian.', N'Là dòng điện có chiều biến đổi nhưng cường độ không đổi.', N'Là dòng điện chỉ thay đổi chiều một lần trong một chu kì.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (482, 17, N'Nguyên tắc tạo ra dòng điện xoay chiều dựa trên hiện tượng nào?', N'Hiện tượng tự cảm.', N'Hiện tượng cảm ứng điện từ.', N'Hiện tượng quang điện.', N'Hiện tượng nhiệt điện.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (483, 17, N'Đại lượng nào sau đây là giá trị tức thời của cường độ dòng điện xoay chiều?', N'I₀.', N'I.', N'i.', N'I/sqrt(2).', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (484, 17, N'Giá trị hiệu dụng của cường độ dòng điện xoay chiều I được xác định bằng công thức nào?', N'I = I₀.', N'I = I₀√2.', N'I = I₀/√2.', N'I = 2I₀.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (485, 17, N'Tần số góc ω trong biểu thức của dòng điện xoay chiều có đơn vị là gì?', N'Hertz (Hz).', N'Giây (s).', N'Radian (rad).', N'Radian/giây (rad/s).', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (486, 17, N'Khi nói về pha ban đầu của điện áp xoay chiều (φᵤ), nó có ý nghĩa gì?', N'Là giá trị cực đại của điện áp.', N'Là giá trị hiệu dụng của điện áp.', N'Là thông số xác định trạng thái ban đầu của điện áp tại thời điểm t=0.', N'Là tần số của điện áp.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (487, 17, N'Dòng điện xoay chiều có ưu thế nào so với dòng điện một chiều trong việc truyền tải điện năng đi xa?', N'Giảm tổn hao năng lượng trên đường dây truyền tải.', N'Tăng tốc độ truyền tải điện năng.', N'Giúp dễ dàng tích trữ năng lượng hơn.', N'Không cần sử dụng máy biến áp.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (488, 17, N'Công suất tỏa nhiệt tức thời trên điện trở R trong mạch điện xoay chiều được xác định bằng biểu thức nào?', N'P = RI₀².', N'P = R.i².', N'P = R.I².', N'P = R.u².', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (489, 17, N'Nam châm điện dùng trong công nghiệp có thể nâng các khối lượng lớn hoạt động dựa trên nguyên tắc nào?', N'Tạo ra từ trường xoáy rất mạnh.', N'Tương tác từ của dòng điện xoay chiều.', N'Nguyên lí hoạt động của động cơ điện.', N'Tạo ra điện trường biến thiên theo thời gian.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (490, 17, N'Trong quá trình truyền tải điện năng đi xa, máy biến áp có vai trò gì?', N'Giảm tần số của dòng điện để giảm tổn hao.', N'Tăng điện áp để giảm cường độ dòng điện, từ đó giảm hao phí.', N'Biến đổi dòng điện xoay chiều thành dòng điện một chiều.', N'Tăng cường độ dòng điện để đảm bảo đủ năng lượng.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (491, 17, N'Trong các thiết bị điện gia dụng như quạt điện, máy giặt, bếp từ, dòng điện xoay chiều được sử dụng để làm gì?', N'Chuyển hóa điện năng thành hóa năng.', N'Chuyển hóa điện năng thành cơ năng hoặc nhiệt năng.', N'Chuyển hóa điện năng thành quang năng.', N'Chỉ để chiếu sáng.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (492, 17, N'Khi mắc nối tiếp đồng hồ đo dòng điện (có bóng đèn dây tóc và khóa K mở) cần đo cường độ dòng điện trong mạch, thứ tự các bước để đọc được số trị là gì?', N'Đóng khóa K, điều chỉnh núm vặn, đọc trị số, ngắt khóa K.', N'Điều chỉnh núm vặn, đóng khóa K, đọc trị số, ngắt khóa K.', N'Đóng khóa K, đọc trị số, điều chỉnh núm vặn, ngắt khóa K.', N'Đọc trị số, đóng khóa K, điều chỉnh núm vặn, ngắt khóa K.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (493, 17, N'Quy tắc an toàn điện trong gia đình nào sau đây là quan trọng nhất?', N'Luôn sử dụng thiết bị điện đắt tiền.', N'Không chạm vào dụng cụ sử dụng điện khi tay ướt.', N'Tránh sử dụng thiết bị điện khi trời mưa.', N'Không kiểm tra hệ thống mạng điện thường xuyên.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (494, 17, N'Giá trị cực đại của cường độ dòng điện xoay chiều được kí hiệu là gì?', N'I.', N'I₀.', N'i.', N'U₀.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (495, 17, N'Suất điện động xoay chiều có biểu thức e = E₀cos(ωt + φₑ). Giá trị E₀ được gọi là gì?', N'Giá trị tức thời của suất điện động.', N'Giá trị hiệu dụng của suất điện động.', N'Giá trị cực đại của suất điện động.', N'Giá trị trung bình của suất điện động.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (496, 17, N'Một dòng điện xoay chiều có cường độ tức thời i = 2cos(100πt + π/2) (A). Giá trị cực đại của cường độ dòng điện là bao nhiêu?', N'2√2 A.', N'2 A.', N'√2 A.', N'100π A.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (497, 17, N'Một dòng điện xoay chiều có giá trị hiệu dụng I = √2 A. Giá trị cực đại của cường độ dòng điện là bao nhiêu?', N'1 A.', N'2 A.', N'√2 A.', N'2√2 A.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (498, 17, N'Một điện áp xoay chiều có giá trị cực đại U₀ = 220√2 V. Giá trị hiệu dụng của điện áp này là bao nhiêu?', N'220 V.', N'110 V.', N'440 V.', N'220√2 V.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (499, 17, N'Một mạch điện xoay chiều có tần số góc ω = 100π rad/s. Tần số (f) của dòng điện này là bao nhiêu?', N'50 Hz.', N'100 Hz.', N'200 Hz.', N'100π Hz.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (500, 17, N'Dòng điện xoay chiều có cường độ tức thời i = 4cos(50πt) (A). Chu kì của dòng điện này là bao nhiêu?', N'0,02 s.', N'0,04 s.', N'0,01 s.', N'0,08 s.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (501, 17, N'Một điện áp xoay chiều có biểu thức u = 100cos(100πt – π/6) (V). Giá trị hiệu dụng của điện áp là bao nhiêu?', N'100 V.', N'50 V.', N'100/√2 V.', N'50√2 V.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (502, 17, N'Dòng điện xoay chiều có cường độ hiệu dụng là 2 A và chu kì là 0,02 s. Pha ban đầu của dòng điện là 0. Biểu thức cường độ dòng điện xoay chiều là gì?', N'i = 2cos(100πt) (A).', N'i = 2√2cos(100πt) (A).', N'i = 2cos(50πt) (A).', N'i = √2cos(100πt) (A).', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (503, 17, N'Một mạch tạo sóng âm tần nổi ra được nối với một dao động kí điện tử để hiển thị mối liên hệ giữa cường độ của tín hiệu điện áp theo thời gian. Dựa vào hình ảnh quan sát được trên màn hình của dao động kí điện tử trong Hình 13P.2, hãy xác định tần số của dòng điện xoay chiều được tạo ra bởi mạch tạo sóng âm tần nổi trên. Biết mỗi ô trên trục hoành ứng với khoảng thời gian 0,5 ms.', N'1 kHz.', N'2 kHz.', N'500 Hz.', N'2,5 kHz.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (504, 17, N'Một dòng điện xoay chiều có biểu thức i = 3cos(ωt) (A). Trong thời gian 0,1 s, dòng điện tăng từ giá trị 0 A đến 3 A. Hãy tính tần số góc của dòng điện xoay chiều qua đoạn mạch.', N'5π rad/s.', N'10π rad/s.', N'15π rad/s.', N'20π rad/s.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (505, 17, N'Một mạch điện xoay chiều chỉ chứa điện trở R = 10 Ω. Điện áp tức thời hai đầu mạch là u = 100cos(100πt) (V). Cường độ dòng điện hiệu dụng qua mạch là bao nhiêu?', N'10 A.', N'5√2 A.', N'10/√2 A.', N'5 A.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (506, 17, N'Một điện áp xoay chiều có biểu thức u = U₀cos(ωt + π/3) (V) và cường độ dòng điện tức thời là i = I₀cos(ωt – π/6) (A). Độ lệch pha giữa điện áp và dòng điện là bao nhiêu?', N'π/6.', N'π/3.', N'π/2.', N'2π/3.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (507, 17, N'Một mạch điện xoay chiều có công suất tỏa nhiệt trung bình trên điện trở R trong một chu kì là 100 W. Nếu giá trị cực đại của dòng điện là 2 A, thì điện trở R của mạch là bao nhiêu?', N'25 Ω.', N'50 Ω.', N'100 Ω.', N'200 Ω.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (508, 17, N'Một máy phát điện xoay chiều tạo ra suất điện động có giá trị cực đại là E₀. Khi tần số quay của máy tăng gấp đôi, đồng thời số vòng dây của khung dây giảm đi một nửa, thì suất điện động cực đại mới sẽ là bao nhiêu?', N'E₀/2.', N'E₀.', N'2E₀.', N'4E₀.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (509, 17, N'Một dòng điện xoay chiều có biểu thức i = I₀cos(100πt + π/4) (A). Tại thời điểm t = 0,01 s, cường độ dòng điện tức thời là bao nhiêu?', N'I₀/√2 A.', N'-I₀/√2 A.', N'0 A.', N'I₀ A.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (510, 17, N'Một điện áp xoay chiều được tạo ra bởi máy phát điện xoay chiều gồm khung dây có N vòng dây, quay đều trong từ trường B với tốc độ góc ω. Suất điện động cực đại E₀ được tính bằng công thức E₀ = NBSω. Nếu tăng gấp đôi số vòng dây N và giảm một nửa tốc độ góc ω, giữ nguyên B và S, thì suất điện động cực đại mới sẽ là bao nhiêu?', N'E₀/2.', N'E₀.', N'2E₀.', N'4E₀.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (511, 18, N'Theo mô hình nguyên tử Rutherford, đặc điểm nào sau đây không đúng về nguyên tử?', N'Nguyên tử có hạt nhân rất nhỏ, mang điện tích dương và tập trung hầu hết khối lượng.', N'Các electron chuyển động xung quanh hạt nhân theo những quỹ đạo xác định và ổn định.', N'Phần lớn không gian bên trong nguyên tử là rỗng, nơi các electron di chuyển.', N'Điện tích dương của hạt nhân cân bằng với tổng điện tích âm của các electron.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (512, 18, N'Hạt nhân nguyên tử được cấu tạo từ những hạt cơ bản nào?', N'Chỉ gồm các proton mang điện tích dương.', N'Gồm các electron và neutron không mang điện.', N'Gồm các proton mang điện tích dương và các neutron không mang điện.', N'Gồm các electron và proton, không có hạt neutron.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (513, 18, N'Khái niệm đồng vị mô tả những hạt nhân có đặc điểm chung nào?', N'Có cùng số khối nhưng khác số proton.', N'Có cùng số neutron nhưng khác số proton.', N'Có cùng số proton nhưng khác số neutron.', N'Có cùng số proton và số neutron nhưng khác nhau về khối lượng.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (514, 18, N'Hệ thức Einstein E = mc² biểu thị mối quan hệ giữa những đại lượng vật lý nào?', N'Giữa năng lượng của một hạt và động lượng của nó trong chuyển động.', N'Giữa khối lượng và năng lượng của một vật, cho thấy chúng có thể chuyển hóa cho nhau.', N'Giữa vận tốc chuyển động của một vật và năng lượng của nó.', N'Giữa nhiệt độ của vật chất và năng lượng tiềm ẩn bên trong nó.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (515, 18, N'Năng lượng liên kết của hạt nhân là năng lượng gì?', N'Năng lượng tỏa ra khi một hạt nhân tự phân rã thành các hạt nhân nhẹ hơn.', N'Năng lượng tối thiểu cần cung cấp để phá vỡ hạt nhân thành các nucleon riêng rẽ.', N'Năng lượng động học của các nucleon khi chúng chuyển động trong hạt nhân.', N'Năng lượng hấp dẫn giữa các nucleon trong hạt nhân, giữ chúng lại với nhau.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (516, 18, N'Hạt nhân càng bền vững khi giá trị nào sau đây càng lớn?', N'Tổng khối lượng của các nucleon riêng rẽ cấu tạo nên hạt nhân.', N'Độ hụt khối của hạt nhân so với tổng khối lượng các nucleon.', N'Năng lượng liên kết riêng, tức là năng lượng liên kết tính trên mỗi nucleon.', N'Số khối (tổng số nucleon) của hạt nhân.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (517, 18, N'Trong một phản ứng hạt nhân, định luật bảo toàn nào sau đây không được áp dụng?', N'Định luật bảo toàn điện tích.', N'Định luật bảo toàn số khối (số nucleon).', N'Định luật bảo toàn động lượng.', N'Định luật bảo toàn khối lượng tuyệt đối.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (518, 18, N'Phản ứng phân hạch là quá trình gì trong vật lý hạt nhân?', N'Quá trình kết hợp của hai hay nhiều hạt nhân nhẹ để tạo thành hạt nhân nặng hơn.', N'Quá trình hạt nhân nặng bị vỡ thành các hạt nhân nhẹ hơn cùng với các neutron.', N'Quá trình tự phát phân rã của một hạt nhân không bền vững thành hạt nhân khác.', N'Quá trình một hạt nhân bị kích thích bởi tia gamma để biến đổi trạng thái.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (519, 18, N'Phản ứng nhiệt hạch là gì?', N'Là quá trình một hạt nhân nặng bị phân rã thành các hạt nhân nhẹ hơn, tỏa năng lượng.', N'Là quá trình các hạt nhân nhẹ kết hợp với nhau để tạo thành hạt nhân nặng hơn, tỏa năng lượng.', N'Là quá trình một hạt nhân phát ra tia phóng xạ alpha và biến đổi thành hạt nhân khác.', N'Là quá trình hấp thụ neutron của hạt nhân để trở nên bền vững hơn.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (520, 18, N'Điều kiện cần thiết để phản ứng nhiệt hạch xảy ra trên Trái Đất là gì?', N'Nhiệt độ rất thấp, gần 0 K, để các hạt nhân đứng yên và kết hợp.', N'Nhiệt độ cực cao (hàng triệu độ Kelvin) và mật độ hạt nhân rất lớn.', N'Áp suất khí quyển bình thường và nhiệt độ phòng để phản ứng diễn ra tự nhiên.', N'Sử dụng chất xúc tác đặc biệt để giảm năng lượng kích hoạt phản ứng.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (521, 18, N'Hiện tượng phóng xạ là gì?', N'Hiện tượng một vật phát ra ánh sáng khi bị nung nóng đến nhiệt độ cao.', N'Hiện tượng hạt nhân bền vững hấp thụ năng lượng và phát ra tia bức xạ.', N'Hiện tượng hạt nhân không bền vững tự phát phân rã và phát ra các tia phóng xạ.', N'Hiện tượng các electron bị bật ra khỏi bề mặt kim loại khi chiếu sáng.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (522, 18, N'Tia gamma (γ) có đặc điểm nổi bật nào trong các loại tia phóng xạ?', N'Là dòng hạt mang điện tích âm, có khả năng ion hóa mạnh nhất.', N'Là sóng điện từ có bước sóng rất ngắn, không mang điện tích và khả năng xuyên thấu rất mạnh.', N'Là dòng hạt nhân heli mang điện tích dương, có khả năng xuyên thấu yếu nhất.', N'Là dòng hạt neutron, không mang điện tích và có khả năng tương tác với vật chất rất yếu.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (523, 18, N'Chu kì bán rã của một chất phóng xạ là gì?', N'Là khoảng thời gian để số hạt nhân của chất phóng xạ giảm đi toàn bộ.', N'Là khoảng thời gian để số hạt nhân của một mẫu chất phóng xạ giảm đi một nửa.', N'Là khoảng thời gian cần thiết để một hạt nhân riêng lẻ phân rã.', N'Là khoảng thời gian mà hoạt độ phóng xạ của chất đó đạt giá trị cực đại.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (524, 18, N'Tác hại của các tia phóng xạ đối với cơ thể sống chủ yếu gây ra bởi hiện tượng nào?', N'Gây ra các phản ứng hóa học trực tiếp với các phân tử sinh học quan trọng.', N'Gây ra sự ion hóa các nguyên tử và phân tử trong tế bào, làm phá vỡ các liên kết hóa học.', N'Làm tăng nhiệt độ của các mô trong cơ thể, gây bỏng và hoại tử.', N'Gây ra lực cơ học tác dụng lên các tế bào, làm biến dạng chúng.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (525, 18, N'Để giảm thiểu tác hại của bức xạ từ một nguồn phóng xạ, quy tắc “ba an toàn” bao gồm những yếu tố nào?', N'Thời gian phơi nhiễm, loại chất phóng xạ và năng lượng của tia phóng xạ.', N'Thời gian phơi nhiễm, khoảng cách đến nguồn phóng xạ và che chắn phóng xạ.', N'Khối lượng nguồn phóng xạ, thể tích và nhiệt độ môi trường.', N'Áp suất, độ ẩm và cường độ từ trường xung quanh nguồn phóng xạ.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (526, 18, N'Hạt nhân của nguyên tử vàng (Au) có số hiệu nguyên tử Z = 79 và số khối A = 197. Số neutron trong hạt nhân vàng là bao nhiêu?', N'79.', N'118.', N'197.', N'276.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (527, 18, N'Tính độ hụt khối của hạt nhân heli (⁴₂He). Biết khối lượng proton (mₚ) là 1,007276 amu, khối lượng neutron (mₙ) là 1,008665 amu và khối lượng hạt nhân heli là 4,001505 amu.', N'0,030374 amu.', N'0,029374 amu.', N'0,031374 amu.', N'0,028374 amu.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (528, 18, N'Năng lượng liên kết của hạt nhân đơteri (²₁H) là 2,224 MeV. Tính độ hụt khối của hạt nhân này theo đơn vị amu. (Biết 1 amu tương ứng 931,5 MeV/c²).', N'0,002387 amu.', N'0,002377 amu.', N'0,002397 amu.', N'0,002407 amu.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (529, 18, N'Trong phản ứng hạt nhân ¹³₂₇Al + X → ¹⁴₂₇Si + ¹₀n, hạt nhân X là gì?', N'¹₁H (proton).', N'⁴₂He (hạt alpha).', N'²₁H (đơteri).', N'¹₀n (neutron).', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (530, 18, N'Một mẫu chất phóng xạ có số hạt nhân ban đầu là 8·10¹⁰ hạt. Sau 3 chu kì bán rã, số hạt nhân còn lại chưa phân rã là bao nhiêu?', N'1·10¹⁰ hạt.', N'2·10¹⁰ hạt.', N'4·10¹⁰ hạt.', N'6·10¹⁰ hạt.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (531, 18, N'Chu kì bán rã của đồng vị ¹³⁷₅₅Cs là 30 năm. Hằng số phóng xạ của đồng vị này là bao nhiêu? (Lấy ln2 ≈ 0,693).', N'0,0231 năm⁻¹.', N'0,0231 s⁻¹.', N'0,0231 ngày⁻¹.', N'0,0231 giờ⁻¹.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (532, 18, N'Bán kính hạt nhân của đồng vị ¹⁶₈O là r. Bán kính hạt nhân của đồng vị ⁴₀₂₀Ca là bao nhiêu so với r?', N'1,26 r.', N'1,36 r.', N'1,46 r.', N'1,56 r.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (533, 18, N'Năng lượng liên kết riêng của hạt nhân Heli (⁴₂He) là 7,07 MeV/nucleon. Tính năng lượng liên kết toàn phần của hạt nhân này.', N'14,14 MeV.', N'21,21 MeV.', N'28,28 MeV.', N'35,35 MeV.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (534, 18, N'Một phản ứng hạt nhân tỏa ra 180 MeV năng lượng. Nếu 1 kg Urani (²³⁵₉₂U) phân hạch hoàn toàn, thì tổng năng lượng tỏa ra là bao nhiêu? (Khối lượng mol của ²³⁵₉₂U là 235 g/mol , 1 MeV = 1,6·10⁻¹³ J).', N'7,33·10¹⁰ J.', N'7,33·10¹² J.', N'7,33·10¹³ J.', N'7,33·10¹⁵ J.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (535, 18, N'Một mẫu gỗ hóa thạch có hoạt độ phóng xạ của đồng vị ¹⁴₆C bằng 25% hoạt độ phóng xạ của đồng vị ¹⁴₆C trong gỗ mới. Chu kì bán rã của ¹⁴₆C là 5730 năm. Tuổi của mẫu gỗ hóa thạch là bao nhiêu?', N'5730 năm.', N'11460 năm.', N'17190 năm.', N'22920 năm.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (536, 18, N'Một nguồn phóng xạ có độ phóng xạ ban đầu là H₀. Sau 4 giờ, độ phóng xạ giảm xuống còn H₀/8. Chu kì bán rã của chất phóng xạ là bao nhiêu?', N'1 giờ.', N'1,5 giờ.', N'2 giờ.', N'1,33 giờ.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (537, 18, N'Một người làm việc trong môi trường có độ phóng xạ 0,2 mSv/giờ. Giới hạn liều chiếu xạ cho phép là 1 mSv/ngày. Hỏi người đó có thể làm việc tối đa bao nhiêu giờ mỗi ngày để đảm bảo an toàn?', N'2 giờ.', N'3 giờ.', N'4 giờ.', N'5 giờ.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (538, 18, N'Cho 3 hạt nhân X, Y, Z có số khối lần lượt là Aₓ, Aᵧ, A₂. Năng lượng liên kết riêng của chúng lần lượt là εₓ, εᵧ, ε₂. Nếu Aₓ < Aᵧ < A₂ và εₓ < ε₂ < εᵧ, thì khi phân hạch hạt nhân Y, năng lượng giải phóng là bao nhiêu?', N'(εᵧ – εₓ – ε₂)Aᵧ.', N'(εᵧ – ε₂)Aᵧ.', N'(εᵧ – εₓ)Aᵧ.', N'(εₓ + ε₂ – εᵧ)Aᵧ.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (539, 18, N'Một lò phản ứng hạt nhân có công suất 500 MW. Mỗi phản ứng phân hạch của Urani giải phóng 200 MeV. Hiệu suất của lò là 25%. Hỏi mỗi giờ lò tiêu thụ bao nhiêu kg Urani? (Khối lượng mol của ²³⁵₉₂U là 235 g/mol , 1 MeV = 1,6·10⁻¹³ J).', N'0,086 kg.', N'0,173 kg.', N'0,347 kg.', N'0,694 kg.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (540, 18, N'Một bệnh nhân được tiêm một liều thuốc phóng xạ có độ phóng xạ ban đầu là 100 µCi. Chu kì bán rã của đồng vị phóng xạ là 6 giờ. Hỏi sau 24 giờ, độ phóng xạ của liều thuốc còn lại trong cơ thể bệnh nhân là bao nhiêu µCi?', N'6,25 µCi.', N'12,5 µCi.', N'25 µCi.', N'50 µCi.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (541, 18, N'Từ trường là gì?', N'Là vùng không gian xung quanh điện tích đứng yên.', N'Là vùng không gian xung quanh dòng điện hoặc nam châm.', N'Là vùng không gian nơi các vật có khối lượng tương tác hấp dẫn.', N'Là vùng không gian nơi các vật nhiễm điện bị hút về tâm.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (542, 18, N'Lực từ là lực tương tác giữa những đối tượng nào?', N'Giữa hai điện tích đứng yên.', N'Giữa một điện tích đứng yên và một nam châm.', N'Giữa dòng điện và nam châm hoặc giữa các dòng điện.', N'Giữa các vật có khối lượng trong không gian.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (543, 18, N'Đặc điểm nào sau đây là đúng về đường sức từ?', N'Các đường sức từ luôn là những đường hở, không bao giờ khép kín.', N'Các đường sức từ không bao giờ cắt nhau và có chiều xác định.', N'Nơi nào đường sức từ thưa thì từ trường mạnh.', N'Chiều của đường sức từ luôn hướng từ cực Nam sang cực Bắc.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (544, 18, N'Khi đặt kim nam châm nhỏ tự do trong từ trường, kim nam châm sẽ định hướng như thế nào?', N'Theo phương vuông góc với đường sức từ.', N'Theo hướng của đường sức từ tại điểm đó.', N'Luôn hướng về phía Bắc địa lí.', N'Không định hướng rõ ràng nếu từ trường không đều.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (545, 18, N'Quy tắc nắm tay phải dùng để xác định đại lượng nào khi có dòng điện chạy qua dây dẫn thẳng?', N'Chiều của lực từ tác dụng lên dây dẫn.', N'Chiều của dòng điện trong dây dẫn.', N'Chiều của đường sức từ xung quanh dây dẫn.', N'Chiều của vectơ cảm ứng từ tại một điểm bất kì.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (546, 18, N'Cảm ứng từ B tại một điểm trong từ trường là đại lượng vật lí đặc trưng cho điều gì?', N'Hướng của từ trường và nhiệt độ tại điểm đó.', N'Độ lớn của từ trường và mật độ đường sức từ.', N'Phương và chiều của lực từ tác dụng lên dây dẫn mang dòng điện.', N'Hướng và độ lớn của lực từ tác dụng lên dây dẫn mang dòng điện.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (547, 18, N'Đơn vị của cảm ứng từ trong hệ SI là gì?', N'Newton (N).', N'Ampe (A).', N'Tesla (T).', N'Weber (Wb).', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (548, 18, N'Lực từ tác dụng lên đoạn dây dẫn mang dòng điện đặt trong từ trường đều được tính bằng biểu thức nào?', N'F = ILBsinα.', N'F = I/LBsinα.', N'F = (I+L+B)sinα.', N'F = ILB/sinα.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (549, 18, N'Khi đoạn dây dẫn mang dòng điện được đặt song song với đường sức từ, lực từ tác dụng lên đoạn dây đó sẽ có độ lớn bằng bao nhiêu?', N'Lực từ lớn nhất.', N'Lực từ bằng không.', N'Lực từ bằng một nửa giá trị lớn nhất.', N'Lực từ có chiều ngược lại.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (550, 18, N'Quy tắc bàn tay trái dùng để xác định đại lượng nào trong từ trường?', N'Chiều của dòng điện trong dây dẫn.', N'Chiều của cảm ứng từ.', N'Chiều của lực từ tác dụng lên dây dẫn mang dòng điện.', N'Chiều chuyển động của các hạt tích điện.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (551, 18, N'Cảm ứng từ tại tâm vòng dây tròn có N vòng dây và bán kính R mang dòng điện I tỉ lệ thuận với những đại lượng nào?', N'N và R, tỉ lệ nghịch với I.', N'N và I, tỉ lệ nghịch với R.', N'R và I, tỉ lệ nghịch với N.', N'N, I, R đều tỉ lệ thuận.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (552, 18, N'Cảm ứng từ bên trong ống dây có chiều dài L và N vòng dây mang dòng điện I tỉ lệ thuận với những đại lượng nào?', N'N và L, tỉ lệ nghịch với I.', N'N và I, tỉ lệ nghịch với L.', N'L và I, tỉ lệ nghịch với N.', N'N, I, L đều tỉ lệ thuận.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (553, 18, N'Nguyên lí chồng chất từ trường phát biểu rằng:', N'Cảm ứng từ tổng hợp tại một điểm là tích của các vectơ cảm ứng từ thành phần.', N'Cảm ứng từ tổng hợp tại một điểm là tổng đại số của các cảm ứng từ thành phần.', N'Cảm ứng từ tổng hợp tại một điểm là tổng vectơ của các cảm ứng từ thành phần.', N'Cảm ứng từ tổng hợp tại một điểm chỉ do nguồn từ mạnh nhất gây ra.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (554, 18, N'Thí nghiệm để đo độ lớn cảm ứng từ thường được thực hiện bằng cách đo lực từ tác dụng lên đại lượng nào?', N'Một nam châm vĩnh cửu.', N'Một điện tích đứng yên.', N'Một đoạn dây dẫn mang dòng điện.', N'Một chùm electron chuyển động.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (555, 18, N'Các đường sức từ của dòng điện chạy qua dây dẫn hình tròn có dạng hình gì?', N'Đường thẳng song song với mặt phẳng vòng dây.', N'Đường tròn đồng tâm với vòng dây và nằm trong mặt phẳng vuông góc với vòng dây.', N'Đường xoắn ốc quanh vòng dây.', N'Đường thẳng đi qua tâm vòng dây.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (556, 18, N'Một đoạn dây dẫn dài 10 cm mang dòng điện 4 A đặt trong từ trường đều có cảm ứng từ 0,5 T. Dây dẫn vuông góc với đường sức từ. Lực từ tác dụng lên dây dẫn là bao nhiêu?', N'0,1 N.', N'0,2 N.', N'0,3 N.', N'0,4 N.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (557, 18, N'Một đoạn dây dẫn dài 25 cm mang dòng điện 3 A đặt trong từ trường đều có cảm ứng từ 0,4 T. Dây dẫn hợp với đường sức từ một góc 30°. Lực từ tác dụng lên dây dẫn là bao nhiêu?', N'0,1 N.', N'0,15 N.', N'0,2 N.', N'0,25 N.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (558, 18, N'Cảm ứng từ tại tâm một vòng dây tròn có bán kính 2 cm, gồm 5 vòng dây mang dòng điện 1 A là bao nhiêu?', N'1,57·10⁻⁴ T.', N'3,14·10⁻⁴ T.', N'4,71·10⁻⁴ T.', N'6,28·10⁻⁴ T.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (559, 18, N'Một ống dây dài 10 cm có 500 vòng dây. Khi có dòng điện 0,2 A chạy qua ống dây, cảm ứng từ bên trong ống dây là bao nhiêu?', N'1,256·10⁻³ T.', N'1,256·10⁻² T.', N'6,28·10⁻⁴ T.', N'6,28·10⁻³ T.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (560, 18, N'Một điện tích q = 1,6·10⁻⁸ C chuyển động với vận tốc 2·10⁵ m/s vuông góc với từ trường đều có cảm ứng từ 0,2 T. Lực Lorentz tác dụng lên điện tích là bao nhiêu?', N'6,4·10⁻¹³ N.', N'3,2·10⁻¹³ N.', N'1,6·10⁻¹³ N.', N'1,28·10⁻¹² N.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (561, 18, N'Một thanh kim loại MN dài 0,5 m mang dòng điện 2 A đặt trong từ trường đều B. Lực từ tác dụng lên thanh là 0,4 N khi thanh vuông góc với B. Độ lớn cảm ứng từ B là bao nhiêu?', N'0,1 T.', N'0,2 T.', N'0,3 T.', N'0,4 T.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (562, 18, N'Một đoạn dây dẫn thẳng dài 20 cm mang dòng điện 5 A. Lực từ tác dụng lên dây dẫn là 0,2 N. Biết góc hợp bởi chiều dòng điện và cảm ứng từ là 30°. Độ lớn cảm ứng từ là bao nhiêu?', N'0,2 T.', N'0,4 T.', N'0,6 T.', N'0,8 T.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (563, 18, N'Hai dây dẫn thẳng dài vô hạn đặt song song, cách nhau 5 cm, mang hai dòng điện ngược chiều I₁ = 1 A và I₂ = 2 A. Lực tương tác trên mỗi mét chiều dài của hai dây dẫn là bao nhiêu?', N'4·10⁻⁶ N/m (lực hút).', N'8·10⁻⁶ N/m (lực hút).', N'4·10⁻⁶ N/m (lực đẩy).', N'8·10⁻⁶ N/m (lực đẩy).', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (564, 18, N'Một ống dây có N vòng dây, chiều dài L, mang dòng điện I. Cảm ứng từ bên trong ống dây là B. Nếu giảm số vòng dây đi một nửa và tăng chiều dài ống dây lên gấp đôi, giữ nguyên dòng điện, thì cảm ứng từ bên trong ống dây sẽ thay đổi như thế nào?', N'Giảm đi một nửa.', N'Giảm đi bốn lần.', N'Tăng gấp đôi.', N'Tăng gấp bốn lần.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (565, 18, N'Một điện tích q = 3·10⁻⁸ C chuyển động trong từ trường đều B = 0,4 T. Nếu vận tốc của điện tích hợp với đường sức từ một góc 60° và lực Lorentz tác dụng lên điện tích là 2,078·10⁻³ N, thì vận tốc của điện tích là bao nhiêu?', N'1·10⁵ m/s.', N'2·10⁵ m/s.', N'3·10⁵ m/s.', N'4·10⁵ m/s.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (566, 18, N'Hai cuộn dây dẫn hình tròn có cùng bán kính và cùng số vòng dây. Cuộn 1 mang dòng điện 2 A, cuộn 2 mang dòng điện 4 A. Cảm ứng từ tại tâm cuộn 2 so với tâm cuộn 1 là bao nhiêu?', N'Bằng nhau.', N'Gấp đôi.', N'Gấp bốn lần.', N'Bằng một nửa.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (567, 18, N'Một điện tích q = -4·10⁻⁸ C chuyển động với vận tốc 5·10⁵ m/s theo phương ngang từ trái sang phải vào một vùng có từ trường đều B = 0,5 T hướng thẳng đứng lên. Chiều của lực Lorentz tác dụng lên điện tích là gì?', N'Hướng lên trên.', N'Hướng xuống dưới.', N'Hướng vào trong mặt phẳng.', N'Hướng ra khỏi mặt phẳng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (568, 18, N'Một thanh kim loại AB dài 1 m, khối lượng 0,1 kg, đặt nằm ngang trên hai thanh ray song song và cách nhau 1 m trong từ trường đều B = 0,5 T hướng thẳng đứng xuống. Hệ số ma sát giữa thanh kim loại và ray là 0,2. Cường độ dòng điện tối thiểu cần chạy qua thanh để nó bắt đầu chuyển động là bao nhiêu?', N'0,4 A.', N'0,8 A.', N'1,0 A.', N'1,2 A.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (569, 18, N'Một điện tích q = 1,6·10⁻¹⁹ C được gia tốc bởi hiệu điện thế U = 1000 V rồi bay vào từ trường đều B = 0,1 T theo phương vuông góc với đường sức từ. Bán kính quỹ đạo chuyển động của điện tích là 10 cm. Khối lượng của điện tích là bao nhiêu? (Bỏ qua trọng lực).', N'3,2·10⁻²⁷ kg.', N'1,6·10⁻²⁷ kg.', N'6,4·10⁻²⁷ kg.', N'4,8·10⁻²⁷ kg.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (570, 18, N'Hai dây dẫn thẳng dài vô hạn đặt song song, cách nhau 10 cm, mang hai dòng điện cùng chiều I₁ = 5 A và I₂ = 10 A. Cảm ứng từ tổng hợp tại điểm M nằm trên mặt phẳng chứa hai dây dẫn và cách dây I₁ 5 cm, cách dây I₂ 5 cm là bao nhiêu?', N'0 T.', N'2·10⁻⁵ T.', N'4·10⁻⁵ T.', N'6·10⁻⁵ T.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (571, 18, N'Chuyển động Brown của các hạt trong chất lỏng hoặc chất khí có đặc điểm nào sau đây?', N'Là chuyển động có quỹ đạo cố định và theo một hướng xác định.', N'Là chuyển động thẳng đều, chỉ bị thay đổi khi có ngoại lực tác dụng.', N'Là chuyển động hỗn loạn, không ngừng, với quỹ đạo là những đường gấp khúc bất kì.', N'Là chuyển động tuần hoàn, lặp lại theo một chu kì nhất định.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (572, 18, N'Điều nào sau đây không phải là tính chất cơ bản của chất khí?', N'Có hình dạng và thể tích xác định.', N'Có khối lượng riêng nhỏ hơn nhiều so với chất lỏng và chất rắn.', N'Rất dễ bị nén.', N'Gây ra áp suất lên thành bình chứa.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (573, 18, N'Khi nhiệt độ của một khối khí tăng lên, điều gì xảy ra với chuyển động của các phân tử khí?', N'Các phân tử khí chuyển động chậm lại và ít va chạm hơn.', N'Các phân tử khí chuyển động nhanh hơn và va chạm mạnh hơn.', N'Các phân tử khí ngừng chuyển động hoàn toàn.', N'Các phân tử khí chuyển động theo một hướng có trật tự hơn.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (574, 18, N'Đơn vị đo lượng chất trong hệ SI là gì và được định nghĩa dựa trên cơ sở nào?', N'Kilogam, dựa trên khối lượng chuẩn.', N'Mol, dựa trên số phân tử hoặc nguyên tử bằng số Avogadro.', N'Mét, dựa trên khoảng cách ánh sáng đi được trong một khoảng thời gian.', N'Ampe, dựa trên lực tương tác giữa hai dòng điện.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (575, 18, N'Quá trình đẳng nhiệt của một khối lượng khí xác định là quá trình biến đổi trạng thái trong đó đại lượng nào được giữ không đổi?', N'Áp suất.', N'Thể tích.', N'Nhiệt độ tuyệt đối.', N'Khối lượng riêng.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (576, 18, N'Định luật Boyle phát biểu về mối liên hệ giữa áp suất và thể tích của một khối lượng khí xác định khi nhiệt độ không đổi như thế nào?', N'Áp suất tỉ lệ thuận với thể tích.', N'Áp suất tỉ lệ nghịch với thể tích.', N'Tích của áp suất và thể tích là một hằng số.', N'Tổng của áp suất và thể tích là một hằng số.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (577, 18, N'Đồ thị biểu diễn mối liên hệ giữa thể tích (V) và nhiệt độ tuyệt đối (T) của một khối khí trong quá trình đẳng áp có dạng hình gì?', N'Đường hypebol.', N'Đường parabol.', N'Đường thẳng đi qua gốc tọa độ.', N'Đường thẳng song song với trục hoành.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (578, 18, N'Định luật Dalton về áp suất riêng phần phát biểu điều gì về áp suất toàn phần của hỗn hợp khí không phản ứng hóa học?', N'Áp suất toàn phần bằng tích các áp suất riêng phần.', N'Áp suất toàn phần bằng tổng các áp suất riêng phần của các khí thành phần.', N'Áp suất toàn phần chỉ phụ thuộc vào khí có áp suất riêng phần lớn nhất.', N'Áp suất toàn phần luôn nhỏ hơn áp suất riêng phần của từng khí.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (579, 18, N'Phương trình trạng thái của khí lí tưởng được thiết lập từ sự kết hợp của những định luật nào?', N'Định luật Boyle và Định luật Charles.', N'Định luật Newton và Định luật Boyle.', N'Định luật Ohm và Định luật Charles.', N'Định luật Faraday và Định luật Lenz.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (580, 18, N'Hằng số khí lí tưởng R trong phương trình pV = nRT có giá trị xấp xỉ là bao nhiêu?', N'1,013·10⁵ J/(mol·K).', N'8,31 J/(mol·K).', N'6,02·10²³ J/(mol·K).', N'273 J/(mol·K).', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (581, 18, N'Quá trình đẳng tích của một khối lượng khí lí tưởng là quá trình biến đổi trạng thái trong đó đại lượng nào được giữ không đổi?', N'Áp suất.', N'Nhiệt độ tuyệt đối.', N'Thể tích.', N'Khối lượng mol.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (582, 18, N'Đồ thị biểu diễn mối liên hệ giữa áp suất (P) và nhiệt độ tuyệt đối (T) của một khối khí trong quá trình đẳng tích có dạng hình gì?', N'Đường thẳng đi qua gốc tọa độ.', N'Đường hypebol.', N'Đường parabol.', N'Đường tròn.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (583, 18, N'Áp suất của chất khí tác dụng lên thành bình chứa có nguyên nhân trực tiếp từ đâu?', N'Lực hấp dẫn giữa các phân tử khí và thành bình.', N'Lực tương tác tĩnh điện giữa các phân tử khí.', N'Sự va chạm của các phân tử khí đang chuyển động với thành bình.', N'Trọng lượng của khối khí đặt trong bình.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (584, 18, N'Động năng tịnh tiến trung bình của các phân tử khí tỉ lệ thuận với đại lượng nào của khối khí?', N'Thể tích.', N'Áp suất.', N'Khối lượng riêng.', N'Nhiệt độ tuyệt đối.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (585, 18, N'Nội năng của một khối lượng khí lí tưởng xác định phụ thuộc vào yếu tố nào?', N'Chỉ phụ thuộc vào áp suất và thể tích.', N'Chỉ phụ thuộc vào nhiệt độ.', N'Chỉ phụ thuộc vào khối lượng riêng.', N'Phụ thuộc vào cả áp suất, thể tích và nhiệt độ.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (586, 18, N'Có 0,5 mol khí cacbonic (CO₂). Hỏi có bao nhiêu phân tử khí CO₂ trong lượng chất này?', N'3,01·10²³ phân tử.', N'6,02·10²³ phân tử.', N'1,5·10²³ phân tử.', N'1,204·10²⁴ phân tử.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (587, 18, N'Một khối khí có thể tích 8 lít ở áp suất 2·10⁵ Pa. Nếu nén đẳng nhiệt khối khí đó để áp suất tăng lên 4·10⁵ Pa, thì thể tích của khối khí lúc này là bao nhiêu?', N'2 lít.', N'4 lít.', N'8 lít.', N'16 lít.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (588, 18, N'Một khối khí có thể tích 12 lít ở 27°C và áp suất không đổi. Nếu nung nóng khối khí đó đến 127°C, thì thể tích của khối khí sẽ là bao nhiêu?', N'16 lít.', N'13,3 lít.', N'15 lít.', N'10 lít.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (589, 18, N'Một bình kín chứa khí ở áp suất 1,5 atm và nhiệt độ 300 K. Nếu nhiệt độ của khí tăng lên 400 K mà thể tích không đổi, thì áp suất của khí trong bình là bao nhiêu?', N'1,0 atm.', N'2,0 atm.', N'1,75 atm.', N'2,25 atm.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (590, 18, N'Một khối khí lý tưởng có nhiệt độ 27°C. Động năng tịnh tiến trung bình của các phân tử khí này là bao nhiêu? (k = 1,38·10⁻²³ J/K)', N'6,21·10⁻²¹ J.', N'5,66·10⁻²¹ J.', N'4,14·10⁻²¹ J.', N'8,31·10⁻²¹ J.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (591, 18, N'Một khối khí lí tưởng có số mol là 0,2 mol ở nhiệt độ 300 K. Tính nội năng của khối khí này (coi là khí đơn nguyên tử). (R = 8,31 J/(mol·K))', N'747,9 J.', N'997,2 J.', N'1246,5 J.', N'1495,8 J.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (592, 18, N'Một khối khí có thể tích ban đầu 6 lít ở áp suất 2·10⁵ Pa. Nếu khí bị nén đẳng nhiệt sao cho áp suất tăng thêm 1·10⁵ Pa, thì thể tích của khí sau khi nén là bao nhiêu?', N'3 lít.', N'4 lít.', N'5 lít.', N'6 lít.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (593, 18, N'Một khối khí lí tưởng có 3,01·10²³ phân tử. Nếu khối lượng mol của khí là 28 g/mol, thì khối lượng của khối khí này là bao nhiêu?', N'7 g.', N'14 g.', N'28 g.', N'56 g.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (594, 18, N'Một lượng khí lý tưởng ở 27°C có áp suất 1 atm và thể tích 10 lít. Vì nén nhanh nên khí bị nóng lên đến 60°C. Áp suất khối khí sau khi nén là 2,78 atm. Hỏi thể tích khối khí sau khi nén là bao nhiêu?', N'4 lít.', N'5 lít.', N'6 lít.', N'7 lít.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (595, 18, N'Một bình kín chứa khí ở áp suất 2·10⁵ Pa và nhiệt độ 300 K. Nếu nhiệt độ tăng lên 450 K, đồng thời 1/4 lượng khí bị thoát ra ngoài, thì áp suất của khí trong bình là bao nhiêu?', N'1,5·10⁵ Pa.', N'2,0·10⁵ Pa.', N'2,25·10⁵ Pa.', N'2,5·10⁵ Pa.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (596, 18, N'Một ống nghiệm chứa không khí bị ngăn cách bởi một giọt thủy ngân dài 10 cm. Ở 0°C giọt thủy ngân đang ở vị trí cách đáy ống A 30 cm. Tính khoảng cách từ đáy ống A đến giọt thủy ngân khi nung nóng bình đến 29°C. Coi tiết diện bình là không đổi và áp suất không đổi.', N'30,5 cm.', N'31,1 cm.', N'32,5 cm.', N'33,2 cm.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (597, 18, N'Một khối khí lý tưởng có thể tích 5 lít ở 27°C và áp suất 2 atm. Sau khi biến đổi trạng thái, khí có thể tích 6 lít và nhiệt độ 77°C. Áp suất của khí sau biến đổi là bao nhiêu?', N'2,0 atm.', N'2,2 atm.', N'2,5 atm.', N'2,8 atm.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (598, 18, N'Một quả bóng bay có thể tích 3 lít chứa khí heli ở nhiệt độ 27°C và áp suất 1 atm. Nếu quả bóng bay được đưa lên độ cao mà nhiệt độ là −23°C và áp suất là 0,6 atm, thì thể tích của khí heli trong quả bóng bay lúc này là bao nhiêu?', N'4,17 lít.', N'4,5 lít.', N'4,83 lít.', N'5 lít.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (599, 18, N'Một bình kín có thể tích 10 lít chứa khí ở 27°C và áp suất 2,0·10⁵ Pa. Người ta muốn tăng áp suất của khí lên gấp 2,5 lần mà vẫn giữ nguyên thể tích bình. Hỏi nhiệt độ của khí lúc này phải là bao nhiêu độ C?', N'477°C.', N'527°C.', N'600°C.', N'750°C.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (600, 18, N'Một khối khí lí tưởng có khối lượng riêng ban đầu là ρ₁. Sau khi biến đổi trạng thái, nhiệt độ tăng gấp 1,5 lần (theo K) và áp suất tăng gấp 2 lần. Hỏi khối lượng riêng của khí sau biến đổi là bao nhiêu?', N'2ρ₁/3.', N'4ρ₁/3.', N'3ρ₁/2.', N'2ρ₁.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (601, 18, N'Đặc điểm nào sau đây không đúng về mô hình động học phân tử chất khí?', N'Các phân tử có kích thước rất nhỏ so với khoảng cách giữa chúng.', N'Các phân tử luôn chuyển động hỗn loạn không ngừng theo mọi hướng.', N'Lực tương tác giữa các phân tử khí rất mạnh, có thể làm thay đổi quỹ đạo.', N'Động năng chuyển động của các phân tử tăng khi nhiệt độ của khí tăng.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (602, 18, N'Khi một chất rắn kết tinh đang nóng chảy, điều gì xảy ra nếu vẫn tiếp tục cung cấp nhiệt?', N'Nhiệt độ của chất rắn sẽ tiếp tục tăng cho đến khi nóng chảy hoàn toàn.', N'Nhiệt độ của hỗn hợp rắn-lỏng duy trì không đổi trong suốt quá trình nóng chảy.', N'Chất rắn sẽ chuyển sang thể lỏng ngay lập tức mà không có giai đoạn chuyển tiếp.', N'Chất rắn sẽ mềm dần rồi chuyển sang lỏng với nhiệt độ thay đổi liên tục.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (603, 18, N'Yếu tố nào sau đây sẽ làm tăng tốc độ bay hơi của một chất lỏng?', N'Giảm diện tích bề mặt tiếp xúc của chất lỏng với không khí.', N'Giảm nhiệt độ của môi trường xung quanh chất lỏng.', N'Tăng độ ẩm của không khí ngay phía trên bề mặt chất lỏng.', N'Tăng tốc độ gió thổi qua bề mặt của chất lỏng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (604, 18, N'Sự sôi khác với sự bay hơi ở điểm nào là cơ bản nhất?', N'Sự sôi chỉ xảy ra trên bề mặt chất lỏng, còn bay hơi xảy ra trong lòng chất lỏng.', N'Sự sôi diễn ra ở mọi nhiệt độ, còn bay hơi chỉ xảy ra ở nhiệt độ xác định.', N'Sự sôi xảy ra đồng thời trong lòng và trên bề mặt chất lỏng ở nhiệt độ xác định.', N'Sự sôi là quá trình chuyển thể từ lỏng sang rắn, còn bay hơi là từ lỏng sang khí.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (605, 18, N'Hiện tượng thăng hoa là quá trình chuyển thể trực tiếp từ trạng thái nào sang trạng thái nào?', N'Từ thể lỏng sang thể khí không qua thể rắn.', N'Từ thể rắn sang thể lỏng không qua thể khí.', N'Từ thể rắn sang thể khí mà không qua thể lỏng.', N'Từ thể khí sang thể rắn mà không qua thể lỏng.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (606, 18, N'Khi hai vật có nhiệt độ khác nhau tiếp xúc nhau, năng lượng nhiệt sẽ được truyền như thế nào?', N'Từ vật có khối lượng lớn hơn sang vật có khối lượng nhỏ hơn.', N'Từ vật có nhiệt độ thấp hơn sang vật có nhiệt độ cao hơn.', N'Từ vật có nhiệt độ cao hơn sang vật có nhiệt độ thấp hơn.', N'Từ vật có thể tích lớn hơn sang vật có thể tích nhỏ hơn.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (607, 18, N'Nguyên lý cơ bản để đo nhiệt độ của một vật là dựa vào sự thay đổi của đại lượng nào?', N'Màu sắc của vật khi bị nung nóng hoặc làm lạnh.', N'Khối lượng của vật khi nhiệt độ của vật thay đổi.', N'Một đại lượng vật lí của vật phụ thuộc vào nhiệt độ.', N'Độ dẫn điện của vật khi bị tác dụng bởi nhiệt.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (608, 18, N'Điểm 0 K trong thang nhiệt độ Kelvin được gọi là nhiệt độ tuyệt đối và có ý nghĩa vật lí gì?', N'Là nhiệt độ mà tại đó nước đóng băng hoàn toàn không còn chuyển động.', N'Là nhiệt độ mà tại đó mọi vật chất đạt đến trạng thái siêu dẫn.', N'Là nhiệt độ mà tại đó động năng chuyển động nhiệt của các phân tử bằng không.', N'Là nhiệt độ mà tại đó thể tích của mọi chất khí bằng không lý tưởng.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (609, 18, N'Điểm ba của nước được định nghĩa là nhiệt độ và áp suất mà tại đó nước tồn tại đồng thời ở những trạng thái nào?', N'Chỉ ở trạng thái lỏng và khí.', N'Chỉ ở trạng thái rắn và lỏng.', N'Cả ba trạng thái rắn, lỏng, khí cùng tồn tại cân bằng.', N'Chỉ ở trạng thái rắn và khí, không qua trạng thái lỏng.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (610, 18, N'Khi so sánh thang nhiệt độ Celsius và Kelvin, phát biểu nào sau đây là đúng?', N'Một khoảng chia trên thang Celsius có độ lớn gấp đôi một khoảng chia trên thang Kelvin.', N'Một khoảng chia trên thang Kelvin có độ lớn bằng một khoảng chia trên thang Celsius.', N'Nhiệt độ 0°C tương ứng với 0 K trên thang nhiệt độ Kelvin.', N'Nhiệt độ âm không tồn tại trên thang Kelvin nhưng có trên thang Celsius.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (611, 18, N'Nội năng của một vật là tổng của những loại năng lượng nào của các phân tử cấu tạo nên vật?', N'Chỉ tổng động năng chuyển động nhiệt của các phân tử.', N'Chỉ tổng thế năng tương tác giữa các phân tử với nhau.', N'Tổng động năng và thế năng tương tác của các phân tử.', N'Tổng năng lượng điện và năng lượng từ trường bên trong vật.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (612, 18, N'Nội năng của một khối khí lý tưởng phụ thuộc vào những yếu tố nào?', N'Chỉ phụ thuộc vào áp suất và khối lượng của khí.', N'Phụ thuộc vào nhiệt độ và thể tích của khối khí.', N'Chỉ phụ thuộc vào khối lượng riêng của khối khí.', N'Phụ thuộc vào loại khí và màu sắc của khối khí.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (613, 18, N'Có mấy cách để làm thay đổi nội năng của một vật và đó là những cách nào?', N'Một cách duy nhất là truyền nhiệt từ vật nóng sang vật lạnh.', N'Hai cách là thực hiện công và truyền nhiệt.', N'Ba cách là thực hiện công, truyền nhiệt và biến đổi hóa học.', N'Bốn cách là thực hiện công, truyền nhiệt, trao đổi vật chất và bức xạ.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (614, 18, N'Trong định luật 1 nhiệt động lực học (ΔU = A + Q), khi vật thực hiện công lên môi trường xung quanh, thì dấu của công (A) được quy ước như thế nào?', N'A > 0.', N'A < 0.', N'A = 0.', N'A có thể âm hoặc dương tùy thuộc vào nhiệt độ.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (615, 18, N'Khi một khối khí thực hiện một chu trình kín, điều nào sau đây là đúng về độ biến thiên nội năng của khối khí?', N'Độ biến thiên nội năng luôn dương.', N'Độ biến thiên nội năng luôn âm.', N'Độ biến thiên nội năng bằng không.', N'Độ biến thiên nội năng thay đổi tùy thuộc vào công và nhiệt.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (616, 18, N'Để nung chảy hoàn toàn 0,5 kg sắt ở nhiệt độ nóng chảy, cần cung cấp một nhiệt lượng là bao nhiêu? Biết nhiệt nóng chảy riêng của sắt là 2,77·10⁵ J/kg.', N'1,385·10⁵ J.', N'2,77·10⁵ J.', N'5,54·10⁵ J.', N'0,6925·10⁵ J.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (617, 18, N'Để hóa hơi hoàn toàn 0,2 kg nước đang ở 100°C, cần cung cấp một nhiệt lượng là 4,6·10⁵ J. Hỏi nhiệt hóa hơi riêng của nước là bao nhiêu?', N'2,3·10⁶ J/kg.', N'4,6·10⁶ J/kg.', N'0,2·10⁶ J/kg.', N'0,46·10⁶ J/kg.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (618, 18, N'Nhiệt độ cơ thể người bình thường là 37°C. Nhiệt độ này tương ứng với bao nhiêu Kelvin?', N'300 K.', N'310 K.', N'313 K.', N'317 K.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (619, 18, N'Nhiệt độ của một khí là 400 K. Nhiệt độ này tương ứng với bao nhiêu độ Celsius?', N'127°C.', N'100°C.', N'150°C.', N'173°C.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (620, 18, N'Để làm nóng 0,5 kg đồng từ 20°C lên 120°C, cần cung cấp một nhiệt lượng là bao nhiêu? Biết nhiệt dung riêng của đồng là 380 J/(kg·K).', N'19000 J.', N'38000 J.', N'48000 J.', N'29000 J.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (621, 18, N'Một hệ nhận công 300 J từ môi trường và truyền nhiệt lượng 100 J cho môi trường. Độ biến thiên nội năng của hệ là bao nhiêu?', N'200 J.', N'400 J.', N'-200 J.', N'-400 J.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (622, 18, N'Một khối nước đá có khối lượng 100 g đang ở 0°C. Để chuyển toàn bộ khối nước đá này thành nước lỏng ở 50°C, cần cung cấp tổng cộng bao nhiêu nhiệt lượng? (λđá = 3,34·10⁵ J/kg; c_nước = 4200 J/(kg·K))', N'33400 J.', N'21000 J.', N'54400 J.', N'64400 J.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (623, 18, N'Để hóa hơi hoàn toàn 0,1 kg rượu ở 78°C và nung nóng lượng rượu đó từ 20°C đến 78°C, cần tổng nhiệt lượng bao nhiêu? (c = 2500 J/(kg·K); L = 0,84·10⁶ J/kg)', N'84000 J.', N'14500 J.', N'98500 J.', N'102500 J.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (624, 18, N'Trong các giá trị nhiệt độ sau, giá trị nào là cao nhất?', N'60°C.', N'320 K.', N'140°F.', N'35°C.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (625, 18, N'Nhiệt độ của một chất thay đổi từ 25°C lên 75°C. Hỏi độ tăng nhiệt độ này tương ứng với bao nhiêu độ Kelvin?', N'25 K.', N'50 K.', N'75 K.', N'100 K.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (626, 18, N'Một khối khí bị nén, nhận công 500 J. Đồng thời, khối khí tỏa nhiệt lượng 200 J ra môi trường. Độ biến thiên nội năng của khối khí là bao nhiêu?', N'300 J.', N'700 J.', N'-300 J.', N'-700 J.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (627, 18, N'Nội năng của một vật giảm 150 J. Biết rằng vật đã truyền 50 J nhiệt lượng ra môi trường. Hỏi vật đã thực hiện công hay nhận công là bao nhiêu?', N'Vật nhận công 100 J.', N'Vật thực hiện công 100 J.', N'Vật nhận công 200 J.', N'Vật thực hiện công 200 J.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (628, 18, N'Thả 200 g nước đá ở 0°C vào 500 g nước ở 50°C (bỏ qua trao đổi nhiệt với môi trường). Nhiệt độ cuối cùng của hệ là bao nhiêu? (λđá = 3,34·10⁵ J/kg; c_nước = 4200 J/(kg·K))', N'0°C (nước đá chưa tan hết).', N'0°C (nước đá tan hết).', N'10°C.', N'13°C.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (629, 18, N'Một ấm điện công suất 1200 W đun 1,5 lít nước từ 20°C đến 100°C, hiệu suất 80%. Thời gian cần để nước sôi là bao lâu? (ρ_nước = 1 kg/lít; c = 4200 J/(kg·K))', N'6 phút 30 giây.', N'7 phút 10 giây.', N'8 phút 45 giây.', N'9 phút 20 giây.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (630, 18, N'Một khối khí lý tưởng có nội năng ban đầu 2000 J. Khối khí nhận 400 J nhiệt lượng và dãn nở thực hiện công 150 J. Nội năng cuối cùng là bao nhiêu?', N'2250 J.', N'2400 J.', N'2650 J.', N'2800 J.', N'A', NULL);
