INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (691, 24, N'Sự kiện nào đánh dấu trật tự hai cực Ianta sụp đổ hoàn toàn?', N'Cuộc gặp gỡ Busơ – Goócbachốp tại đảo Manta (12/1989).', N'Bức tường Béc-lin ở Đức bị phá vỡ (11/1989).', N'Hiệp ước Vác-sa-va và khối SEV chính thức giải thể (1991).', N'Chế độ XHCN tại Liên Xô sụp đổ hoàn toàn (12/1991).', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (692, 24, N'Xu thế chính trong quan hệ quốc tế sau khi Chiến tranh lạnh kết thúc là gì?', N'Hình thành một thế giới đơn cực do Mỹ chi phối.', N'Hòa bình, hợp tác và cùng phát triển.', N'Sự đối đầu gay gắt giữa các quốc gia, cường quốc.', N'Xuất hiện nhiều cuộc chiến tranh thế giới mới.', N'A', NULL);
