INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (694, 24, N'Sau khi Liên Xô tan rã, Mỹ đã theo đuổi mục tiêu chiến lược nào?', N'Hợp tác toàn diện với Liên bang Nga.', N'Thiết lập trật tự thế giới “đơn cực” do Mỹ chi phối.', N'Ủng hộ các nước xã hội chủ nghĩa còn lại.', N'Rút khỏi các cam kết quốc tế, lo việc nội bộ.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (695, 24, N'Sau Chiến tranh lạnh, hầu hết các quốc gia đều điều chỉnh chiến lược, lấy yếu tố nào làm trọng điểm?', N'Quân sự, chính trị', N'Kinh tế', N'Văn hóa, tư tưởng', N'Mở rộng lãnh thổ', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (696, 24, N'Đặc điểm nổi bật trong quan hệ quốc tế sau Chiến tranh lạnh là gì?', N'Chỉ có hợp tác, không có đấu tranh.', N'Các nước lớn hoàn toàn đối đầu nhau.', N'Các quốc gia vừa hợp tác, vừa cạnh tranh, đấu tranh.', N'Hình thành các liên minh quân sự mới.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (697, 24, N'Dù hòa bình là xu thế chủ đạo, nhưng sau Chiến tranh lạnh, thế giới vẫn phải đối mặt với tình hình nào?', N'Nguy cơ một cuộc chiến tranh thế giới mới.', N'Xung đột vũ trang, nội chiến, tranh chấp lãnh thổ ở nhiều nơi.', N'Các quốc gia thực hiện chính sách đóng cửa.', N'Sự sụp đổ hàng loạt của các quốc gia.', N'A', NULL);
