INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (699, 24, N'Sau Chiến tranh lạnh, Liên bang Nga trong những năm 1991-1993 đã theo đuổi chính sách đối ngoại nào?', N'Khôi phục lại Liên bang Xô viết.', N'“Ngả về phương Tây”, tìm kiếm ủng hộ chính trị và viện trợ.', N'Thực hiện chính sách “cân bằng” Đông – Tây.', N'Ưu tiên phát triển quan hệ với các nước châu Á.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (700, 24, N'Từ năm 1994, chính sách đối ngoại của Liên bang Nga có sự điều chỉnh như thế nào?', N'Tiếp tục chính sách hoàn toàn “ngả về phương Tây”.', N'Chỉ quan hệ với các nước thuộc Liên Xô cũ.', N'Chuyển sang định hướng “Âu – Á”, coi trọng cả hai phía.', N'Cắt đứt quan hệ với Mỹ và các nước Tây Âu.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (701, 24, N'Một trong những mục tiêu quan trọng của Trung Quốc sau Chiến tranh lạnh là gì?', N'Trở thành cường quốc quân sự hàng đầu thế giới.', N'Tập trung hiện đại hóa, xây dựng CNXH đặc sắc.', N'Can thiệp vào công việc nội bộ của nước khác.', N'Lập một liên minh quân sự do mình đứng đầu.', N'A', NULL);
