INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (703, 24, N'Đâu KHÔNG phải là đặc điểm của xu thế đa cực, nhiều trung tâm sau Chiến tranh lạnh?', N'Sự vươn lên của Nhật Bản, Tây Âu, Trung Quốc.', N'Vị thế siêu cường của Mỹ bị suy giảm tương đối.', N'Vai trò cường quốc của Liên bang Nga được phục hồi.', N'Thế giới lại bị phân chia thành hai phe đối đầu.', N'A', NULL);
