INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (705, 24, N'Nội dung nào sau đây là bản chất của xu thế toàn cầu hóa?', N'Sự thống nhất về văn hóa của các quốc gia.', N'Sự xóa bỏ vai trò của nhà nước dân tộc.', N'Sự gia tăng liên hệ, tác động, phụ thuộc giữa các nước.', N'Quá trình chỉ mang lại lợi ích cho nước phát triển.', N'A', NULL);
