INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (709, 24, N'Đâu là một trong những trung tâm quyền lực hình thành nên trật tự thế giới đa cực sau Chiến tranh lạnh?', N'Ấn Độ', N'Bra-xin', N'Liên minh châu Âu (EU)', N'Nam Phi', N'A', NULL);
