INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (714, 24, N'Một trong những hệ quả quan trọng của cuộc cách mạng khoa học – công nghệ đối với quan hệ quốc tế sau Chiến tranh lạnh là gì?', N'Khiến các nước càng trở nên biệt lập.', N'Làm cho xu thế toàn cầu hóa phát triển.', N'Dẫn đến sự bùng nổ của chiến tranh mới.', N'Làm cho sự phân hóa giàu nghèo biến mất.', N'A', NULL);
