INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (740, 25, N'Đâu KHÔNG phải là lý do dẫn đến sự ra đời của Hiệp hội các quốc gia Đông Nam Á?', N'Nhu cầu hợp tác giữa các nước để cùng phát triển.', N'Mong muốn hạn chế ảnh hưởng từ các cường quốc.', N'Do sức ép từ Liên Xô và Mỹ yêu cầu thành lập.', N'Ảnh hưởng từ sự thành công của các khối kinh tế khác.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (741, 25, N'Việc thành lập Khu vực Mậu dịch tự do ASEAN (AFTA) có mục tiêu quan trọng nhất là gì?', N'Thống nhất chính sách đối ngoại của các nước ASEAN.', N'Thúc đẩy thương mại nội khối, dỡ bỏ hàng rào thuế quan.', N'Tạo ra một đồng tiền chung thống nhất cho cả khu vực.', N'Cạnh tranh trực tiếp với Liên minh châu Âu (EU).', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (742, 25, N'Hiệp ước về Khu vực không có vũ khí hạt nhân ở Đông Nam Á (SEANWFZ) được ký kết vào năm nào?', N'1971', N'1976', N'1995', N'2007', N'A', NULL);
