INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (909, 32, N'Từ trường là gì?', N'Là vùng không gian xung quanh điện tích đứng yên.', N'Là vùng không gian xung quanh dòng điện hoặc nam châm.', N'Là vùng không gian nơi các vật có khối lượng tương tác hấp dẫn.', N'Là vùng không gian nơi các vật nhiễm điện bị hút về tâm.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (910, 32, N'Lực từ là lực tương tác giữa những đối tượng nào?', N'Giữa hai điện tích đứng yên.', N'Giữa một điện tích đứng yên và một nam châm.', N'Giữa dòng điện và nam châm hoặc giữa các dòng điện.', N'Giữa các vật có khối lượng trong không gian.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (911, 32, N'Đặc điểm nào sau đây là đúng về đường sức từ?', N'Các đường sức từ luôn là những đường hở, không bao giờ khép kín.', N'Các đường sức từ không bao giờ cắt nhau và có chiều xác định.', N'Nơi nào đường sức từ thưa thì từ trường mạnh.', N'Chiều của đường sức từ luôn hướng từ cực Nam sang cực Bắc.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (912, 32, N'Khi đặt kim nam châm nhỏ tự do trong từ trường, kim nam châm sẽ định hướng như thế nào?', N'Theo phương vuông góc với đường sức từ.', N'Theo hướng của đường sức từ tại điểm đó.', N'Luôn hướng về phía Bắc địa lí.', N'Không định hướng rõ ràng nếu từ trường không đều.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (913, 32, N'Quy tắc nắm tay phải dùng để xác định đại lượng nào khi có dòng điện chạy qua dây dẫn thẳng?', N'Chiều của lực từ tác dụng lên dây dẫn.', N'Chiều của dòng điện trong dây dẫn.', N'Chiều của đường sức từ xung quanh dây dẫn.', N'Chiều của vectơ cảm ứng từ tại một điểm bất kì.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (914, 32, N'Cảm ứng từ B tại một điểm trong từ trường là đại lượng vật lí đặc trưng cho điều gì?', N'Hướng của từ trường và nhiệt độ tại điểm đó.', N'Độ lớn của từ trường và mật độ đường sức từ.', N'Phương và chiều của lực từ tác dụng lên dây dẫn mang dòng điện.', N'Hướng và độ lớn của lực từ tác dụng lên dây dẫn mang dòng điện.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (915, 32, N'Đơn vị của cảm ứng từ trong hệ SI là gì?', N'Newton (N).', N'Ampe (A).', N'Tesla (T).', N'Weber (Wb).', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (916, 32, N'Lực từ tác dụng lên đoạn dây dẫn mang dòng điện đặt trong từ trường đều được tính bằng biểu thức nào?', N'F = ILBsinα.', N'F = I/LBsinα.', N'F = (I+L+B)sinα.', N'F = ILB/sinα.', N'A', NULL);
