INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (918, 32, N'Quy tắc bàn tay trái dùng để xác định đại lượng nào trong từ trường?', N'Chiều của dòng điện trong dây dẫn.', N'Chiều của cảm ứng từ.', N'Chiều của lực từ tác dụng lên dây dẫn mang dòng điện.', N'Chiều chuyển động của các hạt tích điện.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (919, 32, N'Cảm ứng từ tại tâm vòng dây tròn có N vòng dây và bán kính R mang dòng điện I tỉ lệ thuận với những đại lượng nào?', N'N và R, tỉ lệ nghịch với I.', N'N và I, tỉ lệ nghịch với R.', N'R và I, tỉ lệ nghịch với N.', N'N, I, R đều tỉ lệ thuận.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (920, 32, N'Cảm ứng từ bên trong ống dây có chiều dài L và N vòng dây mang dòng điện I tỉ lệ thuận với những đại lượng nào?', N'N và L, tỉ lệ nghịch với I.', N'N và I, tỉ lệ nghịch với L.', N'L và I, tỉ lệ nghịch với N.', N'N, I, L đều tỉ lệ thuận.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (921, 32, N'Nguyên lí chồng chất từ trường phát biểu rằng:', N'Cảm ứng từ tổng hợp tại một điểm là tích của các vectơ cảm ứng từ thành phần.', N'Cảm ứng từ tổng hợp tại một điểm là tổng đại số của các cảm ứng từ thành phần.', N'Cảm ứng từ tổng hợp tại một điểm là tổng vectơ của các cảm ứng từ thành phần.', N'Cảm ứng từ tổng hợp tại một điểm chỉ do nguồn từ mạnh nhất gây ra.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (922, 32, N'Thí nghiệm để đo độ lớn cảm ứng từ thường được thực hiện bằng cách đo lực từ tác dụng lên đại lượng nào?', N'Một nam châm vĩnh cửu.', N'Một điện tích đứng yên.', N'Một đoạn dây dẫn mang dòng điện.', N'Một chùm electron chuyển động.', N'C', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (923, 32, N'Các đường sức từ của dòng điện chạy qua dây dẫn hình tròn có dạng hình gì?', N'Đường thẳng song song với mặt phẳng vòng dây.', N'Đường tròn đồng tâm với vòng dây và nằm trong mặt phẳng vuông góc với vòng dây.', N'Đường xoắn ốc quanh vòng dây.', N'Đường thẳng đi qua tâm vòng dây.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (924, 32, N'Một đoạn dây dẫn dài 10 cm mang dòng điện 4 A đặt trong từ trường đều có cảm ứng từ 0,5 T. Dây dẫn vuông góc với đường sức từ. Lực từ tác dụng lên dây dẫn là bao nhiêu?', N'0,1 N.', N'0,2 N.', N'0,3 N.', N'0,4 N.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (925, 32, N'Một đoạn dây dẫn dài 25 cm mang dòng điện 3 A đặt trong từ trường đều có cảm ứng từ 0,4 T. Dây dẫn hợp với đường sức từ một góc 30°. Lực từ tác dụng lên dây dẫn là bao nhiêu?', N'0,1 N.', N'0,15 N.', N'0,2 N.', N'0,25 N.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (926, 32, N'Cảm ứng từ tại tâm một vòng dây tròn có bán kính 2 cm, gồm 5 vòng dây mang dòng điện 1 A là bao nhiêu?', N'1,57·10⁻⁴ T.', N'3,14·10⁻⁴ T.', N'4,71·10⁻⁴ T.', N'6,28·10⁻⁴ T.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (927, 32, N'Một ống dây dài 10 cm có 500 vòng dây. Khi có dòng điện 0,2 A chạy qua ống dây, cảm ứng từ bên trong ống dây là bao nhiêu?', N'1,256·10⁻³ T.', N'1,256·10⁻² T.', N'6,28·10⁻⁴ T.', N'6,28·10⁻³ T.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (928, 32, N'Một điện tích q = 1,6·10⁻⁸ C chuyển động với vận tốc 2·10⁵ m/s vuông góc với từ trường đều có cảm ứng từ 0,2 T. Lực Lorentz tác dụng lên điện tích là bao nhiêu?', N'6,4·10⁻¹³ N.', N'3,2·10⁻¹³ N.', N'1,6·10⁻¹³ N.', N'1,28·10⁻¹² N.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (929, 32, N'Một thanh kim loại MN dài 0,5 m mang dòng điện 2 A đặt trong từ trường đều B. Lực từ tác dụng lên thanh là 0,4 N khi thanh vuông góc với B. Độ lớn cảm ứng từ B là bao nhiêu?', N'0,1 T.', N'0,2 T.', N'0,3 T.', N'0,4 T.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (930, 32, N'Một đoạn dây dẫn thẳng dài 20 cm mang dòng điện 5 A. Lực từ tác dụng lên dây dẫn là 0,2 N. Biết góc hợp bởi chiều dòng điện và cảm ứng từ là 30°. Độ lớn cảm ứng từ là bao nhiêu?', N'0,2 T.', N'0,4 T.', N'0,6 T.', N'0,8 T.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (931, 32, N'Hai dây dẫn thẳng dài vô hạn đặt song song, cách nhau 5 cm, mang hai dòng điện ngược chiều I₁ = 1 A và I₂ = 2 A. Lực tương tác trên mỗi mét chiều dài của hai dây dẫn là bao nhiêu?', N'4·10⁻⁶ N/m (lực hút).', N'8·10⁻⁶ N/m (lực hút).', N'4·10⁻⁶ N/m (lực đẩy).', N'8·10⁻⁶ N/m (lực đẩy).', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (932, 32, N'Một ống dây có N vòng dây, chiều dài L, mang dòng điện I. Cảm ứng từ bên trong ống dây là B. Nếu giảm số vòng dây đi một nửa và tăng chiều dài ống dây lên gấp đôi, giữ nguyên dòng điện, thì cảm ứng từ bên trong ống dây sẽ thay đổi như thế nào?', N'Giảm đi một nửa.', N'Giảm đi bốn lần.', N'Tăng gấp đôi.', N'Tăng gấp bốn lần.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (933, 32, N'Một điện tích q = 3·10⁻⁸ C chuyển động trong từ trường đều B = 0,4 T. Nếu vận tốc của điện tích hợp với đường sức từ một góc 60° và lực Lorentz tác dụng lên điện tích là 2,078·10⁻³ N, thì vận tốc của điện tích là bao nhiêu?', N'1·10⁵ m/s.', N'2·10⁵ m/s.', N'3·10⁵ m/s.', N'4·10⁵ m/s.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (934, 32, N'Hai cuộn dây dẫn hình tròn có cùng bán kính và cùng số vòng dây. Cuộn 1 mang dòng điện 2 A, cuộn 2 mang dòng điện 4 A. Cảm ứng từ tại tâm cuộn 2 so với tâm cuộn 1 là bao nhiêu?', N'Bằng nhau.', N'Gấp đôi.', N'Gấp bốn lần.', N'Bằng một nửa.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (935, 32, N'Một điện tích q = -4·10⁻⁸ C chuyển động với vận tốc 5·10⁵ m/s theo phương ngang từ trái sang phải vào một vùng có từ trường đều B = 0,5 T hướng thẳng đứng lên. Chiều của lực Lorentz tác dụng lên điện tích là gì?', N'Hướng lên trên.', N'Hướng xuống dưới.', N'Hướng vào trong mặt phẳng.', N'Hướng ra khỏi mặt phẳng.', N'D', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (936, 32, N'Một thanh kim loại AB dài 1 m, khối lượng 0,1 kg, đặt nằm ngang trên hai thanh ray song song và cách nhau 1 m trong từ trường đều B = 0,5 T hướng thẳng đứng xuống. Hệ số ma sát giữa thanh kim loại và ray là 0,2. Cường độ dòng điện tối thiểu cần chạy qua thanh để nó bắt đầu chuyển động là bao nhiêu?', N'0,4 A.', N'0,8 A.', N'1,0 A.', N'1,2 A.', N'B', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (937, 32, N'Một điện tích q = 1,6·10⁻¹⁹ C được gia tốc bởi hiệu điện thế U = 1000 V rồi bay vào từ trường đều B = 0,1 T theo phương vuông góc với đường sức từ. Bán kính quỹ đạo chuyển động của điện tích là 10 cm. Khối lượng của điện tích là bao nhiêu? (Bỏ qua trọng lực).', N'3,2·10⁻²⁷ kg.', N'1,6·10⁻²⁷ kg.', N'6,4·10⁻²⁷ kg.', N'4,8·10⁻²⁷ kg.', N'A', NULL);
INSERT INTO CauHoi (MaCauHoi, MaChuong, NoiDung, CauA, CauB, CauC, CauD, DapAnDung, LoiGiai) VALUES (938, 32, N'Hai dây dẫn thẳng dài vô hạn đặt song song, cách nhau 10 cm, mang hai dòng điện cùng chiều I₁ = 5 A và I₂ = 10 A. Cảm ứng từ tổng hợp tại điểm M nằm trên mặt phẳng chứa hai dây dẫn và cách dây I₁ 5 cm, cách dây I₂ 5 cm là bao nhiêu?', N'0 T.', N'2·10⁻⁵ T.', N'4·10⁻⁵ T.', N'6·10⁻⁵ T.', N'B', NULL);
