DELETE FROM LichSuLamBai;
DELETE FROM CauHoi;
DELETE FROM Chuong;
DELETE FROM NguoiDung;
DELETE FROM MonHoc;
DELETE FROM VaiTro;

-- Seeding VaiTro

-- Seeding MonHoc
SET IDENTITY_INSERT MonHoc ON;
SET IDENTITY_INSERT MonHoc OFF;

-- Seeding Chuong
SET IDENTITY_INSERT Chuong ON;
SET IDENTITY_INSERT Chuong OFF;

-- Seeding CauHoi
SET IDENTITY_INSERT CauHoi ON;


